import 'dotenv/config';
import { supabase } from './src/lib/supabase';

async function createAdminUser() {
    const email = 'leonardo.cordeiro@lasalle.org.br';
    const password = 'Admin@2026';

    console.log(`\n­ƒöÉ Criando usu├írio administrador...`);

    try {
        console.log('1. Verificando/Criando usu├írio no Auth...');
        const { data: authData, error: authError } = await supabase.auth.signUp({
            email,
            password,
        });

        if (authError) {
            if (authError.message.includes('already registered')) {
                console.log(`Ô£à Usu├írio ${email} j├í existe no Auth.`);
                const { data: signInData, error: signInError } = await supabase.auth.signInWithPassword({
                    email,
                    password
                });

                if (signInError) {
                    console.error('ÔØî Erro no Login:', signInError.message);
                    throw signInError;
                }

                console.log(`Ô£à Login realizado! ID: ${signInData.user.id}`);
                await createProfile(signInData.user.id, email);
            } else {
                console.error('ÔØî Erro no Sign Up:', authError.message);
                throw authError;
            }
        } else if (authData.user) {
            console.log(`Ô£à Auth User criado! ID: ${authData.user.id}`);
            await createProfile(authData.user.id, email);
        }

    } catch (error: any) {
        console.error(`ÔØî Falha no processo:`, error.message || error);
        process.exit(1);
    }
}

async function createProfile(userId: string, email: string) {
    const escola_id = 'e6328325-1845-420a-b333-87a747953259';
    console.log(`2. Criando perfil para escola: ${escola_id}...`);

    const { error: profileError } = await supabase
        .from('usuarios')
        .upsert({
            id: userId,
            escola_id: escola_id,
            nome: 'Leonardo Cordeiro',
            email: email,
            tipo_usuario: 'ADMIN',
            ativo: true
        }, { onConflict: 'id' });

    if (profileError) {
        console.error('ÔØî Erro ao criar/atualizar perfil:', profileError);
        throw profileError;
    }

    console.log(`Ô£à Perfil pronto na tabela usuarios!`);
    console.log(`\nÔ£¿ ADMINISTRADOR CONFIGURADO COM SUCESSO!`);
    console.log(`   Email: ${email}`);
    console.log(`   Senha: Admin@2026`);
}

createAdminUser();

import { useState, useEffect } from 'react';
import { supabase } from '../../lib/supabase';
import { X, UserCheck, Phone, Mail, Shield } from 'lucide-react';

type GuardianFormData = {
    nome_completo: string;
    cpf: string;
    telefone: string;
    email: string;
    parentesco: string;
    foto_documento_url: string;
};

type AuthorizationFormData = {
    aluno_id: string;
    tipo_autorizacao: 'PRINCIPAL' | 'SECUNDARIO' | 'EMERGENCIA';
    ativa: boolean;
};

type AddGuardianFormProps = {
    isOpen: boolean;
    onClose: () => void;
    escolaId: string;
    onSuccess: () => void;
};

export default function AddGuardianForm({ isOpen, onClose, escolaId, onSuccess }: AddGuardianFormProps) {
    const [guardianData, setGuardianData] = useState<GuardianFormData>({
        nome_completo: '',
        cpf: '',
        telefone: '',
        email: '',
        parentesco: '',
        foto_documento_url: ''
    });
    const [authData, setAuthData] = useState<AuthorizationFormData>({
        aluno_id: '',
        tipo_autorizacao: 'PRINCIPAL',
        ativa: true
    });
    const [students, setStudents] = useState<any[]>([]);
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState('');

    useEffect(() => {
        if (isOpen) {
            fetchStudents();
        }
    }, [isOpen, escolaId]);

    const fetchStudents = async () => {
        const { data } = await supabase
            .from('alunos')
            .select('id, nome_completo, matricula, turma')
            .eq('escola_id', escolaId)
            .order('nome_completo');

        setStudents(data || []);
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setLoading(true);
        setError('');

        try {
            // 1. Check if guardian already exists by CPF
            const { data: existingGuardian } = await supabase
                .from('responsaveis')
                .select('id')
                .eq('cpf', guardianData.cpf)
                .maybeSingle();

            let guardianId;

            if (existingGuardian) {
                // Update existing guardian info
                const { error: uError } = await supabase
                    .from('responsaveis')
                    .update({
                        nome_completo: guardianData.nome_completo,
                        telefone: guardianData.telefone,
                        email: guardianData.email,
                        parentesco: guardianData.parentesco,
                        foto_documento_url: guardianData.foto_documento_url
                    })
                    .eq('id', existingGuardian.id);

                if (uError) throw uError;
                guardianId = existingGuardian.id;
            } else {
                // Create new guardian
                const { data: newGuardian, error: gError } = await supabase
                    .from('responsaveis')
                    .insert(guardianData)
                    .select()
                    .single();

                if (gError) throw gError;
                guardianId = newGuardian.id;
            }

            // 2. Create authorization link
            const { error: authError } = await supabase
                .from('autorizacoes')
                .insert({
                    aluno_id: authData.aluno_id,
                    responsavel_id: guardianId,
                    tipo_autorizacao: authData.tipo_autorizacao,
                    ativa: authData.ativa
                });

            if (authError) throw authError;

            onSuccess();
            resetForm();
            onClose();
        } catch (err: any) {
            setError(err.message || 'Erro ao adicionar respons├ível');
        } finally {
            setLoading(false);
        }
    };

    const resetForm = () => {
        setGuardianData({
            nome_completo: '',
            cpf: '',
            telefone: '',
            email: '',
            parentesco: '',
            foto_documento_url: ''
        });
        setAuthData({
            aluno_id: '',
            tipo_autorizacao: 'PRINCIPAL',
            ativa: true
        });
    };

    if (!isOpen) return null;

    return (
        <>
            <div className="fixed inset-0 bg-black/50 z-40" onClick={onClose} />
            <div className="fixed inset-y-0 right-0 w-full max-w-2xl bg-white shadow-2xl z-50 flex flex-col">
                {/* Header */}
                <div className="flex items-center justify-between px-6 py-4 border-b">
                    <div className="flex items-center gap-3">
                        <div className="p-2 bg-emerald-100 rounded-lg">
                            <UserCheck className="w-5 h-5 text-emerald-600" />
                        </div>
                        <h2 className="text-lg font-bold">Adicionar Respons├ível</h2>
                    </div>
                    <button onClick={onClose} className="p-2 hover:bg-slate-100 rounded-lg">
                        <X className="w-5 h-5" />
                    </button>
                </div>

                {/* Form */}
                <form onSubmit={handleSubmit} className="flex-1 overflow-y-auto px-6 py-6">
                    <div className="space-y-6">
                        {/* Guardian Info */}
                        <div>
                            <h3 className="text-sm font-bold text-slate-900 mb-4">Dados do Respons├ível</h3>
                            <div className="grid grid-cols-2 gap-4">
                                <div className="col-span-2">
                                    <label className="block text-sm font-medium text-slate-700 mb-2">
                                        Nome Completo *
                                    </label>
                                    <input
                                        type="text"
                                        required
                                        value={guardianData.nome_completo}
                                        onChange={(e) => setGuardianData({ ...guardianData, nome_completo: e.target.value })}
                                        className="w-full px-4 py-3 border rounded-lg focus:ring-2 focus:ring-emerald-500"
                                    />
                                </div>

                                <div>
                                    <label className="block text-sm font-medium text-slate-700 mb-2">
                                        CPF *
                                    </label>
                                    <input
                                        type="text"
                                        required
                                        value={guardianData.cpf}
                                        onChange={(e) => setGuardianData({ ...guardianData, cpf: e.target.value })}
                                        className="w-full px-4 py-3 border rounded-lg focus:ring-2 focus:ring-emerald-500"
                                        placeholder="000.000.000-00"
                                    />
                                </div>

                                <div>
                                    <label className="block text-sm font-medium text-slate-700 mb-2 flex items-center gap-2">
                                        <Phone className="w-4 h-4" />
                                        Telefone *
                                    </label>
                                    <input
                                        type="tel"
                                        required
                                        value={guardianData.telefone}
                                        onChange={(e) => setGuardianData({ ...guardianData, telefone: e.target.value })}
                                        className="w-full px-4 py-3 border rounded-lg focus:ring-2 focus:ring-emerald-500"
                                    />
                                </div>

                                <div className="col-span-2">
                                    <label className="block text-sm font-medium text-slate-700 mb-2 flex items-center gap-2">
                                        <Mail className="w-4 h-4" />
                                        E-mail
                                    </label>
                                    <input
                                        type="email"
                                        value={guardianData.email}
                                        onChange={(e) => setGuardianData({ ...guardianData, email: e.target.value })}
                                        className="w-full px-4 py-3 border rounded-lg focus:ring-2 focus:ring-emerald-500"
                                    />
                                </div>

                                <div>
                                    <label className="block text-sm font-medium text-slate-700 mb-2">
                                        Parentesco *
                                    </label>
                                    <input
                                        type="text"
                                        required
                                        value={guardianData.parentesco}
                                        onChange={(e) => setGuardianData({ ...guardianData, parentesco: e.target.value })}
                                        className="w-full px-4 py-3 border rounded-lg focus:ring-2 focus:ring-emerald-500"
                                        placeholder="Ex: M├úe, Pai, Av├│"
                                    />
                                </div>
                            </div>
                        </div>

                        {/* Authorization */}
                        <div className="pt-4 border-t">
                            <h3 className="text-sm font-bold text-slate-900 mb-4">Autoriza├º├úo</h3>
                            <div className="space-y-4">
                                <div>
                                    <label className="block text-sm font-medium text-slate-700 mb-2">
                                        Aluno *
                                    </label>
                                    <select
                                        required
                                        value={authData.aluno_id}
                                        onChange={(e) => setAuthData({ ...authData, aluno_id: e.target.value })}
                                        className="w-full px-4 py-3 border rounded-lg focus:ring-2 focus:ring-emerald-500"
                                    >
                                        <option value="">Selecione um aluno</option>
                                        {students.map(student => (
                                            <option key={student.id} value={student.id}>
                                                {student.nome_completo} - {student.turma}
                                            </option>
                                        ))}
                                    </select>
                                </div>

                                <div>
                                    <label className="block text-sm font-medium text-slate-700 mb-2 flex items-center gap-2">
                                        <Shield className="w-4 h-4" />
                                        Tipo de Respons├ível *
                                    </label>
                                    <select
                                        required
                                        value={authData.tipo_autorizacao}
                                        onChange={(e) => setAuthData({ ...authData, tipo_autorizacao: e.target.value as any })}
                                        className="w-full px-4 py-3 border rounded-lg focus:ring-2 focus:ring-emerald-500"
                                    >
                                        <option value="PRINCIPAL">Principal</option>
                                        <option value="SECUNDARIO">Secund├írio</option>
                                        <option value="EMERGENCIA">Emerg├¬ncia</option>
                                    </select>
                                </div>

                                <label className="flex items-center gap-3 p-4 bg-emerald-50 rounded-lg cursor-pointer">
                                    <input
                                        type="checkbox"
                                        checked={authData.ativa}
                                        onChange={(e) => setAuthData({ ...authData, ativa: e.target.checked })}
                                        className="w-5 h-5 text-emerald-600 rounded focus:ring-2 focus:ring-emerald-500"
                                    />
                                    <span className="text-sm font-medium text-slate-700">
                                        Autorizado a retirar o aluno
                                    </span>
                                </label>
                            </div>
                        </div>

                        {error && (
                            <div className="p-3 bg-red-50 border border-red-200 rounded-lg text-sm text-red-600">
                                {error}
                            </div>
                        )}
                    </div>
                </form>

                {/* Actions */}
                <div className="border-t px-6 py-4 flex gap-3">
                    <button
                        type="button"
                        onClick={onClose}
                        className="flex-1 px-4 py-3 border rounded-lg hover:bg-slate-50"
                    >
                        Cancelar
                    </button>
                    <button
                        onClick={handleSubmit}
                        disabled={loading}
                        className="flex-1 px-4 py-3 bg-emerald-600 text-white rounded-lg hover:bg-emerald-700 disabled:opacity-50"
                    >
                        {loading ? 'Salvando...' : 'Adicionar Respons├ível'}
                    </button>
                </div>
            </div>
        </>
    );
}

import { useState, useRef } from 'react';
import { X, Upload, FileText, AlertCircle, CheckCircle2, Loader2, Download } from 'lucide-react';
import { supabase } from '../../lib/supabase';
import { getSalaBySerie } from '../../lib/utils';

type BulkImportModalProps = {
    escolaId: string;
    onClose: () => void;
    onSuccess: () => void;
};

export default function BulkImportModal({ escolaId, onClose, onSuccess }: BulkImportModalProps) {
    const fileInputRef = useRef<HTMLInputElement>(null);
    const [importMode, setImportMode] = useState<'upload' | 'paste'>('upload');
    const [pastedData, setPastedData] = useState('');
    const [fileName, setFileName] = useState<string | null>(null);
    const [loading, setLoading] = useState(false);
    const [preview, setPreview] = useState<any[]>([]);
    const [error, setError] = useState<string | null>(null);

    // Fetch all turmas from DB so we can match properly
    const fetchTurmasFromDB = async (): Promise<{ nome: string; serie: string; secao: string }[]> => {
        const { data, error } = await supabase.from('turmas').select('nome').eq('ativa', true);
        if (error || !data) return [];
        return data.map(t => {
            const m = t.nome.match(/^(.*?) - (.*?) \((.*?)\)$/);
            if (m) return { nome: t.nome, serie: m[1], secao: m[3] };
            // Fallback: simple "serie (secao)" format
            const m2 = t.nome.match(/^(.*?) \((.*?)\)$/);
            if (m2) return { nome: t.nome, serie: m2[1], secao: m2[2] };
            return { nome: t.nome, serie: t.nome, secao: '' };
        });
    };

    const getShortSerie = (str: string): string => {
        const beforeDash = str.split(' - ')[0];
        const beforeParen = beforeDash.split('(')[0];
        return beforeParen.trim();
    };

    const parseCSV = (text: string, dbTurmas: { nome: string; serie: string; secao: string }[]) => {
        const lines = text.split('\n').filter(line => line.trim());
        if (lines.length < 2) throw new Error('O arquivo deve conter um cabe├ºalho e pelo menos uma linha de dados.');

        const headers = lines[0].split(/[;,\t]/).map(h => h.trim().toLowerCase());
        const data = lines.slice(1).map(line => {
            const values = line.split(/[;,\t]/).map(v => v.trim());
            const obj: any = {};
            headers.forEach((header, i) => {
                if (header.includes('nome')) obj.nome_completo = values[i];
                if (header.includes('matr')) obj.matricula = values[i];
                if (header.includes('s├®rie') || header.includes('serie')) obj.serie = values[i];
                if (header.includes('turma')) obj.turma_secao = values[i];
            });
            return obj;
        });

        // Validation and Sala + Turma assignment
        const normalize = (str: string) => str.trim().toLowerCase().replace(/\s+/g, ' ');
        const validated = data.map(item => {
            if (!item.nome_completo || !item.serie) return null;

            // Try to match the CSV serie against real turmas in the DB
            let turmaFormatada = item.serie; // fallback
            if (dbTurmas.length > 0) {
                const csvShortSerie = normalize(item.serie);
                const csvSecao = item.turma_secao || '';

                // Find a DB turma whose short serie prefix matches AND secao matches
                const matched = dbTurmas.find(t =>
                    normalize(getShortSerie(t.serie)) === csvShortSerie &&
                    normalize(t.secao) === normalize(csvSecao)
                ) || dbTurmas.find(t =>
                    // Fallback: full serie matches CSV serie
                    normalize(t.serie) === csvShortSerie &&
                    normalize(t.secao) === normalize(csvSecao)
                );

                if (matched) {
                    turmaFormatada = matched.nome;
                } else {
                    // No match found in turmas table ÔÇö store in simple format
                    turmaFormatada = item.turma_secao
                        ? `${item.serie} (${item.turma_secao})`
                        : item.serie;
                }
            } else {
                // DB turmas not available ÔÇö use old simple format
                turmaFormatada = item.turma_secao
                    ? `${item.serie} (${item.turma_secao})`
                    : item.serie;
            }

            return {
                nome_completo: item.nome_completo,
                matricula: item.matricula || `MAT-${Math.random().toString(36).substr(2, 9).toUpperCase()}`,
                turma: turmaFormatada,
                sala: getSalaBySerie(item.serie),
                escola_id: escolaId,
                ativo: true
            };
        }).filter(Boolean);

        if (validated.length === 0) throw new Error('Nenhum dado v├ílido encontrado. Verifique se o cabe├ºalho cont├®m "Nome" e "S├®rie".');
        return validated;
    };

    const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) return;

        setFileName(file.name);
        setError(null);

        const reader = new FileReader();
        reader.onload = async (event) => {
            try {
                const text = event.target?.result as string;
                const dbTurmas = await fetchTurmasFromDB();
                const parsed = parseCSV(text, dbTurmas);
                setPreview(parsed);
            } catch (err: any) {
                setError(err.message);
                setPreview([]);
            }
        };
        reader.readAsText(file);
    };

    const handlePasteProcess = async () => {
        try {
            setError(null);
            const dbTurmas = await fetchTurmasFromDB();
            const parsed = parseCSV(pastedData, dbTurmas);
            setPreview(parsed);
        } catch (err: any) {
            setError(err.message);
            setPreview([]);
        }
    };

    const handleImport = async () => {
        setLoading(true);
        setError(null);

        try {
            const { error: insertError } = await supabase
                .from('alunos')
                .insert(preview);

            if (insertError) throw insertError;

            onSuccess();
            onClose();
        } catch (err: any) {
            setError(err.message || 'Erro ao importar alunos');
        } finally {
            setLoading(false);
        }
    };

    const downloadTemplate = () => {
        const csvContent = "\uFEFFNome Completo;Matr├¡cula;S├®rie;Turma\nJo├úo Silva;2024001;1┬║ Ano;A\nMaria Oliveira;2024002;2┬║ Ano;B";
        const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
        const link = document.createElement("a");
        const url = URL.createObjectURL(blob);
        link.setAttribute("href", url);
        link.setAttribute("download", "modelo_importacao_alunos.csv");
        link.style.visibility = 'hidden';
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
    };

    return (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-[100] flex items-center justify-center p-4">
            <div className="bg-white w-full max-w-4xl rounded-[2rem] shadow-2xl overflow-hidden flex flex-col max-h-[90vh]">
                <div className="p-8 border-b border-slate-100 flex items-center justify-between bg-slate-50/50">
                    <div>
                        <h2 className="text-2xl font-black text-slate-900 tracking-tight uppercase italic">Importa├º├úo em Massa</h2>
                        <p className="text-sm text-slate-500 font-medium">Adicione m├║ltiplos alunos de uma s├│ vez</p>
                    </div>
                    <button onClick={onClose} className="p-2 hover:bg-slate-200 rounded-full transition-colors text-slate-400">
                        <X className="w-6 h-6" />
                    </button>
                </div>

                <div className="flex-1 overflow-y-auto p-8">
                    {/* Mode Selector */}
                    <div className="flex gap-4 mb-8">
                        <button
                            onClick={() => { setImportMode('upload'); setPreview([]); }}
                            className={`flex-1 p-4 rounded-2xl border-2 transition-all flex items-center gap-3 font-bold uppercase tracking-wider text-xs ${importMode === 'upload' ? 'border-blue-500 bg-blue-50 text-blue-700' : 'border-slate-100 text-slate-400 hover:border-slate-200'}`}
                        >
                            <Upload className="w-5 h-5" /> Enviar Arquivo (CSV)
                        </button>
                        <button
                            onClick={() => { setImportMode('paste'); setPreview([]); }}
                            className={`flex-1 p-4 rounded-2xl border-2 transition-all flex items-center gap-3 font-bold uppercase tracking-wider text-xs ${importMode === 'paste' ? 'border-blue-500 bg-blue-50 text-blue-700' : 'border-slate-100 text-slate-400 hover:border-slate-200'}`}
                        >
                            <FileText className="w-5 h-5" /> Colar Dados (Texto)
                        </button>
                    </div>

                    {importMode === 'upload' ? (
                        <div
                            onClick={() => fileInputRef.current?.click()}
                            className="border-2 border-dashed border-slate-200 rounded-3xl p-12 flex flex-col items-center justify-center gap-4 hover:border-blue-400 transition-colors cursor-pointer group"
                        >
                            <input type="file" ref={fileInputRef} onChange={handleFileUpload} accept=".csv,.txt" className="hidden" />
                            <div className="w-16 h-16 bg-blue-50 text-blue-500 rounded-2xl flex items-center justify-center group-hover:scale-110 transition-transform">
                                <Upload className="w-8 h-8" />
                            </div>
                            <div className="text-center">
                                <p className="text-lg font-bold text-slate-700">{fileName || 'Clique para selecionar arquivo'}</p>
                                <p className="text-sm text-slate-400">Formato aceito: .CSV (separado por v├¡rgula ou ponto e v├¡rgula)</p>
                            </div>
                            <button
                                onClick={(e) => { e.stopPropagation(); downloadTemplate(); }}
                                className="mt-4 flex items-center gap-2 text-xs font-black text-blue-600 hover:underline uppercase tracking-widest"
                            >
                                <Download className="w-4 h-4" /> Baixar Modelo Exemplo
                            </button>
                        </div>
                    ) : (
                        <div className="space-y-4">
                            <textarea
                                value={pastedData}
                                onChange={(e) => setPastedData(e.target.value)}
                                className="w-full h-48 bg-slate-50 border border-slate-200 rounded-2xl p-6 font-mono text-sm outline-none focus:border-blue-500 transition-all"
                                placeholder={"Nome Completo, Matr├¡cula, S├®rie, Turma\nAna Souza, 1002, 3┬║ Ano, B"}
                            />
                            <button
                                onClick={handlePasteProcess}
                                disabled={!pastedData}
                                className="w-full py-4 bg-slate-900 text-white rounded-xl font-bold uppercase tracking-widest text-xs hover:bg-slate-800 transition-all disabled:opacity-50"
                            >
                                Processar Texto
                            </button>
                        </div>
                    )}

                    {error && (
                        <div className="mt-6 p-4 bg-red-50 border border-red-100 rounded-xl flex items-start gap-3 text-red-600 animate-in fade-in slide-in-from-top-2">
                            <AlertCircle className="w-5 h-5 shrink-0" />
                            <p className="text-sm font-medium">{error}</p>
                        </div>
                    )}

                    {preview.length > 0 && (
                        <div className="mt-10 space-y-4">
                            <div className="flex items-center justify-between">
