import { useEffect, useState } from 'react';
import { supabase } from '../../lib/supabase';
import { Clock, User as UserIcon, Check } from 'lucide-react';
import { useToast } from '../../components/ui/Toast';

interface PriorityPipelineProps {
    selectedClass: string;
    activeRequestId?: string;
    onSelectRequest: (request: any) => void;
    onQueueChange?: (requests: any[]) => void;
    userId: string;
    escolaId?: string;
}

export default function PriorityPipeline({
    selectedClass,
    activeRequestId,
    onSelectRequest,
    onQueueChange,
    userId,
    escolaId
}: PriorityPipelineProps) {
    const toast = useToast();
    const [requests, setRequests] = useState<any[]>([]);
    const [loading, setLoading] = useState(true);

    const fetchRequests = async () => {
        let query = supabase
            .from('solicitacoes_retirada')
            .select(`
                id,
                status,
                tipo_solicitacao,
                horario_solicitacao,
                aluno:alunos!inner (
                    id,
                    nome_completo,
                    turma,
                    sala,
                    foto_url,
                    observacoes
                ),
                mensagem_recepcao,
                status_geofence,
                distancia_estimada_metros
            `)
            .in('status', ['SOLICITADO', 'AGUARDANDO']);

        if (selectedClass !== 'TODAS') {
            if (selectedClass.startsWith('Sala ')) {
                query = query.eq('alunos.sala', selectedClass);
            } else {
                query = query.eq('alunos.turma', selectedClass);
            }
        }

        if (escolaId) {
            query = query.eq('escola_id', escolaId);
        }

        const { data, error } = await query.order('horario_solicitacao', { ascending: true });

        if (!error && data) {
            setRequests(data);
            if (onQueueChange) onQueueChange(data);
        }
        setLoading(false);
    };

    const handleLiberarTodos = async () => {
        if (requests.length === 0) return;

        const ids = requests.map(r => r.id);

        const { error } = await supabase
            .from('solicitacoes_retirada')
            .update({
                status: 'LIBERADO',
                professor_id: userId,
                horario_liberacao: new Date().toISOString()
            })
            .in('id', ids);

        if (!error) {
            fetchRequests();
        } else {
            toast.error('Erro ao liberar alunos', error.message);
        }
    };

    useEffect(() => {
        if (!userId) return;

        fetchRequests();

        // High-frequency polling (1 second) for ultra-fast sync
        const interval = setInterval(fetchRequests, 1000);

        // Also keep Realtime for immediate push notification response
        const channel = supabase
            .channel(`pipeline_room_${selectedClass}_${userId}`)
            .on(
                'postgres_changes',
                {
                    event: '*',
                    schema: 'public',
                    table: 'solicitacoes_retirada'
                },
                () => fetchRequests()
            )
            .subscribe();

        return () => {
            clearInterval(interval);
            supabase.removeChannel(channel);
        };
    }, [selectedClass, userId, escolaId]);

    return (
        <div className="w-96 border-r border-white/5 bg-white/[0.02] backdrop-blur-2xl flex flex-col z-20">
            <div className="p-6 border-b border-white/5 flex items-center justify-between">
                <div>
                    <h3 className="text-xs font-black text-slate-400 uppercase tracking-widest mb-1">Fila de Prioridade</h3>
                    <p className="text-[10px] text-emerald-500 font-bold uppercase tracking-tighter">Sequ├¬ncia de Retirada (FIFO)</p>
                </div>
                <div className="flex items-center gap-2">
                    <div className="w-1.5 h-1.5 bg-emerald-500 rounded-full animate-pulse"></div>
                    <span className="text-[8px] font-black text-emerald-500/50 uppercase tracking-widest">Ao Vivo</span>
                </div>
            </div>

            <div className="flex-1 overflow-y-auto p-4 space-y-3 custom-scrollbar">
                {loading && requests.length === 0 ? (
                    <div className="py-10 flex flex-col items-center justify-center opacity-20">
                        <div className="w-8 h-8 border-2 border-white border-t-transparent rounded-full animate-spin mb-4"></div>
                    </div>
                ) : requests.length === 0 ? (
                    <div className="h-full flex flex-col items-center justify-center text-center p-8 opacity-30 grayscale">
                        <div className="w-12 h-12 mb-4 border-2 border-white/20 rounded-2xl flex items-center justify-center">
                            <Clock className="w-6 h-6 text-slate-500" />
                        </div>
                        <p className="text-sm font-black uppercase tracking-widest">Fila Vazia</p>
                        <p className="text-[10px] font-bold mt-2 leading-relaxed">Sistema em espera: Aguardando pr├│xima solicita├º├úo...</p>
                    </div>
                ) : (
                    requests.map((req, idx) => (
                        <button
                            key={req.id}
                            onClick={() => onSelectRequest(req)}
                            className={`w-full group relative p-4 rounded-2xl border transition-all duration-300 flex items-center gap-4 text-left ${activeRequestId === req.id
                                ? 'bg-emerald-500 border-emerald-400 shadow-2xl shadow-emerald-500/20'
                                : 'bg-white/5 border-white/5 hover:border-white/10 hover:bg-white/[0.08]'}`}
                        >
                            <div className="relative shrink-0">
                                <div className={`w-12 h-12 rounded-xl overflow-hidden border-2 transition-colors ${activeRequestId === req.id ? 'border-white/40' : 'border-white/10 group-hover:border-white/20'}`}>
                                    {req.aluno.foto_url ? (
                                        <img src={req.aluno.foto_url} alt="" className="w-full h-full object-cover" />
                                    ) : (
                                        <div className="w-full h-full flex items-center justify-center bg-slate-800">
                                            <UserIcon className="w-6 h-6 text-slate-600" />
                                        </div>
                                    )}
                                </div>
                                {idx === 0 && (
                                    <div className="absolute -top-1.5 -right-1.5 w-5 h-5 bg-amber-500 rounded-full flex items-center justify-center border-2 border-[#0f172a] animate-bounce">
                                        <Clock className="w-3 h-3 text-slate-950 font-black" />
                                    </div>
                                )}
                            </div>
                            <div className="flex-1 overflow-hidden">
                                <p className={`font-black uppercase italic tracking-tighter truncate leading-none mb-1 ${activeRequestId === req.id ? 'text-slate-950' : 'text-white'}`}>
                                    {req.aluno.nome_completo.split(' ')[0]} {req.aluno.nome_completo.split(' ')[1] || ''}
                                </p>
                                <div className="flex items-center gap-2">
                                    <span className={`text-[9px] font-black uppercase tracking-widest ${activeRequestId === req.id ? 'text-slate-950/60' : 'text-emerald-400'}`}>
                                        {req.aluno.turma}
                                    </span>
                                    <span className={`w-1 h-1 rounded-full ${activeRequestId === req.id ? 'bg-slate-950/20' : 'bg-white/10'}`}></span>
                                    <span className={`text-[9px] font-bold ${activeRequestId === req.id ? 'text-slate-950/60' : 'text-slate-500'}`}>
                                        {req.aluno.sala}
                                    </span>
                                </div>
                            </div>
                            {activeRequestId === req.id && (
                                <div className="absolute top-1/2 -translate-y-1/2 right-4 flex items-center gap-3">
                                    {req.status_geofence === 'CHEGOU' && (
                                        <div className="bg-emerald-400/20 text-emerald-400 px-2 py-0.5 rounded text-[8px] font-black animate-pulse">NA PORTA</div>
                                    )}
                                    <div className="w-1.5 h-6 bg-slate-900/20 rounded-full animate-pulse"></div>
                                </div>
                            )}
                            {activeRequestId !== req.id && req.status_geofence === 'CHEGOU' && (
                                <div className="absolute top-4 right-4 animate-bounce">
                                    <div className="w-2 h-2 bg-emerald-500 rounded-full shadow-[0_0_8px_rgba(16,185,129,0.8)]"></div>
                                </div>
                            )}
                        </button>
                    ))
                )}
            </div>

            {requests.length > 1 && (
                <div className="p-4 bg-emerald-500/10 border-t border-white/5">
                    <button
                        onClick={handleLiberarTodos}
                        className="w-full py-4 bg-emerald-500 hover:bg-emerald-400 text-slate-900 rounded-2xl font-black text-xs uppercase tracking-[0.2em] transition-all shadow-xl shadow-emerald-500/10 active:scale-95 flex items-center justify-center gap-3"
                    >
                        <Check className="w-5 h-5" /> Liberar Todos em Lote
                    </button>
                </div>
            )}

            <div className="p-4 bg-slate-900/40 border-t border-white/5 flex items-center justify-between">
                <div className="flex flex-col">
                    <span className="text-[8px] font-black text-slate-500 uppercase tracking-widest">Carga Atual</span>
                    <span className="text-sm font-black italic">{requests.length} Aluno(s)</span>
                </div>
            </div>
        </div>
    );
}

import { useEffect, useState } from 'react';
import { supabase } from '../../lib/supabase';
import { Navigation } from 'lucide-react';

// Coordinates of the school (Example: LaSalle)
// TODO: Move to database/settings
const SCHOOL_COORDS = {
    latitude: -29.916892, // Replace with actual school coords
    longitude: -51.179836
};

// Haversine formula to calculate distance in meters
function getDistanceFromLatLonInMeters(lat1: number, lon1: number, lat2: number, lon2: number) {
    var R = 6371; // Radius of the earth in km
    var dLat = deg2rad(lat2 - lat1);
    var dLon = deg2rad(lon2 - lon1);
    var a =
        Math.sin(dLat / 2) * Math.sin(dLat / 2) +
        Math.cos(deg2rad(lat1)) * Math.cos(deg2rad(lat2)) *
        Math.sin(dLon / 2) * Math.sin(dLon / 2);
    var c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
    var d = R * c; // Distance in km
    return d * 1000; // Meters
}

function deg2rad(deg: number) {
    return deg * (Math.PI / 180);
}

export default function GeoTracker({ pickupId }: { pickupId: string }) {
    const [tracking, setTracking] = useState(false);
    const [distance, setDistance] = useState<number | null>(null);
    const [error, setError] = useState<string | null>(null);

    useEffect(() => {
        let watchId: number;

        if (tracking) {
            if (!navigator.geolocation) {
                setError('Geolocaliza├º├úo n├úo suportada');
                return;
            }

            setError(null); // Clear previous errors
            watchId = navigator.geolocation.watchPosition(
                (position) => {
                    const { latitude, longitude } = position.coords;
                    const dist = getDistanceFromLatLonInMeters(
                        latitude,
                        longitude,
                        SCHOOL_COORDS.latitude,
                        SCHOOL_COORDS.longitude
                    );

                    setDistance(Math.round(dist));
                    updateStatus(pickupId, dist, latitude, longitude);
                },
                (err) => setError(err.message),
                {
                    enableHighAccuracy: false, // Standard accuracy is more reliable for testing
                    timeout: 15000,           // Increased to 15 seconds
                    maximumAge: 5000          // Accept a 5-second old position
                }
            );
        }

        return () => {
            if (watchId) navigator.geolocation.clearWatch(watchId);
        };
    }, [tracking, pickupId]);

    const updateStatus = async (id: string, dist: number, lat: number, lng: number) => {
        let statusGeofence = 'LONGE';
        if (dist < 50) statusGeofence = 'CHEGOU';
        else if (dist < 500) statusGeofence = 'PERTO';

        // Update database
        // Debounce this in real production to save writes
        await supabase
            .from('solicitacoes_retirada')
            .update({
                latitude: lat,
                longitude: lng,
                distancia_estimada_metros: dist,
                status_geofence: statusGeofence
            })
            .eq('id', id);

        // If "CHEGOU", we can also auto-update the main status if business logic requires
    };

    return (
        <div className="p-4 bg-slate-50 rounded-xl border border-slate-200 mt-4">
            <div className="flex items-center justify-between">
                <div className="flex items-center gap-3">
                    <div className={`w-10 h-10 rounded-full flex items-center justify-center ${tracking ? 'bg-emerald-100 text-emerald-600 animate-pulse' : 'bg-slate-200 text-slate-400'}`}>
                        <Navigation className="w-5 h-5" />
                    </div>
                    <div>
                        <p className="font-bold text-slate-700 text-sm">Modo "Estou Chegando"</p>
                        <p className="text-xs text-slate-500">
                            {tracking
                                ? distance
                                    ? `Dist├óncia: ${distance}m`
                                    : 'Calculando...'
                                : 'Ative para avisar automaticamente'}
                        </p>
                    </div>
                </div>
                <button
                    onClick={() => setTracking(!tracking)}
                    className={`px-4 py-2 rounded-lg font-bold text-xs uppercase tracking-wider transition-all ${tracking
                        ? 'bg-red-100 text-red-600 hover:bg-red-200'
                        : 'bg-emerald-500 text-white hover:bg-emerald-600 shadow-lg shadow-emerald-500/20'
                        }`}
                >
                    {tracking ? 'Parar' : 'Ativar'}
                </button>
            </div>
            {error && <p className="text-xs text-red-500 mt-2">{error}</p>}
        </div>
    );
}

import { useRef, useEffect } from 'react';
import { X, QrCode } from 'lucide-react';
import jsQR from 'jsqr';
import { useToast } from '../../components/ui/Toast';

interface QRScannerModalProps {
    isOpen: boolean;
    onClose: () => void;
    onScan: (data: string) => void;
}

export default function QRScannerModal({ isOpen, onClose, onScan }: QRScannerModalProps) {
    const videoRef = useRef<HTMLVideoElement>(null);
    const canvasRef = useRef<HTMLCanvasElement>(null);
    const toast = useToast();

    useEffect(() => {
        let stream: MediaStream | null = null;
        let animationId: number;

        const startCamera = async () => {
            try {
                stream = await navigator.mediaDevices.getUserMedia({
                    video: { facingMode: 'environment' }
                });
                if (videoRef.current) {
                    videoRef.current.srcObject = stream;
                    videoRef.current.play();
                    requestAnimationFrame(scanQRCode);
                }
            } catch (error) {
                console.error('Erro ao acessar c├ómera:', error);
                toast.error('Erro de c├ómera', 'N├úo foi poss├¡vel acessar a c├ómera. Verifique as permiss├Áes.');
                onClose();
            }
        };

        const scanQRCode = () => {
            if (videoRef.current && canvasRef.current && videoRef.current.readyState === videoRef.current.HAVE_ENOUGH_DATA) {
                const canvas = canvasRef.current;
                const video = videoRef.current;
                const context = canvas.getContext('2d');

                if (context) {
                    canvas.width = video.videoWidth;
                    canvas.height = video.videoHeight;
                    context.drawImage(video, 0, 0, canvas.width, canvas.height);

                    const imageData = context.getImageData(0, 0, canvas.width, canvas.height);
                    const code = jsQR(imageData.data, imageData.width, imageData.height, {
                        inversionAttempts: 'dontInvert',
                    });

                    if (code) {
                        onScan(code.data);
                        return; // Stop scanning once found
                    }
                }
            }
            animationId = requestAnimationFrame(scanQRCode);
        };

        if (isOpen) {
            startCamera();
        }

        return () => {
            if (stream) {
                stream.getTracks().forEach(track => track.stop());
            }
            cancelAnimationFrame(animationId);
        };
    }, [isOpen]);

    if (!isOpen) return null;

    return (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/90 backdrop-blur-md animate-in fade-in duration-300">
            <div className="bg-[#0f172a] w-full max-w-lg rounded-[2.5rem] overflow-hidden shadow-2xl shadow-emerald-500/10 border border-white/10 flex flex-col">
                <div className="flex items-center justify-between p-6 border-b border-white/10">
                    <div className="flex items-center gap-3">
                        <div className="w-10 h-10 bg-emerald-500/20 rounded-xl flex items-center justify-center">
                            <QrCode className="w-5 h-5 text-emerald-500" />
                        </div>
                        <div>
                            <h2 className="text-lg font-black italic tracking-tighter text-white uppercase">Escanear QR de Identidade</h2>
                            <p className="text-[10px] font-bold text-slate-500 uppercase tracking-widest">Aproxime o cart├úo da c├ómera</p>
                        </div>
                    </div>
                    <button
                        onClick={onClose}
                        className="p-2 hover:bg-white/5 rounded-full transition-colors text-slate-500 hover:text-white"
                    >
                        <X className="w-6 h-6" />
                    </button>
                </div>

                <div className="relative aspect-square bg-black overflow-hidden m-6 rounded-3xl border-2 border-white/5">
                    <video
                        ref={videoRef}
                        className="w-full h-full object-cover"
                        playsInline
                    />
                    <canvas ref={canvasRef} className="hidden" />

                    {/* Scanner Overlay UI */}
                    <div className="absolute inset-0 pointer-events-none">
                        <div className="absolute inset-0 border-[40px] border-slate-900/40"></div>
                        <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-64 h-64 border-2 border-emerald-500/50 rounded-3xl">
                            {/* Corner Markers */}
                            <div className="absolute -top-1 -left-1 w-8 h-8 border-t-4 border-l-4 border-emerald-500 rounded-tl-xl"></div>
                            <div className="absolute -top-1 -right-1 w-8 h-8 border-t-4 border-r-4 border-emerald-500 rounded-tr-xl"></div>
                            <div className="absolute -bottom-1 -left-1 w-8 h-8 border-b-4 border-l-4 border-emerald-500 rounded-bl-xl"></div>
                            <div className="absolute -bottom-1 -right-1 w-8 h-8 border-b-4 border-r-4 border-emerald-500 rounded-br-xl"></div>

                            {/* Scanning Animation */}
                            <div className="absolute inset-x-4 top-0 h-1 bg-emerald-500 shadow-[0_0_15px_rgba(16,185,129,0.5)] animate-scan-line"></div>
                        </div>

                        <div className="absolute inset-x-0 bottom-10 flex flex-col items-center gap-4 animate-in fade-in slide-in-from-bottom-4">
                            <div className="px-6 py-3 bg-slate-900/80 backdrop-blur-md border border-white/10 rounded-2xl flex items-center gap-3">
                                <div className="w-2 h-2 bg-emerald-500 rounded-full animate-pulse" />
                                <span className="text-xs font-black uppercase tracking-widest text-emerald-500">Buscando QR Code...</span>
                            </div>
                        </div>
                    </div>
                </div>

                <div className="p-8 pt-0 text-center">
                    <p className="text-[10px] font-bold text-slate-500 uppercase tracking-[0.2em] leading-relaxed max-w-[200px] mx-auto">
                        Aponte a c├ómera para o c├│digo impresso no cart├úo de seguran├ºa do aluno.
                    </p>
                </div>
            </div>
        </div>
    );
}

import { useState, useEffect } from 'react';
import { supabase } from '../../lib/supabase';
import { useAuth } from '../../context/AuthContext';
import { Clock, User as UserIcon, MessageSquare, AlertCircle, Check, MapPin } from 'lucide-react';
import { useToast } from '../../components/ui/Toast';

import type { Student } from '../../types';

type PickupRequest = {
    id: string;
    aluno: Student;
    status: string;
    horario_solicitacao: string;
    tempo_espera_segundos?: number;
    mensagem_sala?: string;
    mensagem_recepcao?: string;
    latitude?: number;
    longitude?: number;
    distancia_estimada_metros?: number;
    status_geofence?: 'LONGE' | 'PERTO' | 'CHEGOU';
};

export default function WithdrawalQueue() {
    const { user } = useAuth();
    const toast = useToast();
    const [pendingPickups, setPendingPickups] = useState<PickupRequest[]>([]);

    const fetchPending = async () => {
        const { data } = await supabase
            .from('solicitacoes_retirada')
            .select(`
                id,
                status,
                horario_solicitacao,
                mensagem_recepcao,
                mensagem_sala,
                aluno:alunos (
                    id,
                    nome_completo,
                    turma,
                    sala,
                foto_url
                ),
                latitude,
                longitude,
                distancia_estimada_metros,
                status_geofence
            `)
            .in('status', ['SOLICITADO', 'NOTIFICADO', 'CONFIRMADO', 'AGUARDANDO', 'LIBERADO'])
            .is('horario_confirmacao', null)
            .order('horario_solicitacao', { ascending: true });

        if (data) {
            setPendingPickups(data.map((item: any) => ({
                id: item.id,
                status: item.status,
                horario_solicitacao: item.horario_solicitacao,
                aluno: item.aluno,
                mensagem_recepcao: item.mensagem_recepcao,
                mensagem_sala: item.mensagem_sala,
                distancia_estimada_metros: item.distancia_estimada_metros,
                status_geofence: item.status_geofence
            })));
        }
    };

    const markAsAtReception = async (pickupId: string) => {
        try {
            const { error } = await supabase
                .from('solicitacoes_retirada')
                .update({
                    status: 'CONFIRMADO'
                })
                .eq('id', pickupId);

            if (error) throw error;
            addLog(`Aluno ${pickupId} chegou na recep├º├úo.`);
        } catch (error: any) {
            console.error('Error marking as at reception:', error);
            toast.error('Erro ao registrar chegada', error.message);
        }
    };

    const finalizePickup = async (pickupId: string) => {
        try {
            const { error } = await supabase
                .from('solicitacoes_retirada')
                .update({
                    horario_confirmacao: new Date().toISOString(),
                    status: 'LIBERADO',
                    recepcionista_id: user?.id
                })
                .eq('id', pickupId);

            if (error) throw error;

            // Optimistic update
            setPendingPickups(prev => prev.filter(p => p.id !== pickupId));
        } catch (error: any) {
            console.error('Error finalizing pickup:', error);
            toast.error('Erro ao finalizar sa├¡da', error.message);
        }
    };

    const resetMissingStudent = async (pickupId: string) => {
        try {
            const { error } = await supabase
                .from('solicitacoes_retirada')
                .update({
                    status: 'SOLICITADO',
                    horario_liberacao: null,
                    professor_id: null
                })
                .eq('id', pickupId);

            if (error) throw error;

            // Optimistic update handled by subscription/polling
            addLog(`Solicita├º├úo ${pickupId} retornada para a fila de prioridade.`);
        } catch (error: any) {
            console.error('Error resetting missing student:', error);
            toast.error('Erro ao retornar aluno', error.message);
        }
    };

    // Helper for logs (since this is receptive, we can just console log or add local state if needed)
    const addLog = (msg: string) => console.log(`[Queue] ${msg}`);

    useEffect(() => {
        if (!user) return;

        fetchPending();

        // 1 second polling for high synchronization
        const interval = setInterval(fetchPending, 1000);

        const channel = supabase
            .channel(`reception_queue_${user.id}`)
            .on(
                'postgres_changes',
                {
                    event: '*',
                    schema: 'public',
                    table: 'solicitacoes_retirada'
                },
                () => {
                    fetchPending();
                }
            )
            .subscribe();

        return () => {
            clearInterval(interval);
            supabase.removeChannel(channel);
        };
