export const useAuth = () => useContext(AuthContext);

export const AuthProvider = ({ children }: { children: React.ReactNode }) => {
    const [user, setUser] = useState<User | null>(null);
    const [session, setSession] = useState<Session | null>(null);
    const [loading, setLoading] = useState(true);
    const [role, setRole] = useState<string | null>(null);
    const [escolaId, setEscolaId] = useState<string | null>(null);

    useEffect(() => {
        // Get initial session
        supabase.auth.getSession().then(({ data: { session } }) => {
            setSession(session);
            setUser(session?.user ?? null);
            if (session?.user) {
                fetchUserProfile(session.user.id);
            } else {
                setLoading(false);
            }
        });

        // Listen for auth changes
        const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
            setSession(session);
            setUser(session?.user ?? null);
            if (session?.user) {
                fetchUserProfile(session.user.id);
            } else {
                setRole(null);
                setEscolaId(null);
                setLoading(false);
            }
        });

        return () => subscription.unsubscribe();
    }, []);

    const fetchUserProfile = async (userId: string) => {
        try {
            const { data, error } = await supabase
                .from('usuarios')
                .select('tipo_usuario, escola_id')
                .eq('id', userId)
                .single();

            if (error) {
                console.error('Error fetching user profile:', error);
            } else if (data) {
                setRole(data.tipo_usuario);
                setEscolaId(data.escola_id);
            }
        } catch (error) {
            console.error('Error fetching user profile:', error);
        } finally {
            setLoading(false);
        }
    };

    const signOut = async () => {
        await supabase.auth.signOut();
        setRole(null);
        setEscolaId(null);
    };

    return (
        <AuthContext.Provider value={{ user, session, loading, role, escolaId, signOut }}>
            {children}
        </AuthContext.Provider>
    );
};

import { supabase } from './supabase';

export type AuditAction =
    | 'SISTEMA_LOGIN'
    | 'SISTEMA_LOGOUT'
    | 'LIMPEZA_REGISTROS'
    | 'EXPORTACAO_DADOS'
    | 'ALTERACAO_CONFIGURACAO'
    | 'EXCLUSAO_ESTUDANTE'
    | 'CADASTRO_ESTUDANTE'
    | 'MANIPULACAO_DADOS'
    | 'ANALISE'
    | 'MANUTENCAO';

/**
 * Registra uma a├º├úo no log de auditoria do sistema.
 * 
 * @param action Tipo da a├º├úo (enum AuditAction)
 * @param table Tabela afetada (opcional)
 * @param recordId ID do registro afetado (opcional)
 * @param details Objeto JSON com detalhes adicionais da a├º├úo
 * @param userId ID do usu├írio que realizou a a├º├úo
 * @param escolaId ID da escola associada
 */
export async function logAudit(
    action: AuditAction,
    table?: string,
    recordId?: string,
    details?: any,
    userId?: string,
    escolaId?: string
) {
    try {
        const { error } = await supabase
            .from('logs_auditoria')
            .insert({
                acao: action,
                tabela_afetada: table,
                registro_id: recordId,
                detalhes: details,
                usuario_id: userId,
                escola_id: escolaId,
                ip_address: '0.0.0.0', // Idealmente capturado pelo backend/edge function no Supabase
                user_agent: typeof navigator !== 'undefined' ? navigator.userAgent : 'Server-side'
            });

        if (error) {
            console.error('Audit Log Error:', error);
        }
    } catch (err) {
        console.error('Failed to log audit event:', err);
    }
}

/**
 * Converte um arquivo de imagem para uma data URL v├ílida.
 * Suporta HEIC/HEIF (iPhone) com convers├úo autom├ítica para JPEG.
 * 
 * Estrat├®gia de convers├úo HEIC (3 camadas):
 * 1. createImageBitmap ÔåÆ Canvas (usa decodificador nativo do SO)
 * 2. libheif-js com HEVC decoder (libde265) via WASM
 * 3. Mensagem amig├ível pedindo JPEG/PNG
 */
export async function fileToDataUrl(file: File): Promise<string> {
    const name = file.name.toLowerCase();
    const isHeic = name.endsWith('.heic') || name.endsWith('.heif') ||
        file.type === 'image/heic' || file.type === 'image/heif';
    const hasNoMime = !file.type || file.type === 'application/octet-stream';
    const needsConversion = isHeic || hasNoMime;

    if (needsConversion) {
        console.log('[imageUtils] Arquivo precisa de convers├úo. Nome:', file.name, 'Tipo:', file.type || '(vazio)', 'Tamanho:', file.size);

        // ÔòÉÔòÉÔòÉ CAMADA 1: Decodificador nativo do navegador/SO ÔòÉÔòÉÔòÉ
        try {
            console.log('[imageUtils] Tentando createImageBitmap (decodificador nativo)...');
            const bitmap = await createImageBitmap(file);
            const canvas = document.createElement('canvas');
            canvas.width = bitmap.width;
            canvas.height = bitmap.height;
            const ctx = canvas.getContext('2d');
            if (ctx) {
                ctx.drawImage(bitmap, 0, 0);
                bitmap.close();
                const dataUrl = canvas.toDataURL('image/jpeg', 0.85);
                console.log('[imageUtils] Ô£à Convers├úo via createImageBitmap OK! Dimens├Áes:', canvas.width, 'x', canvas.height);
                return dataUrl;
            }
            bitmap.close();
        } catch (err: any) {
            console.warn('[imageUtils] createImageBitmap falhou:', err?.message || err);
        }

        // ÔòÉÔòÉÔòÉ CAMADA 2: libheif-js com HEVC decoder (libde265) ÔòÉÔòÉÔòÉ
        try {
            console.log('[imageUtils] Tentando libheif-js (WASM com HEVC decoder)...');
            const buffer = await file.arrayBuffer();
            const dataUrl = await decodeHeicWithLibheif(new Uint8Array(buffer));
            console.log('[imageUtils] Ô£à Convers├úo via libheif-js OK!');
            return dataUrl;
        } catch (err: any) {
            console.error('[imageUtils] libheif-js falhou:', err?.message || err);
        }

        // ÔòÉÔòÉÔòÉ CAMADA 3: Verificar se ├® realmente HEIC ÔòÉÔòÉÔòÉ
        if (isHeic || await detectHeicSignature(file)) {
            throw new Error(
                'HEIC_NOT_SUPPORTED: N├úo foi poss├¡vel converter o arquivo HEIC. ' +
                'Por favor, salve a foto como JPEG ou PNG antes de enviar.\n\n' +
                'No iPhone: Ajustes ÔåÆ C├ómera ÔåÆ Formatos ÔåÆ Mais Compat├¡vel'
            );
        }

        console.log('[imageUtils] Arquivo sem MIME type mas n├úo ├® HEIC, carregando direto...');
    }

    return readFileAsDataUrl(file);
}

/**
 * Decodifica um arquivo HEIC usando libheif-js com o decoder HEVC (libde265).
 * Usa o wasm-bundle que inclui o decoder HEVC embutido.
 */
async function decodeHeicWithLibheif(heicData: Uint8Array): Promise<string> {
    // Import din├ómico do wasm-bundle que inclui o HEVC decoder (libde265)
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const libheifModule = await import('libheif-js/wasm-bundle') as any;
    const libheif = libheifModule.default || libheifModule;

    console.log('[imageUtils] libheif carregado. Tipo:', typeof libheif, 'HeifDecoder:', typeof libheif.HeifDecoder);

    const decoder = new libheif.HeifDecoder();
    const images = decoder.decode(heicData.buffer);

    if (!images || images.length === 0) {
        throw new Error('Nenhuma imagem encontrada no arquivo HEIC');
    }

    const image = images[0];
    const width = image.get_width();
    const height = image.get_height();

    console.log('[imageUtils] HEIC decodificado. Dimens├Áes:', width, 'x', height);

    // Criar canvas e ImageData para renderizar
    const canvas = document.createElement('canvas');
    canvas.width = width;
    canvas.height = height;
    const ctx = canvas.getContext('2d');

    if (!ctx) {
        throw new Error('N├úo foi poss├¡vel criar contexto canvas');
    }

    const imageData = ctx.createImageData(width, height);

    // Renderizar a imagem HEIC no ImageData via callback
    await new Promise<void>((resolve, reject) => {
        image.display(imageData, (displayData: ImageData | null) => {
            if (!displayData) {
                reject(new Error('Falha ao renderizar imagem HEIC'));
                return;
            }
            resolve();
        });
    });

    // Colocar o ImageData no canvas e exportar como JPEG
    ctx.putImageData(imageData, 0, 0);
    const dataUrl = canvas.toDataURL('image/jpeg', 0.85);

    console.log('[imageUtils] JPEG gerado via canvas. DataURL length:', dataUrl.length);
    return dataUrl;
}

/**
 * Detecta se um arquivo ├® HEIC pela assinatura bin├íria (magic bytes).
 */
async function detectHeicSignature(file: File): Promise<boolean> {
    try {
        const buffer = await file.slice(0, 24).arrayBuffer();
        const view = new Uint8Array(buffer);
        const text = String.fromCharCode(...view);
        return /ftyp(heic|heix|hevc|mif1|msf1)/i.test(text);
    } catch {
        return false;
    }
}

/**
 * L├¬ um File como data URL.
 */
function readFileAsDataUrl(file: File): Promise<string> {
    return new Promise<string>((resolve, reject) => {
        const reader = new FileReader();
        reader.onloadend = () => {
            const result = reader.result as string;
            if (result) {
                console.log('[imageUtils] Ô£à Data URL gerada, length:', result.length, 'prefix:', result.substring(0, 40));
                resolve(result);
            } else {
                reject(new Error('FileReader n├úo produziu resultado'));
            }
        };
        reader.onerror = () => reject(reader.error || new Error('Erro ao ler arquivo'));
        reader.readAsDataURL(file);
    });
}

