import { useState } from 'react';
import { supabase } from '../../lib/supabase';
import { Mail, ArrowLeft, CheckCircle, Lock } from 'lucide-react';
import { Link } from 'react-router-dom';
import NavigationControls from '../../components/NavigationControls';

type RecoveryStep = 'email' | 'success';

export default function AccountRecoveryFlow() {
    const [step, setStep] = useState<RecoveryStep>('email');
    const [email, setEmail] = useState('');
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState('');

    const handleSendReset = async (e: React.FormEvent) => {
        e.preventDefault();
        setLoading(true);
        setError('');

        try {
            const { error: resetError } = await supabase.auth.resetPasswordForEmail(
                email,
                { redirectTo: window.location.origin + '/reset-password' }
            );

            if (resetError) throw resetError;
            setStep('success');
        } catch (err: any) {
            setError(err.message || 'Erro ao enviar e-mail de recupera├º├úo');
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="min-h-screen bg-gradient-to-br from-slate-50 to-emerald-50 flex items-center justify-center p-4">
            <div className="w-full max-w-md">
                <NavigationControls />
                {step === 'email' ? (
                    <div className="bg-white rounded-2xl shadow-xl p-8">
                        {/* Header */}
                        <div className="text-center mb-8">
                            <div className="inline-flex p-4 bg-emerald-100 rounded-full mb-4">
                                <Lock className="w-8 h-8 text-emerald-600" />
                            </div>
                            <h1 className="text-2xl font-bold text-slate-900 mb-2">Recuperar Acesso</h1>
                            <p className="text-slate-600">
                                Digite seu e-mail cadastrado para receber instru├º├Áes de recupera├º├úo
                            </p>
                        </div>

                        {/* Form */}
                        <form onSubmit={handleSendReset} className="space-y-6">
                            <div>
                                <label className="block text-sm font-medium text-slate-700 mb-2">
                                    E-mail
                                </label>
                                <div className="relative">
                                    <Mail className="absolute left-3 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-400" />
                                    <input
                                        type="email"
                                        required
