                                    </div>
                                    <div className="mt-10 flex justify-end gap-3">
                                        <button
                                            type="button"
                                            onClick={() => setShowForm(false)}
                                            className="px-6 py-3 rounded-2xl font-bold text-slate-500 hover:bg-slate-100 transition-all text-sm"
                                        >
