                        {/* Empty State */}
                        {!showForm && guardians.length === 0 && (
                            <div className="bg-white border border-dashed border-slate-300 rounded-3xl p-16 text-center">
                                <Users className="w-16 h-16 text-slate-100 mx-auto mb-4" />
                                <h3 className="text-lg font-bold text-slate-900 mb-2">Nenhum respons├ível cadastrado</h3>
                                <p className="text-slate-500 max-w-sm mx-auto">Voc├¬ precisa adicionar pelo menos um respons├ível autorizado para prosseguir com o registro.</p>
