                                            <p className="text-slate-500">Carregando turmas...</p>
                                        </td>
                                    </tr>
                                ) : filteredTurmas.length === 0 ? (
                                    <tr>
                                        <td colSpan={4} className="px-6 py-12 text-center text-slate-500">
