// ÔöÇÔöÇÔöÇ Main Component ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

export default function PickupHistoryView() {
    const [records, setRecords] = useState<PickupRecord[]>([]);
    const [loading, setLoading] = useState(true);
    const [refreshing, setRefreshing] = useState(false);
    const [period, setPeriod] = useState<Period>('day');
    const [customStart, setCustomStart] = useState('');
    const [customEnd, setCustomEnd] = useState('');
    // granular pickers
    const [pickDay, setPickDay] = useState(() => new Date().toISOString().split('T')[0]);
    const [pickMonth, setPickMonth] = useState(() => new Date().getMonth());
    const [pickMonthYear, setPickMonthYear] = useState(() => new Date().getFullYear());
    const [pickYear, setPickYear] = useState(() => new Date().getFullYear());
    const [searchTerm, setSearchTerm] = useState('');
    const [statusFilter, setStatusFilter] = useState('all');
    const [detailRecord, setDetailRecord] = useState<PickupRecord | null>(null);
    const [activeView, setActiveView] = useState<'list' | 'analytics'>('list');
    const [page, setPage] = useState(0);
    const PAGE_SIZE = 20;

    const { from, to } = useMemo(
        () => periodRange(period, customStart, customEnd, pickDay, pickMonth, pickMonthYear, pickYear),
        [period, customStart, customEnd, pickDay, pickMonth, pickMonthYear, pickYear]
    );

    const fetchRecords = useCallback(async (silent = false) => {
        if (!silent) setLoading(true);
        else setRefreshing(true);
        try {
            const { data, error } = await supabase
                .from('solicitacoes_retirada')
                .select(`
                    id, status, tipo_solicitacao, horario_solicitacao,
                    horario_notificacao, horario_confirmacao, horario_liberacao,
                    tempo_espera_segundos, observacoes, mensagem_recepcao,
                    aluno:alunos(nome_completo, matricula, turma, sala, foto_url),
                    responsavel:responsaveis(nome_completo, cpf, foto_url)
                `)
                .gte('horario_solicitacao', from)
                .lte('horario_solicitacao', to)
                .order('horario_solicitacao', { ascending: false })
                .limit(500);

            if (error) throw error;
            setRecords((data as any[]) || []);
            setPage(0);
        } catch (err) {
            console.error('Erro ao buscar registros:', err);
        } finally {
            setLoading(false);
            setRefreshing(false);
        }
    }, [from, to]);

    useEffect(() => { fetchRecords(); }, [fetchRecords]);

    // ÔöÇÔöÇ Filtered records ÔöÇÔöÇ
    const filtered = useMemo(() => {
        let r = records;
        if (statusFilter !== 'all') r = r.filter(x => x.status === statusFilter);
        if (searchTerm.trim()) {
            const s = searchTerm.toLowerCase();
            r = r.filter(x =>
                x.aluno?.nome_completo?.toLowerCase().includes(s) ||
                x.responsavel?.nome_completo?.toLowerCase().includes(s) ||
                x.aluno?.matricula?.includes(searchTerm) ||
                x.aluno?.turma?.toLowerCase().includes(s)
            );
        }
        return r;
    }, [records, statusFilter, searchTerm]);

    const paginated = filtered.slice(page * PAGE_SIZE, (page + 1) * PAGE_SIZE);
    const totalPages = Math.ceil(filtered.length / PAGE_SIZE);

    // ÔöÇÔöÇ Analytics ÔöÇÔöÇ
    const analytics = useMemo(() => {
        const total = records.length;
        const liberados = records.filter(r => r.status === 'LIBERADO');
        const cancelados = records.filter(r => r.status === 'CANCELADO');
        const avgWait = liberados.length
            ? Math.round(liberados.reduce((a, r) => a + (r.tempo_espera_segundos || 0), 0) / liberados.length)
            : 0;

        // Pickups by hour bucket (6 buckets: 6h-23h)
        const hours: Record<number, number> = {};
        records.forEach(r => {
            if (r.horario_solicitacao) {
                const h = new Date(r.horario_solicitacao).getHours();
                hours[h] = (hours[h] || 0) + 1;
            }
        });
        const hourBuckets = Array.from({ length: 18 }, (_, i) => i + 6).map(h => ({
            label: `${String(h).padStart(2, '0')}h`,
            value: hours[h] || 0,
        }));

        // Top guardians
        const guardianMap: Record<string, { name: string; count: number }> = {};
        records.forEach(r => {
            if (r.responsavel?.cpf) {
                const key = r.responsavel.cpf;
                if (!guardianMap[key]) guardianMap[key] = { name: r.responsavel.nome_completo, count: 0 };
                guardianMap[key].count++;
            }
        });
        const topGuardians = Object.values(guardianMap).sort((a, b) => b.count - a.count).slice(0, 5);

        // Top students (most pickups)
        const studentMap: Record<string, { name: string; turma: string; count: number }> = {};
        records.forEach(r => {
            if (r.aluno?.matricula) {
                const key = r.aluno.matricula;
                if (!studentMap[key]) studentMap[key] = { name: r.aluno.nome_completo, turma: r.aluno.turma, count: 0 };
                studentMap[key].count++;
            }
        });
        const topStudents = Object.values(studentMap).sort((a, b) => b.count - a.count).slice(0, 5);

        // By day (for week/month/year periods)
        const dayMap: Record<string, number> = {};
        records.forEach(r => {
            if (r.horario_solicitacao) {
                const d = new Date(r.horario_solicitacao).toLocaleDateString('pt-BR', { weekday: 'short' });
                dayMap[d] = (dayMap[d] || 0) + 1;
            }
        });
        const weekDays = ['dom', 'seg', 'ter', 'qua', 'qui', 'sex', 's├íb'];
        const dayBuckets = weekDays.map(d => ({ label: d, value: dayMap[d] || 0 }));

        return { total, liberados: liberados.length, cancelados: cancelados.length, avgWait, hourBuckets, dayBuckets, topGuardians, topStudents };
    }, [records]);

    // ÔöÇÔöÇ Export CSV ÔöÇÔöÇ
    const exportCSV = () => {
        const header = ['Data', 'Hora Solicita├º├úo', 'Hora Libera├º├úo', 'Aluno', 'Matr├¡cula', 'Turma', 'Sala', 'Respons├ível', 'CPF', 'Status', 'Tempo Espera (seg)', 'Observa├º├Áes'];
        const rows = filtered.map(r => [
            fmtDate(r.horario_solicitacao),
            fmtTime(r.horario_solicitacao),
            fmtTime(r.horario_liberacao),
            r.aluno?.nome_completo || '',
            r.aluno?.matricula || '',
            r.aluno?.turma || '',
            r.aluno?.sala || '',
            r.responsavel?.nome_completo || '',
            r.responsavel?.cpf || '',
            STATUS_PT[r.status] || r.status,
            r.tempo_espera_segundos?.toString() || '',
            r.observacoes || '',
        ]);
        const csv = [header, ...rows].map(r => r.map(v => `"${String(v).replace(/"/g, '""')}"`).join(',')).join('\n');
        const blob = new Blob(['\uFEFF' + csv], { type: 'text/csv;charset=utf-8;' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a'); a.href = url;
        a.download = `retiradas_${period}_${new Date().toISOString().split('T')[0]}.csv`;
        a.click(); URL.revokeObjectURL(url);
    };

    const PERIOD_LABELS: Record<Period, string> = {
        day: 'Hoje', week: 'Esta Semana', month: 'Este M├¬s', year: 'Este Ano',
        custom: 'Intervalo', 'pick-day': 'Dia', 'pick-month': 'M├¬s', 'pick-year': 'Ano'
    };

    const MONTH_NAMES = ['Janeiro', 'Fevereiro', 'Mar├ºo', 'Abril', 'Maio', 'Junho', 'Julho', 'Agosto', 'Setembro', 'Outubro', 'Novembro', 'Dezembro'];
    const currentYear = new Date().getFullYear();
    const yearOptions = Array.from({ length: 6 }, (_, i) => currentYear - i);

    if (loading) {
        return (
            <div className="min-h-screen flex items-center justify-center bg-slate-50">
                <div className="flex flex-col items-center gap-4">
                    <div className="w-12 h-12 border-4 border-indigo-600 border-t-transparent rounded-full animate-spin" />
                    <p className="font-bold text-slate-400 animate-pulse uppercase tracking-widest text-xs">Carregando Relat├│rios...</p>
                </div>
            </div>
        );
    }

    return (
        <div className="bg-slate-50 min-h-screen text-slate-800 font-display">
            {/* Sticky Header */}
            <header className="sticky top-0 z-30 bg-white/95 backdrop-blur-md border-b border-slate-200 shadow-sm">
                <div className="max-w-7xl mx-auto px-6 h-16 flex items-center justify-between gap-4">
                    <div className="flex items-center gap-3">
                        <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center shadow-lg shadow-indigo-600/20">
                            <BarChart2 className="text-white w-5 h-5" />
                        </div>
                        <div>
                            <span className="text-sm font-black text-slate-900 block leading-none">Central de Relat├│rios</span>
                            <span className="text-[10px] text-slate-400 font-medium">Retiradas ┬À Auditoria ┬À An├ílise</span>
                        </div>
                    </div>
                    <div className="flex items-center gap-3">
                        {/* View toggle */}
                        <div className="flex bg-slate-100 rounded-xl p-1 gap-1">
                            <button onClick={() => setActiveView('list')} className={`px-4 py-1.5 rounded-lg text-xs font-bold transition-all flex items-center gap-1.5 ${activeView === 'list' ? 'bg-white shadow text-indigo-600' : 'text-slate-400 hover:text-slate-700'}`}>
                                <FileText className="w-3.5 h-3.5" /> Registros
                            </button>
                            <button onClick={() => setActiveView('analytics')} className={`px-4 py-1.5 rounded-lg text-xs font-bold transition-all flex items-center gap-1.5 ${activeView === 'analytics' ? 'bg-white shadow text-indigo-600' : 'text-slate-400 hover:text-slate-700'}`}>
                                <Activity className="w-3.5 h-3.5" /> An├ílise
                            </button>
                        </div>
                        <button onClick={() => fetchRecords(true)} className={`p-2 rounded-xl border border-slate-200 hover:border-indigo-300 transition-all text-slate-400 hover:text-indigo-600 ${refreshing ? 'animate-spin' : ''}`}>
                            <RefreshCw className="w-4 h-4" />
                        </button>
                        <button onClick={exportCSV} className="flex items-center gap-2 px-4 py-2 bg-indigo-600 hover:bg-indigo-700 text-white rounded-xl text-xs font-bold transition-all shadow-lg shadow-indigo-600/20 active:scale-95">
                            <Download className="w-4 h-4" /> Exportar CSV
                        </button>
                    </div>
                </div>
            </header>

            <main className="max-w-7xl mx-auto px-6 py-8 space-y-8">
                <NavigationControls />

                {/* Period Selector */}
                <div className="space-y-3">
                    {/* Quick presets row */}
                    <div className="flex flex-wrap items-center gap-2">
                        <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest shrink-0">Atalhos:</span>
                        {(['day', 'week', 'month', 'year'] as Period[]).map(p => (
                            <button key={p} onClick={() => { setPeriod(p); setPage(0); }}
                                className={`px-4 py-2 rounded-xl text-xs font-bold transition-all border ${period === p
                                        ? 'bg-indigo-600 text-white border-indigo-600 shadow-md shadow-indigo-200'
                                        : 'bg-white text-slate-500 border-slate-200 hover:border-indigo-300 hover:text-indigo-600'
                                    }`}>{PERIOD_LABELS[p]}</button>
                        ))}
                        <div className="h-5 w-px bg-slate-200 mx-1" />
                        <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest shrink-0">Personalizado:</span>
                        {(['pick-day', 'pick-month', 'pick-year', 'custom'] as Period[]).map(p => (
                            <button key={p} onClick={() => { setPeriod(p); setPage(0); }}
                                className={`px-4 py-2 rounded-xl text-xs font-bold transition-all border ${period === p
                                        ? 'bg-violet-600 text-white border-violet-600 shadow-md shadow-violet-200'
                                        : 'bg-white text-slate-500 border-slate-200 hover:border-violet-300 hover:text-violet-600'
                                    }`}>{PERIOD_LABELS[p]}</button>
                        ))}
                    </div>

                    {/* Contextual Sub-picker */}
                    {period === 'pick-day' && (
                        <div className="flex items-center gap-3 bg-white border border-violet-200 rounded-2xl px-5 py-3 shadow-sm w-fit">
                            <Calendar className="w-4 h-4 text-violet-500 shrink-0" />
                            <span className="text-xs font-bold text-slate-500">Selecione o dia:</span>
                            <input
                                type="date"
                                value={pickDay}
                                max={new Date().toISOString().split('T')[0]}
                                onChange={e => { setPickDay(e.target.value); setPage(0); }}
                                className="text-sm font-bold text-slate-800 outline-none bg-transparent border-b-2 border-violet-300 focus:border-violet-600 transition-colors px-1"
                            />
                        </div>
                    )}

                    {period === 'pick-month' && (
                        <div className="flex items-center gap-3 bg-white border border-violet-200 rounded-2xl px-5 py-3 shadow-sm w-fit">
                            <Calendar className="w-4 h-4 text-violet-500 shrink-0" />
                            <span className="text-xs font-bold text-slate-500">M├¬s:</span>
                            <select
                                value={pickMonth}
                                onChange={e => { setPickMonth(Number(e.target.value)); setPage(0); }}
                                className="text-sm font-bold text-slate-800 outline-none bg-transparent border-b-2 border-violet-300 focus:border-violet-600 transition-colors px-1 pr-6"
                            >
                                {MONTH_NAMES.map((m, i) => (
                                    <option key={i} value={i}>{m}</option>
                                ))}
                            </select>
                            <span className="text-xs font-bold text-slate-500">Ano:</span>
                            <select
                                value={pickMonthYear}
                                onChange={e => { setPickMonthYear(Number(e.target.value)); setPage(0); }}
                                className="text-sm font-bold text-slate-800 outline-none bg-transparent border-b-2 border-violet-300 focus:border-violet-600 transition-colors px-1 pr-4"
                            >
                                {yearOptions.map(y => <option key={y} value={y}>{y}</option>)}
                            </select>
                        </div>
                    )}

                    {period === 'pick-year' && (
                        <div className="flex items-center gap-3 bg-white border border-violet-200 rounded-2xl px-5 py-3 shadow-sm w-fit">
                            <Calendar className="w-4 h-4 text-violet-500 shrink-0" />
                            <span className="text-xs font-bold text-slate-500">Ano:</span>
                            <select
                                value={pickYear}
                                onChange={e => { setPickYear(Number(e.target.value)); setPage(0); }}
                                className="text-sm font-bold text-slate-800 outline-none bg-transparent border-b-2 border-violet-300 focus:border-violet-600 transition-colors px-1 pr-4"
                            >
                                {yearOptions.map(y => <option key={y} value={y}>{y}</option>)}
                            </select>
                        </div>
                    )}

                    {period === 'custom' && (
                        <div className="flex flex-wrap items-center gap-3 bg-white border border-violet-200 rounded-2xl px-5 py-3 shadow-sm w-fit">
                            <Calendar className="w-4 h-4 text-violet-500 shrink-0" />
                            <span className="text-xs font-bold text-slate-500">De:</span>
                            <input type="date" value={customStart}
                                max={new Date().toISOString().split('T')[0]}
                                onChange={e => setCustomStart(e.target.value)}
                                className="text-sm font-bold text-slate-800 outline-none bg-transparent border-b-2 border-violet-300 focus:border-violet-600 transition-colors px-1" />
                            <span className="text-xs font-bold text-slate-400">at├®:</span>
                            <input type="date" value={customEnd}
                                max={new Date().toISOString().split('T')[0]}
                                onChange={e => setCustomEnd(e.target.value)}
                                className="text-sm font-bold text-slate-800 outline-none bg-transparent border-b-2 border-violet-300 focus:border-violet-600 transition-colors px-1" />
                            <button onClick={() => { setPage(0); fetchRecords(); }}
                                disabled={!customStart || !customEnd}
                                className="px-4 py-1.5 bg-violet-600 text-white rounded-xl text-xs font-bold disabled:opacity-40 hover:bg-violet-700 transition-colors">
                                Aplicar
                            </button>
                        </div>
                    )}

                    {/* Active range label */}
                    <div className="flex items-center gap-2 text-[11px] text-slate-400 font-medium">
                        <Clock className="w-3.5 h-3.5" />
                        <span>Exibindo: <strong className="text-slate-600">{fmtDate(from)}</strong> at├® <strong className="text-slate-600">{fmtDate(to)}</strong></span>
                    </div>
                </div>

                {/* KPI Stats */}
                <div className="grid grid-cols-2 lg:grid-cols-4 gap-4">
                    <StatCard label="Total de Retiradas" value={analytics.total} icon={Activity}
                        color="border-slate-200 text-slate-600" sub={period === 'day' ? 'neste dia' : undefined} />
                    <StatCard label="Liberados" value={analytics.liberados} icon={CheckCircle2}
                        color="border-emerald-200 text-emerald-600"
                        sub={analytics.total ? `${Math.round(analytics.liberados / analytics.total * 100)}% do total` : undefined}
                        trend={analytics.liberados > 0 ? 'up' : 'neutral'} />
                    <StatCard label="Cancelados / Alertas" value={analytics.cancelados} icon={AlertTriangle}
                        color="border-rose-200 text-rose-600"
                        trend={analytics.cancelados > 0 ? 'down' : 'neutral'} />
                    <StatCard label="Tempo M├®dio de Espera" value={waitLabel(analytics.avgWait)} icon={Clock}
                        color="border-indigo-200 text-indigo-600"
                        sub="registros liberados" />
                </div>

                {/* ÔöÇÔöÇÔöÇ ANALYTICS VIEW ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ */}
                {activeView === 'analytics' && (
                    <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
                        {/* Retiradas por Hora do Dia */}
                        <div className="bg-white rounded-3xl border border-slate-200 shadow-sm p-6">
                            <div className="flex items-center gap-2 mb-6">
                                <Clock className="w-4 h-4 text-indigo-600" />
                                <h3 className="text-sm font-black text-slate-900">Retiradas por Hora do Dia</h3>
                            </div>
                            {records.length > 0 ? (
                                <MiniBarChart data={analytics.hourBuckets} color="#6366f1" />
                            ) : (
                                <p className="text-xs text-slate-400 italic text-center py-8">Sem dados para o per├¡odo.</p>
                            )}
                        </div>

                        {/* Retiradas por Dia da Semana */}
                        <div className="bg-white rounded-3xl border border-slate-200 shadow-sm p-6">
                            <div className="flex items-center gap-2 mb-6">
                                <Calendar className="w-4 h-4 text-violet-600" />
                                <h3 className="text-sm font-black text-slate-900">Retiradas por Dia da Semana</h3>
                            </div>
                            {records.length > 0 ? (
                                <MiniBarChart data={analytics.dayBuckets} color="#7c3aed" />
                            ) : (
                                <p className="text-xs text-slate-400 italic text-center py-8">Sem dados para o per├¡odo.</p>
                            )}
                        </div>

                        {/* Top Respons├íveis */}
                        <div className="bg-white rounded-3xl border border-slate-200 shadow-sm p-6">
                            <div className="flex items-center gap-2 mb-6">
                                <Users className="w-4 h-4 text-blue-600" />
                                <h3 className="text-sm font-black text-slate-900">Respons├íveis Mais Frequentes</h3>
                            </div>
                            {analytics.topGuardians.length > 0 ? (
                                <div className="space-y-3">
                                    {analytics.topGuardians.map((g, i) => (
                                        <div key={i} className="flex items-center gap-3">
                                            <div className={`w-7 h-7 rounded-lg flex items-center justify-center text-[10px] font-black shrink-0 ${i === 0 ? 'bg-indigo-600 text-white' : 'bg-slate-100 text-slate-500'}`}>{i + 1}</div>
                                            <div className="flex-1 min-w-0">
                                                <p className="text-xs font-bold text-slate-900 truncate">{g.name}</p>
                                                <div className="w-full bg-slate-100 rounded-full h-1.5 mt-1">
                                                    <div className="bg-indigo-500 h-1.5 rounded-full" style={{ width: `${(g.count / (analytics.topGuardians[0]?.count || 1)) * 100}%` }} />
                                                </div>
                                            </div>
                                            <span className="text-xs font-black text-indigo-600 shrink-0">{g.count}x</span>
                                        </div>
                                    ))}
                                </div>
                            ) : (
                                <p className="text-xs text-slate-400 italic text-center py-8">Sem dados.</p>
                            )}
                        </div>

                        {/* Alunos com mais retiradas */}
                        <div className="bg-white rounded-3xl border border-slate-200 shadow-sm p-6">
                            <div className="flex items-center gap-2 mb-6">
                                <Shield className="w-4 h-4 text-emerald-600" />
                                <h3 className="text-sm font-black text-slate-900">Alunos com Mais Retiradas</h3>
                            </div>
                            {analytics.topStudents.length > 0 ? (
                                <div className="space-y-3">
                                    {analytics.topStudents.map((s, i) => (
                                        <div key={i} className="flex items-center gap-3">
                                            <div className={`w-7 h-7 rounded-lg flex items-center justify-center text-[10px] font-black shrink-0 ${i === 0 ? 'bg-emerald-600 text-white' : 'bg-slate-100 text-slate-500'}`}>{i + 1}</div>
                                            <div className="flex-1 min-w-0">
                                                <p className="text-xs font-bold text-slate-900 truncate">{s.name}</p>
                                                <p className="text-[10px] text-slate-400 truncate">{s.turma}</p>
                                                <div className="w-full bg-slate-100 rounded-full h-1.5 mt-1">
                                                    <div className="bg-emerald-500 h-1.5 rounded-full" style={{ width: `${(s.count / (analytics.topStudents[0]?.count || 1)) * 100}%` }} />
                                                </div>
                                            </div>
                                            <span className="text-xs font-black text-emerald-600 shrink-0">{s.count}x</span>
                                        </div>
                                    ))}
                                </div>
                            ) : (
                                <p className="text-xs text-slate-400 italic text-center py-8">Sem dados.</p>
                            )}
                        </div>

                        {/* Tempo m├®dio por hora */}
                        <div className="bg-white rounded-3xl border border-slate-200 shadow-sm p-6 lg:col-span-2">
                            <div className="flex items-center justify-between mb-4">
                                <div className="flex items-center gap-2">
                                    <TrendingUp className="w-4 h-4 text-amber-600" />
                                    <h3 className="text-sm font-black text-slate-900">Auditoria de Seguran├ºa ÔÇö Alertas e Cancelamentos</h3>
                                </div>
                            </div>
                            {analytics.cancelados > 0 ? (
                                <div className="space-y-2">
                                    {records.filter(r => r.status === 'CANCELADO').slice(0, 8).map(r => (
                                        <div key={r.id} onClick={() => setDetailRecord(r)}
                                            className="flex items-center gap-4 p-3 bg-rose-50 border border-rose-100 rounded-2xl hover:border-rose-300 cursor-pointer transition-all group">
                                            <AlertCircle className="w-4 h-4 text-rose-500 shrink-0" />
                                            <div className="flex-1 min-w-0">
                                                <p className="text-xs font-bold text-slate-900 truncate">{r.aluno?.nome_completo}</p>
                                                <p className="text-[10px] text-slate-400">{r.responsavel?.nome_completo || 'Respons├ível n├úo identificado'} ┬À {fmtDate(r.horario_solicitacao)} ├ás {fmtTime(r.horario_solicitacao)}</p>
                                            </div>
                                            {r.observacoes && <p className="text-[10px] text-rose-500 italic truncate max-w-[180px]">{r.observacoes}</p>}
                                            <Eye className="w-4 h-4 text-rose-300 group-hover:text-rose-500 shrink-0" />
                                        </div>
                                    ))}
                                </div>
                            ) : (
                                <div className="flex items-center gap-3 p-6 bg-emerald-50 rounded-2xl">
                                    <CheckCircle2 className="w-5 h-5 text-emerald-500 shrink-0" />
                                    <p className="text-sm font-bold text-emerald-700">Nenhum cancelamento ou alerta registrado no per├¡odo. Ô£ô</p>
                                </div>
                            )}
                        </div>
                    </div>
                )}

                {/* ÔöÇÔöÇÔöÇ LIST VIEW ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ */}
                {activeView === 'list' && (
                    <>
                        {/* Filters */}
                        <div className="bg-white rounded-2xl border border-slate-200 shadow-sm p-4 flex flex-col md:flex-row gap-4 items-center justify-between">
                            <div className="relative flex-1 md:w-80 w-full">
                                <Search className="absolute left-3 top-2.5 w-4 h-4 text-slate-400 pointer-events-none" />
                                <input
                                    type="text"
                                    placeholder="Buscar aluno, respons├ível, turma..."
                                    value={searchTerm}
                                    onChange={e => { setSearchTerm(e.target.value); setPage(0); }}
                                    className="w-full pl-10 pr-4 py-2 bg-slate-50 border-none rounded-xl text-xs font-semibold placeholder:text-slate-400 outline-none focus:ring-2 focus:ring-indigo-500/20"
                                />
                            </div>
                            <div className="flex items-center gap-2">
                                <Filter className="w-4 h-4 text-slate-400" />
                                <div className="flex bg-slate-50 p-1 rounded-xl gap-1">
                                    {['all', 'LIBERADO', 'CONFIRMADO', 'SOLICITADO', 'CANCELADO'].map(s => (
                                        <button key={s} onClick={() => { setStatusFilter(s); setPage(0); }}
                                            className={`px-3 py-1.5 rounded-lg text-[10px] font-bold uppercase tracking-wider transition-all ${statusFilter === s ? 'bg-white shadow text-indigo-600' : 'text-slate-400 hover:text-slate-600'}`}>
                                            {s === 'all' ? 'Todos' : STATUS_PT[s]}
                                        </button>
                                    ))}
                                </div>
                            </div>
                        </div>

                        {/* Table */}
                        <div className="bg-white rounded-3xl border border-slate-200 shadow-sm overflow-hidden">
                            <div className="overflow-x-auto">
                                <table className="w-full text-left border-collapse">
                                    <thead>
                                        <tr className="bg-slate-50 border-b border-slate-200">
                                            {['Aluno', 'Turma / Sala', 'Respons├ível', 'Status', 'Solicitado', 'Liberado', 'Espera', ''].map((h, i) => (
                                                <th key={i} className="px-5 py-4 text-[10px] font-black text-slate-400 uppercase tracking-widest whitespace-nowrap">{h}</th>
                                            ))}
                                        </tr>
                                    </thead>
                                    <tbody className="divide-y divide-slate-100">
                                        {paginated.map(record => (
                                            <tr key={record.id} className="hover:bg-indigo-50/30 transition-colors group">
                                                <td className="px-5 py-4">
                                                    <div className="flex items-center gap-3">
                                                        {record.aluno?.foto_url ? (
                                                            <img src={record.aluno.foto_url} className="w-8 h-8 rounded-xl object-cover shrink-0" alt="" />
                                                        ) : (
                                                            <div className="w-8 h-8 rounded-xl bg-indigo-100 flex items-center justify-center text-indigo-600 font-black text-xs shrink-0">
                                                                {record.aluno?.nome_completo?.[0] || '?'}
                                                            </div>
                                                        )}
                                                        <p className="text-sm font-bold text-slate-900 whitespace-nowrap">{record.aluno?.nome_completo || 'ÔÇö'}</p>
                                                    </div>
                                                </td>
                                                <td className="px-5 py-4">
                                                    <p className="text-xs font-bold text-slate-700">{record.aluno?.turma || 'ÔÇö'}</p>
                                                    <p className="text-[10px] text-slate-400">Sala: {record.aluno?.sala || 'ÔÇö'}</p>
                                                </td>
                                                <td className="px-5 py-4">
                                                    <p className="text-xs font-bold text-slate-700">{record.responsavel?.nome_completo || 'ÔÇö'}</p>
                                                    <p className="text-[10px] text-slate-400 font-mono">{record.responsavel?.cpf || ''}</p>
                                                </td>
                                                <td className="px-5 py-4">
                                                    <span className={`inline-flex items-center gap-1 px-2.5 py-1 rounded-lg border text-[10px] font-bold uppercase tracking-wider ${STATUS_STYLE[record.status] || 'bg-slate-50 text-slate-600 border-slate-200'}`}>
                                                        {STATUS_PT[record.status] || record.status}
                                                    </span>
                                                </td>
                                                <td className="px-5 py-4 text-xs font-bold text-slate-600 whitespace-nowrap">
                                                    <p>{fmtDate(record.horario_solicitacao)}</p>
                                                    <p className="text-slate-400">{fmtTime(record.horario_solicitacao)}</p>
                                                </td>
                                                <td className="px-5 py-4 text-xs font-bold text-emerald-600 whitespace-nowrap">
                                                    {fmtTime(record.horario_liberacao)}
                                                </td>
                                                <td className="px-5 py-4 text-xs font-bold text-indigo-600 whitespace-nowrap">
                                                    {waitLabel(record.tempo_espera_segundos)}
                                                </td>
                                                <td className="px-5 py-4">
                                                    <button onClick={() => setDetailRecord(record)}
                                                        className="p-2 rounded-xl text-slate-300 hover:text-indigo-600 hover:bg-indigo-50 transition-all">
                                                        <Eye className="w-4 h-4" />
                                                    </button>
                                                </td>
                                            </tr>
                                        ))}
                                    </tbody>
                                </table>

                                {paginated.length === 0 && (
                                    <div className="flex flex-col items-center justify-center py-20">
                                        <Search className="w-12 h-12 text-slate-200 mb-4" />
                                        <p className="text-sm font-bold text-slate-400 uppercase tracking-widest">Nenhum registro encontrado</p>
                                        <p className="text-xs text-slate-300 mt-2">Ajuste os filtros ou o per├¡odo selecionado.</p>
                                    </div>
                                )}
                            </div>

                            {/* Pagination */}
                            <div className="px-6 py-4 border-t border-slate-100 bg-slate-50/50 flex items-center justify-between">
                                <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">
                                    {filtered.length} registro{filtered.length !== 1 ? 's' : ''} ┬À P├ígina {page + 1} de {Math.max(totalPages, 1)}
                                </span>
                                <div className="flex gap-2">
                                    <button disabled={page === 0} onClick={() => setPage(p => p - 1)}
                                        className="flex items-center gap-1 px-3 py-1.5 bg-white border border-slate-200 rounded-lg text-xs font-bold text-slate-500 hover:text-indigo-600 hover:border-indigo-300 disabled:opacity-30 transition-all">
                                        <ArrowLeft className="w-3.5 h-3.5" /> Anterior
                                    </button>
                                    <button disabled={page >= totalPages - 1} onClick={() => setPage(p => p + 1)}
                                        className="flex items-center gap-1 px-3 py-1.5 bg-white border border-slate-200 rounded-lg text-xs font-bold text-slate-500 hover:text-indigo-600 hover:border-indigo-300 disabled:opacity-30 transition-all">
                                        Pr├│xima <ArrowRight className="w-3.5 h-3.5" />
                                    </button>
                                </div>
                            </div>
                        </div>
                    </>
                )}
            </main>

            {/* Detail Modal */}
            {detailRecord && <RecordDetail record={detailRecord} onClose={() => setDetailRecord(null)} />}
        </div>
    );
}

import { useState, useEffect, useRef } from 'react';
import { supabase } from '../../lib/supabase';
import { Search, QrCode, Download, Printer, User as UserIcon, Calendar, Smartphone, ArrowLeft, Loader2, Camera, Edit2, Check, X } from 'lucide-react';
import QRCodeStyling from 'qr-code-styling';
import domtoimage from 'dom-to-image-more';
import NavigationControls from '../../components/NavigationControls';
import { useToast } from '../../components/ui/Toast';

import type { Guardian } from '../../types';

export default function AdminQRGenerator() {
    const toast = useToast();
    const [searchTerm, setSearchTerm] = useState('');
    const [guardians, setGuardians] = useState<Guardian[]>([]);
    const [selectedGuardian, setSelectedGuardian] = useState<Guardian | null>(null);
    const [loading, setLoading] = useState(false);
    const [generating, setGenerating] = useState(false);
    const qrRef = useRef<HTMLDivElement>(null);
    const qrCode = useRef<QRCodeStyling | null>(null);
    const fileInputRef = useRef<HTMLInputElement>(null);
    const [uploadingPhoto, setUploadingPhoto] = useState(false);
    const [editingValidity, setEditingValidity] = useState(false);
    const [newValidityDate, setNewValidityDate] = useState('');
    const [updatingValidity, setUpdatingValidity] = useState(false);

    useEffect(() => {
        if (selectedGuardian && qrRef.current) {
            generateQRCode();
        }
    }, [selectedGuardian]);

    const handleSearch = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!searchTerm.trim()) return;

        setLoading(true);
        try {
            const { data, error } = await supabase
                .from('responsaveis')
                .select('*')
                .or(`nome_completo.ilike.%${searchTerm}%,cpf.ilike.%${searchTerm}%`)
                .limit(5);

            if (error) throw error;
            setGuardians(data || []);
        } catch (err) {
            console.error('Error searching guardians:', err);
        } finally {
            setLoading(false);
        }
    };

    const selectGuardian = async (guardian: Guardian) => {
        setGenerating(true);
        setSelectedGuardian(null);

        try {
            // Check for existing QR card
            const { data: qrCard, error: fetchError } = await supabase
                .from('parent_qr_cards')
                .select('*')
                .eq('responsavel_id', guardian.id)
                .eq('active', true)
                .order('created_at', { ascending: false })
                .limit(1)
                .maybeSingle(); // Limit 1 + maybeSingle is safer against data duplication

            if (fetchError) throw fetchError;

            let finalCard = qrCard;

            // Create or Reactivate
            if (!finalCard) {
                console.log('[QRGen] No active card found, searching for any existing card for responsavel:', guardian.id);
                // Check if any card exists (even inactive) to reuse QR code
                const { data: anyCard, error: anyCardError } = await supabase
                    .from('parent_qr_cards')
                    .select('*')
                    .eq('responsavel_id', guardian.id)
                    .order('created_at', { ascending: false })
                    .limit(1)
                    .maybeSingle();

                if (anyCardError) {
                    console.error('[QRGen] Error searching for any existing card:', anyCardError);
                }

                const newQRCodeBase = anyCard?.qr_code || `LaSalleCheguei-${guardian.id}-${Date.now()}`;
                const expiresAt = new Date();
                expiresAt.setMonth(expiresAt.getMonth() + 12); // Extending to 12 months as per standard

                console.log('[QRGen] Inserting/Reactivating card with QR:', newQRCodeBase);
                const { data: newCard, error: insertError } = await supabase
                    .from('parent_qr_cards')
                    .insert({
                        responsavel_id: guardian.id,
                        qr_code: newQRCodeBase,
                        expires_at: expiresAt.toISOString(),
                        active: true
                    })
                    .select()
                    .maybeSingle(); // maybeSingle instead of single() to handle RLS visibility issues gracefully

                if (insertError) {
                    console.error('[QRGen] Insert error:', insertError);
                    throw insertError;
                }
                finalCard = newCard;
            }

            setSelectedGuardian({
                ...guardian,
                qr_code: finalCard?.qr_code,
                expires_at: finalCard?.expires_at,
                codigo_acesso: guardian.codigo_acesso
            });
        } catch (err: any) {
            console.error('Error selecting guardian:', err);
            const errorMsg = err.message || 'Erro desconhecido';
            toast.error('Erro ao carregar/gerar cart├úo', `Detalhe: ${errorMsg}. Verifique as permiss├Áes de RLS no banco.`);
        } finally {
            setGenerating(false);
        }
    };

    const generateQRCode = () => {
        if (!selectedGuardian?.qr_code) return;

        qrCode.current = new QRCodeStyling({
            width: 300,
            height: 300,
            data: selectedGuardian.qr_code,
            type: 'canvas', // Explicitly use canvas for better html2canvas support
            dotsOptions: {
                color: '#047857',
                type: 'rounded'
            },
            backgroundOptions: {
                color: '#ffffff'
            },
            imageOptions: {
                crossOrigin: 'anonymous',
                margin: 10
            }
        });

        if (qrRef.current) {
            qrRef.current.innerHTML = '';
            qrCode.current.append(qrRef.current);
        }
    };

    const handleDownload = async () => {
        const cardElement = document.getElementById('qr-card-printable');
        if (cardElement && selectedGuardian) {
            setGenerating(true);
            try {
                if (qrRef.current && qrRef.current.innerHTML === '' && qrCode.current) {
                    qrCode.current.append(qrRef.current);
                }

                await new Promise(resolve => setTimeout(resolve, 500));

                // --- STEP 1: INJECT OVERRIDE STYLESHEET ---
                const captureStyle = document.createElement('style');
                captureStyle.id = 'qr-capture-override';
                captureStyle.textContent = `
                    #qr-card-printable,
                    #qr-card-printable *,
                    #qr-card-printable *::before,
                    #qr-card-printable *::after {
                        border-color: transparent !important;
                        border-image: none !important;
                        outline: none !important;
                        box-shadow: none !important;
                        text-shadow: none !important;
                        text-decoration: none !important;
                    }
                    #qr-card-printable canvas {
                        border: none !important;
                        outline: none !important;
                    }
                    #qr-card-printable .capture-ignore,
                    #qr-card-printable .no-print {
                        display: none !important;
                    }
                `;
                document.head.appendChild(captureStyle);

                // --- STEP 2: ALSO PATCH INLINE STYLES (belt-and-suspenders) ---
                // dom-to-image inlines computed styles; we force transparent on the live DOM
                // so the computed value IS transparent when dom-to-image reads it.
                const allElements = [cardElement, ...Array.from(cardElement.querySelectorAll('*'))] as HTMLElement[];
                const savedStyles = allElements.map(el => el.getAttribute('style'));

                allElements.forEach(el => {
                    el.style.borderColor = 'transparent';
                    el.style.outline = 'none';
                    el.style.boxShadow = 'none';
                    // Also force border on canvas explicitly
                    if (el.tagName === 'CANVAS') {
                        el.style.border = 'none';
                    }
                });

                // Let browser recalculate
                await new Promise(resolve => setTimeout(resolve, 200));

                const dataUrl = await domtoimage.toPng(cardElement, {
                    bgcolor: '#ffffff',
                    width: cardElement.offsetWidth,
                    height: cardElement.offsetHeight,
                    cacheBust: true,
                });

                // --- STEP 3: RESTORE EVERYTHING ---
                captureStyle.remove();
                allElements.forEach((el, i) => {
                    if (savedStyles[i] !== null) {
                        el.setAttribute('style', savedStyles[i]!);
                    } else {
                        el.removeAttribute('style');
                    }
                });

                const link = document.createElement('a');
                link.download = `cartao-qr-${selectedGuardian.nome_completo.toLowerCase().replace(/\s+/g, '-')}.png`;
                link.href = dataUrl;
                document.body.appendChild(link);
                link.click();
                document.body.removeChild(link);
                toast.success('Sucesso', 'Download iniciado!');
            } catch (err) {
                console.error('Error in handleDownload:', err);
                document.getElementById('qr-capture-override')?.remove();
                toast.error('Erro ao gerar imagem', 'Tente novamente ou use a op├º├úo imprimir.');
            } finally {
                setGenerating(false);
            }
        }
    };


    const handlePhotoUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file || !selectedGuardian) return;

        setUploadingPhoto(true);
        try {
            const fileExt = file.name.split('.').pop();
            const fileName = `${selectedGuardian.id}-${Math.random()}.${fileExt}`;
            const filePath = `avatars/${fileName}`;

            const { error: uploadError } = await supabase.storage
                .from('responsaveis')
                .upload(filePath, file);

            if (uploadError) throw uploadError;

            const { data: { publicUrl } } = supabase.storage
                .from('responsaveis')
                .getPublicUrl(filePath);

            const { error: updateError } = await supabase
                .from('responsaveis')
                .update({ foto_url: publicUrl })
                .eq('id', selectedGuardian.id);

            if (updateError) throw updateError;

            setSelectedGuardian({ ...selectedGuardian, foto_url: publicUrl });
            toast.success('Foto atualizada', 'A foto do respons├ível foi atualizada com sucesso.');
        } catch (err) {
            console.error('Error uploading photo:', err);
            toast.error('Erro ao enviar foto', 'Tente novamente com uma imagem menor.');
        } finally {
            setUploadingPhoto(false);
        }
    };

    const handleUpdateValidity = async () => {
        if (!selectedGuardian || !newValidityDate) return;

        setUpdatingValidity(true);
        try {
            const { error } = await supabase
                .from('parent_qr_cards')
                .update({ expires_at: new Date(newValidityDate).toISOString() })
                .eq('responsavel_id', selectedGuardian.id)
                .eq('active', true);

            if (error) throw error;

            setSelectedGuardian({ ...selectedGuardian, expires_at: new Date(newValidityDate).toISOString() });
            setEditingValidity(false);
            toast.success('Validade atualizada', 'A data de validade do cart├úo foi atualizada.');
        } catch (err) {
            console.error('Error updating validity:', err);
            toast.error('Erro ao atualizar validade', 'Tente novamente.');
        } finally {
            setUpdatingValidity(false);
        }
    };

    const handlePrint = () => {
        window.print();
    };

    return (
        <div className="min-h-screen bg-slate-50 p-6 md:p-12 font-sans">
            <style>
                {`
                @media print {
                    @page {
                        margin: 0;
                        size: portrait;
                    }
                    body {
                        visibility: hidden;
                        background: white !important;
                        -webkit-print-color-adjust: exact !important;
                        print-color-adjust: exact !important;
                    }
                    #qr-card-printable, #qr-card-printable * {
                        visibility: visible;
                        -webkit-print-color-adjust: exact !important;
                        print-color-adjust: exact !important;
                    }
                    #qr-card-printable {
                        position: absolute;
                        left: 10mm;
                        top: 10mm;
                        width: 85mm !important;
                        max-width: 85mm !important;
                        height: auto !important;
                        box-shadow: none !important;
                        border: none !important;
                        border-radius: 6mm !important;
                        overflow: hidden !important;
                        margin: 0 !important;
                        padding: 0 !important;
                        background: #ffffff !important;
                    }
                    /* Header: dark bg with rounded top corners */
                    #qr-card-printable .print-header {
                        border-radius: 6mm 6mm 0 0 !important;
                        background-color: #0f172a !important;
                        border: none !important;
                        overflow: hidden !important;
                    }
                    /* Footer: light bg with rounded bottom corners */
                    #qr-card-printable .print-footer {
                        border-radius: 0 0 6mm 6mm !important;
                        background-color: #f1f5f9 !important;
                        border: none !important;
                        margin-left: 0 !important;
                        margin-right: 0 !important;
                        margin-bottom: 0 !important;
                        padding: 3mm 5mm !important;
                    }
                    /* Force all borders transparent in print */
                    #qr-card-printable *,
                    #qr-card-printable *::before,
                    #qr-card-printable *::after {
                        border-color: transparent !important;
                        box-shadow: none !important;
                    }
                    #qr-card-printable .p-10 { padding: 5mm !important; }
                    #qr-card-printable .px-10 { padding-left: 5mm !important; padding-right: 5mm !important; }
                    #qr-card-printable .py-8 { padding-top: 4mm !important; padding-bottom: 4mm !important; }
                    #qr-card-printable .text-2xl { font-size: 1.25rem !important; }
                    #qr-card-printable .text-3xl { font-size: 1.5rem !important; }
                    #qr-card-printable .w-16 { width: 12mm !important; height: 12mm !important; }
                    #qr-card-printable .h-16 { height: 12mm !important; }
                    #qr-card-printable .w-12 { width: 8mm !important; height: 8mm !important; }
                    #qr-card-printable .h-12 { height: 8mm !important; }

                    /* Fix for info boxes (CPF, Code, Validity) */
                    #qr-card-printable .grid-cols-3 {
                        display: grid !important;
                        grid-template-columns: repeat(3, 1fr) !important;
                        gap: 2mm !important;
                    }
                    #qr-card-printable .grid-cols-3 > div {
                        padding: 2mm 1.5mm !important;
                        border-radius: 4mm !important;
                    }
                    #qr-card-printable .grid-cols-3 p:first-child {
                        font-size: 8px !important;
                        margin-bottom: 1mm !important;
                    }
                    #qr-card-printable .grid-cols-3 p:last-child,
                    #qr-card-printable .grid-cols-3 .text-sm,
                    #qr-card-printable .grid-cols-3 .text-base {
                        font-size: 10px !important;
                        letter-spacing: normal !important;
                    }
                    
                    .no-print { display: none !important; }
                }
                `}
            </style>

            <div className="max-w-4xl mx-auto">
                <div className="no-print mb-8">
                    <NavigationControls />
                    <h1 className="text-3xl font-black text-slate-900 tracking-tighter italic uppercase">Gerador de Cart├úo QR</h1>
                    <p className="text-slate-500 font-medium">Emita cart├Áes de identifica├º├úo para pais e respons├íveis</p>
                </div>

                <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
                    {/* Left: Search & Selection */}
                    <div className="lg:col-span-5 no-print space-y-6">
                        <section className="bg-white rounded-3xl p-6 shadow-sm border border-slate-100">
                            <h2 className="text-sm font-black text-slate-900 uppercase tracking-widest mb-4">Buscar Respons├ível</h2>
                            <form onSubmit={handleSearch} className="relative">
                                <Search className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-400" />
                                <input
                                    type="text"
                                    placeholder="Nome ou CPF..."
                                    className="w-full pl-12 pr-4 py-4 bg-slate-50 border-2 border-transparent focus:border-emerald-500 focus:bg-white rounded-2xl transition-all outline-none font-medium"
                                    value={searchTerm}
                                    onChange={(e) => setSearchTerm(e.target.value)}
                                />
                                <button
                                    type="submit"
                                    disabled={loading}
                                    className="absolute right-2 top-1/2 -translate-y-1/2 p-2 bg-emerald-500 text-white rounded-xl hover:bg-emerald-600 transition-colors"
                                >
                                    {loading ? <Loader2 className="w-5 h-5 animate-spin" /> : <ArrowLeft className="w-5 h-5 rotate-180" />}
                                </button>
                            </form>
                        </section>

                        <section className="space-y-3">
                            {guardians.length > 0 ? (
                                guardians.map((g) => (
                                    <button
                                        key={g.id}
                                        onClick={() => selectGuardian(g)}
                                        className={`w-full text-left p-4 rounded-2xl border-2 transition-all flex items-center justify-between group ${selectedGuardian?.id === g.id ? 'border-emerald-500 bg-emerald-50' : 'border-transparent bg-white hover:border-slate-200'}`}
                                    >
                                        <div>
                                            <p className="font-bold text-slate-900 uppercase italic tracking-tight">{g.nome_completo}</p>
                                            <p className="text-xs text-slate-500 font-medium">{g.cpf}</p>
                                        </div>
                                        <QrCode className={`w-5 h-5 ${selectedGuardian?.id === g.id ? 'text-emerald-500' : 'text-slate-300 group-hover:text-slate-400'}`} />
                                    </button>
                                ))
                            ) : searchTerm && !loading && (
                                <div className="text-center py-8 text-slate-400">
                                    <p className="text-sm font-medium italic">Nenhum respons├ível encontrado.</p>
                                </div>
                            )}
                        </section>
                    </div>

                    {/* Right: Preview */}
                    <div className="lg:col-span-7">
                        {selectedGuardian ? (
                            <div className="space-y-6">
                                {/* The Card - Cleaned for Capture */}
                                <div id="qr-card-printable" className="bg-white rounded-[3rem] overflow-hidden relative" style={{ backgroundColor: '#ffffff' }}>
                                    {/* Capture Loader Overlay */}
                                    {generating && (
                                        <div className="absolute inset-0 z-50 bg-white/60 backdrop-blur-[2px] flex flex-col items-center justify-center gap-4 animate-in fade-in duration-300 capture-ignore">
                                            <Loader2 className="w-10 h-10 text-emerald-500 animate-spin" />
                                            <p className="text-[10px] font-black text-slate-900 uppercase tracking-[0.2em] italic">Capturando Cart├úo...</p>
                                        </div>
                                    )}
                                    <div className="bg-slate-900 px-10 py-8 flex items-center justify-between relative overflow-hidden print-header" style={{ backgroundColor: '#0f172a', border: 'none' }}>
                                        <div className="absolute top-0 right-0 w-32 h-32 bg-emerald-500/10 rounded-full blur-3xl -mr-16 -mt-16" style={{ backgroundColor: 'rgba(16, 185, 129, 0.1)' }}></div>
                                        <div className="relative z-10">
                                            <h2 className="text-xs font-black text-emerald-500 uppercase tracking-[0.2em] mb-1" style={{ color: '#10B981', outline: 'none', border: 'none' }}>Institui├º├úo de Ensino</h2>
                                            <p className="text-2xl font-black text-white italic tracking-tighter uppercase leading-none" style={{ outline: 'none', border: 'none' }}>Col├®gio La Salle Sobradinho</p>
                                        </div>
                                        <div className="w-12 h-12 rounded-xl flex items-center justify-center" style={{ backgroundColor: 'rgba(255, 255, 255, 0.1)', border: '1px solid rgba(255,255,255,0.2)' }}>
                                            <QrCode className="w-6 h-6 text-white" />
                                        </div>
                                    </div>

                                    <div className="p-10 space-y-8 text-center">
                                        <div className="flex justify-center items-center gap-6 py-2">
                                            <div ref={qrRef} />
                                        </div>

                                        <div className="space-y-6">
                                            <div className="flex items-center gap-6">
                                                <div
                                                    className="w-16 h-16 bg-slate-100 rounded-2xl flex items-center justify-center shrink-0 relative overflow-hidden cursor-pointer group/avatar"
                                                    style={{ backgroundColor: '#f1f5f9' }}
                                                    onClick={() => fileInputRef.current?.click()}
                                                >
                                                    {selectedGuardian.foto_url ? (
                                                        <img
                                                            src={selectedGuardian.foto_url}
                                                            alt={selectedGuardian.nome_completo}
                                                            className="w-full h-full object-cover"
                                                            crossOrigin="anonymous"
                                                        />
                                                    ) : (
                                                        <UserIcon className="w-8 h-8 text-slate-400" style={{ color: '#94a3b8' }} />
                                                    )}
                                                    <div className="absolute inset-0 bg-black/40 flex items-center justify-center opacity-0 group-hover/avatar:opacity-100 transition-opacity" style={{ backgroundColor: 'rgba(0,0,0,0.4)' }}>
                                                        <Camera className="w-6 h-6 text-white" style={{ color: '#ffffff' }} />
                                                    </div>
                                                    {uploadingPhoto && (
                                                        <div className="absolute inset-0 bg-white/80 flex items-center justify-center" style={{ backgroundColor: 'rgba(255,255,255,0.8)' }}>
                                                            <Loader2 className="w-6 h-6 text-emerald-500 animate-spin" style={{ color: '#10B981' }} />
                                                        </div>
                                                    )}
                                                </div>
                                                <input
                                                    type="file"
                                                    ref={fileInputRef}
                                                    onChange={handlePhotoUpload}
                                                    className="hidden"
                                                    accept="image/*"
                                                />
                                                <div className="text-left">
                                                    <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1 leading-none" style={{ color: '#94a3b8' }}>Nome do Respons├ível</p>
                                                    <p className="text-xl md:text-2xl font-black text-slate-900 uppercase italic tracking-tighter break-words leading-tight" style={{ color: '#0f172a' }}>{selectedGuardian.nome_completo}</p>
                                                </div>
                                            </div>

                                            <div className="grid grid-cols-3 gap-4">
                                                <div className="p-4 bg-slate-50 rounded-2xl" style={{ backgroundColor: '#f8fafc' }}>
                                                    <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1 leading-none" style={{ color: '#94a3b8' }}>CPF</p>
                                                    <p className="text-[11px] font-black text-slate-700" style={{ color: '#334155' }}>{selectedGuardian.cpf}</p>
                                                </div>
                                                <div className="p-4 bg-indigo-50 border border-indigo-100 rounded-2xl" style={{ backgroundColor: '#f5f3ff' }}>
                                                    <p className="text-[10px] font-black text-indigo-600/60 uppercase tracking-widest mb-1 leading-none" style={{ color: '#4f46e5' }}>C├│d. Acesso</p>
                                                    <p className="text-base font-black text-indigo-700 tracking-widest" style={{ color: '#4338ca' }}>{selectedGuardian.codigo_acesso || '---'}</p>
                                                </div>
                                                <div className="p-4 bg-slate-50 rounded-2xl relative group/validity" style={{ backgroundColor: '#f8fafc' }}>
                                                    <p className="text-[10px] font-black text-emerald-600/50 uppercase tracking-widest mb-1 leading-none" style={{ color: 'rgba(5, 150, 105, 0.5)' }}>Validade</p>
                                                    <div className="flex items-center justify-between gap-2">
                                                        <div className="flex items-center gap-2 text-left">
                                                            <Calendar className="w-3 h-3 text-emerald-500" style={{ color: '#10B981' }} />
                                                            {editingValidity ? (
                                                                <input
                                                                    type="date"
                                                                    className="text-xs font-black text-emerald-600 bg-transparent outline-none border-b border-emerald-500/30"
                                                                    value={newValidityDate || (selectedGuardian.expires_at ? new Date(selectedGuardian.expires_at).toISOString().split('T')[0] : '')}
                                                                    onChange={(e) => setNewValidityDate(e.target.value)}
                                                                />
                                                            ) : (
                                                                <p className="text-sm font-black text-emerald-600">
                                                                    {selectedGuardian.expires_at ? new Date(selectedGuardian.expires_at).toLocaleDateString('pt-BR') : '--/--/----'}
                                                                </p>
                                                            )}
                                                        </div>
                                                        <div className="no-print">
                                                            {editingValidity ? (
                                                                <div className="flex gap-1">
                                                                    <button
                                                                        onClick={handleUpdateValidity}
                                                                        disabled={updatingValidity}
                                                                        className="p-1 hover:bg-emerald-100 rounded-md text-emerald-600"
                                                                    >
