import { useState, useEffect, useRef } from 'react';
import {
    Settings, Building2, Shield, Bell, Globe,
    Save, AlertTriangle,
    Calendar, Upload, ChevronRight, Loader2, Trash2
} from 'lucide-react';
import { supabase } from '../../lib/supabase';
import { useAuth } from '../../context/AuthContext';
import NavigationControls from '../../components/NavigationControls';
import { useToast } from '../../components/ui/Toast';
import { fileToDataUrl } from '../../lib/imageUtils';

export default function SystemSettings() {
    const { user } = useAuth();
    const toast = useToast();
    const fileInputRef = useRef<HTMLInputElement>(null);
    const [activeTab, setActiveTab] = useState('general');
    const [loading, setLoading] = useState(true);
    const [saving, setSaving] = useState(false);

    const [settings, setSettings] = useState({
        nome: 'Col├®gio La Salle',
        website: 'https://lasalle.org.br',
        endereco: 'Rua Jose Bonifacio, 212 - Canoas, RS',
        logo_url: 'https://images.unsplash.com/photo-1599305090598-fe179d501227?auto=format&fit=crop&q=80&w=200',
        security: {
            twoFactor: true,
            autoLogout: true,
            ipWhitelist: false,
            idEncryption: true,
        },
        notifications: {
            emailAlerts: true,
            pushNotifications: true,
            smsEmergencies: false,
        },
        academic: {
            allowLatePickup: true,
            strictSchedule: false,
        },
        infrastructure: {
            dynamicIp: true,
            maintenanceMode: false,
        }
    });

    const escola_id = 'e6328325-1845-420a-b333-87a747953259';

    useEffect(() => {
        fetchSettings();
    }, []);

    const fetchSettings = async () => {
        try {
            setLoading(true);
            const { data, error } = await supabase
                .from('escolas')
                .select('*')
                .eq('id', escola_id)
                .single();

            if (error) {
                if (error.code === 'PGRST116') {
                    console.log('Nenhum registro de escola encontrado no banco.');
                    return;
                }
                throw error;
            }

            if (data) {
                setSettings({
                    nome: data.nome ?? '',
                    website: data.website ?? '',
                    endereco: data.endereco ?? '',
                    logo_url: data.logo_url ?? '',
                    security: { ...settings.security, ...(data.config_seguranca || {}) },
                    notifications: { ...settings.notifications, ...(data.config_notificacoes || {}) },
                    academic: { ...settings.academic, ...(data.config_academica || {}) },
                    infrastructure: { ...settings.infrastructure, ...(data.config_infraestrutura || {}) },
                });
            }
        } catch (err: any) {
            console.error('Error fetching settings:', err);
            toast.error('Erro ao carregar configura├º├Áes', err.message);
        } finally {
            setLoading(false);
        }
    };

    const handleSave = async () => {
        try {
            setSaving(true);

            let payload: any = {
                nome: settings.nome,
                website: settings.website,
                endereco: settings.endereco,
                logo_url: settings.logo_url,
                config_seguranca: settings.security,
                config_notificacoes: settings.notifications,
                config_academica: settings.academic,
                config_infraestrutura: settings.infrastructure,
            };

            let success = false;
            let missingColumns: string[] = [];

            while (!success && Object.keys(payload).length > 0) {
                const { error, count } = await supabase
                    .from('escolas')
                    .update(payload, { count: 'exact' })
                    .eq('id', escola_id);

                if (error) {
                    const message = error.message;
                    const match = message.match(/Could not find the '([^']+)' column/i);

                    if (match && match[1]) {
                        const failingColumn = match[1];
                        delete payload[failingColumn];
                        missingColumns.push(failingColumn);
                        continue;
                    }
                    throw error;
                }

                if (count === 0) {
                    throw new Error('Permiss├úo negada ou registro n├úo encontrado no banco de dados.');
                }

                success = true;
            }

            if (success) {
                if (missingColumns.length > 0) {
                    toast.warning(
                        'Salvamento Parcial',
                        `Dados b├ísicos salvos, mas as colunas (${missingColumns.join(', ')}) n├úo existem no banco.`
                    );
                } else {
                    toast.success('Configura├º├Áes Salvas', 'As altera├º├Áes foram aplicadas com sucesso.');
                }
            }
        } catch (err: any) {
            console.error('Error saving settings:', err);
            toast.error('Erro ao salvar', err.message);
        } finally {
            setSaving(false);
        }
    };

    const handleLogoChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (file) {
            try {
                const dataUrl = await fileToDataUrl(file);
                setSettings({ ...settings, logo_url: dataUrl });
                toast.success('Imagem preparada', 'Clique em Salvar para aplicar permanentemente.');
            } catch (err: any) {
                toast.error('Erro no upload', err.message);
            }
        }
    };

    const handleRemoveLogo = () => {
        setSettings({ ...settings, logo_url: '' });
        toast.info('Logo removida', 'Clique em Salvar para confirmar a remo├º├úo.');
    };

    const handleReset = async () => {
        if (!confirm('ATEN├ç├âO: Isso resetar├í todas as configura├º├Áes para o padr├úo de f├íbrica. Continuar?')) return;

        try {
            setSaving(true);
            // In a real app, this would call a reset RPC or clear fields
            toast.info('Reset de F├íbrica', 'A funcionalidade de reset completo requer permiss├úo de Super Admin.');
        } finally {
            setSaving(false);
        }
    };

    const tabs = [
        { id: 'general', label: 'Geral', icon: Building2 },
        { id: 'security', label: 'Seguran├ºa', icon: Shield },
