import { useState } from 'react';
import { supabase } from '../../lib/supabase';
import { useNavigate } from 'react-router-dom';
import { School, Loader2, Eye, EyeOff } from 'lucide-react';

export default function ClassroomLogin() {
    const navigate = useNavigate();
    const [email, setEmail] = useState('');
    const [password, setPassword] = useState('');
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState<string | null>(null);
    const [showPassword, setShowPassword] = useState(false);

    const handleLogin = async (e: React.FormEvent) => {
        e.preventDefault();
        setLoading(true);
        setError(null);

        try {
            const { data, error } = await supabase.auth.signInWithPassword({
                email,
                password,
            });

            if (error) throw error;

            if (data.user) {
                // Verify role
                const { data: userData, error: userError } = await supabase
                    .from('usuarios')
                    .select('tipo_usuario, turma_atribuida')
                    .eq('id', data.user.id)
                    .single();

                if (userError) throw userError;

                if (userData.tipo_usuario !== 'SCT' && userData.tipo_usuario !== 'ADMIN') {
                    await supabase.auth.signOut();
                    throw new Error('Acesso restrito para SCTs.');
                }

                navigate('/sala/dashboard');
            }
        } catch (err: any) {
            setError(err.message || 'Erro ao acessar sala');
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="min-h-screen bg-[#0f172a] flex items-center justify-center p-6 sm:p-12 overflow-hidden relative font-sans">
            {/* Background Decorative Elements */}
            <div className="absolute top-[-10%] left-[-10%] w-[40%] h-[40%] bg-emerald-500/10 rounded-full blur-[120px] animate-pulse"></div>
            <div className="absolute bottom-[-10%] right-[-10%] w-[40%] h-[40%] bg-blue-500/10 rounded-full blur-[120px] animate-pulse delay-700"></div>

            <div className="w-full max-w-5xl grid grid-cols-1 lg:grid-cols-2 bg-slate-900/50 backdrop-blur-3xl rounded-[3rem] border border-white/10 shadow-2xl overflow-hidden relative z-10">
                {/* Left Side: Brand/Visual */}
                <div className="hidden lg:flex flex-col justify-between p-16 bg-gradient-to-br from-emerald-600 to-emerald-900 relative">
                    <div className="absolute inset-0 opacity-20 pointer-events-none">
                        <svg className="w-full h-full" viewBox="0 0 100 100" preserveAspectRatio="none">
                            <path d="M0 100 C 20 0 50 0 100 100 Z" fill="white" />
                        </svg>
                    </div>

                    <div className="relative z-10">
                        <div className="w-16 h-16 bg-white/20 backdrop-blur-md rounded-2xl flex items-center justify-center mb-8 border border-white/30">
                            <School className="w-8 h-8 text-white" />
                        </div>
                        <h2 className="text-6xl font-black text-white italic tracking-tighter leading-none mb-6">
                            SALA DE <br /> AULA
                        </h2>
                        <div className="w-20 h-2 bg-white/30 rounded-full"></div>
                    </div>

                    <div className="relative z-10">
                        <p className="text-emerald-100 font-bold text-lg leading-tight opacity-80 italic">
                            "Conectando SCTs e alunos <br /> para uma retirada segura."
                        </p>
                    </div>
                </div>

                {/* Right Side: Form */}
                <div className="p-10 sm:p-16 flex flex-col justify-center">
                    <div className="mb-10 text-center lg:text-left">
                        <h1 className="text-4xl font-black text-white italic tracking-tighter mb-2 uppercase">Acesso Tablet</h1>
                        <p className="text-slate-400 font-bold uppercase tracking-widest text-xs">Identifique sua sala para iniciar</p>
                    </div>

                    <form onSubmit={handleLogin} className="space-y-6">
                        <div className="space-y-3">
                            <label className="text-[10px] font-black text-emerald-500 uppercase tracking-[0.2em] ml-2">E-mail da Sala</label>
                            <input
                                type="email"
                                required
                                value={email}
                                onChange={(e) => setEmail(e.target.value)}
                                className="w-full px-8 py-5 rounded-3xl bg-slate-800/50 border-2 border-white/5 text-white placeholder-slate-600 focus:border-emerald-500 focus:ring-0 outline-none transition-all text-xl font-medium shadow-inner"
                                placeholder="sala@escola.com"
                            />
                        </div>

                        <div className="space-y-3">
                            <label className="text-[10px] font-black text-emerald-500 uppercase tracking-[0.2em] ml-2">Senha Digital</label>
                            <div className="relative">
                                <input
                                    type={showPassword ? 'text' : 'password'}
                                    required
                                    value={password}
                                    onChange={(e) => setPassword(e.target.value)}
                                    className="w-full px-8 py-5 rounded-3xl bg-slate-800/50 border-2 border-white/5 text-white placeholder-slate-600 focus:border-emerald-500 focus:ring-0 outline-none transition-all text-xl font-medium pr-16 shadow-inner tracking-widest"
                                    placeholder="ÔÇóÔÇóÔÇóÔÇó"
                                />
                                <button
                                    type="button"
                                    onClick={() => setShowPassword(!showPassword)}
                                    className="absolute right-6 top-1/2 -translate-y-1/2 text-slate-500 hover:text-emerald-500 transition-colors"
                                >
                                    {showPassword ? <EyeOff className="w-7 h-7" /> : <Eye className="w-7 h-7" />}
                                </button>
                            </div>
                        </div>

                        {error && (
                            <div className="p-5 bg-red-500/10 text-red-400 font-bold text-sm rounded-3xl border border-red-500/20 flex items-center gap-3 animate-shake">
                                <div className="w-2 h-2 bg-red-500 rounded-full"></div>
                                {error}
                            </div>
                        )}

                        <button
                            type="submit"
                            disabled={loading}
                            className="w-full bg-emerald-500 hover:bg-emerald-400 text-slate-950 font-black py-6 rounded-3xl transition-all transform hover:scale-[1.02] active:scale-95 disabled:opacity-50 disabled:cursor-not-allowed flex items-center justify-center gap-4 text-xl uppercase tracking-widest shadow-2xl shadow-emerald-500/20 group"
                        >
                            {loading ? (
                                <Loader2 className="w-8 h-8 animate-spin" />
                            ) : (
                                <>
                                    Conectar Terminal
                                    <School className="w-6 h-6 group-hover:rotate-12 transition-transform" />
                                </>
                            )}
                        </button>
                    </form>

                    <div className="mt-12 text-center">
                        <p className="text-slate-500 font-bold text-[10px] uppercase tracking-widest">
                            Sistema de Retirada Inteligente ÔÇó La Salle, Cheguei!
                        </p>
                    </div>
                </div>
            </div>
        </div>
    );
}

import { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { supabase } from '../../lib/supabase';
import { User, ArrowRight, ShieldCheck, Loader2 } from 'lucide-react';

export default function ParentLogin() {
    const navigate = useNavigate();
    const [cpf, setCpf] = useState('');
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState('');
    const [step, setStep] = useState<'CPF' | 'SELECT_STUDENT'>('CPF');
    const [students, setStudents] = useState<any[]>([]);
    const [guardianName, setGuardianName] = useState('');

    const handleSearch = async (e: React.FormEvent) => {
        e.preventDefault();
        setLoading(true);
        setError('');

        try {
            // Normalize CPF (remove non-digits)
            const cleanCpf = cpf.replace(/\D/g, '');

            // 1. Find Responsavel by CPF
            const { data: responsavel, error: respError } = await supabase
                .from('responsaveis')
                .select('id, nome_completo')
                .eq('cpf', cleanCpf) // Ensure your DB stores CPF clean or handle formatting
                .single();

            if (respError || !responsavel) {
                throw new Error('Respons├ível n├úo encontrado. Verifique o CPF.');
            }

            setGuardianName(responsavel.nome_completo);

            // 2. Find Students connected to this Responsavel
            const { data: links, error: linkError } = await supabase
                .from('alunos_responsaveis')
                .select(`
                    aluno:alunos (
                        id,
                        nome_completo,
                        turma,
                        foto_url
                    )
                `)
                .eq('responsavel_id', responsavel.id);

            if (linkError) throw linkError;

            if (!links || links.length === 0) {
                throw new Error('Nenhum aluno vinculado a este respons├ível.');
            }

            setStudents(links.map((l: any) => l.aluno));
            setStep('SELECT_STUDENT');

            // Store guardian info locally for "session"
            localStorage.setItem('sisra_parent_session', JSON.stringify({
                id: responsavel.id,
                nome: responsavel.nome_completo,
                cpf: cleanCpf
            }));

        } catch (err: any) {
            setError(err.message || 'Erro ao buscar cadastro.');
        } finally {
            setLoading(false);
        }
    };

    const handleSelectStudent = (studentId: string) => {
        navigate(`/parent/status/${studentId}`);
    };

    return (
        <div className="min-h-screen bg-slate-50 flex items-center justify-center p-4 font-sans">
            <div className="w-full max-w-md bg-white rounded-3xl shadow-xl overflow-hidden">
                <div className="bg-blue-600 p-8 text-center">
                    <div className="mx-auto bg-white/20 w-16 h-16 rounded-2xl flex items-center justify-center mb-4 backdrop-blur-sm">
                        <User className="w-8 h-8 text-white" />
                    </div>
                    <h1 className="text-2xl font-bold text-white mb-1">Acesso dos Pais</h1>
                    <p className="text-blue-100 text-sm">Identifique-se para buscar seu filho</p>
                </div>

                <div className="p-8">
                    {step === 'CPF' ? (
                        <form onSubmit={handleSearch} className="space-y-6">
                            <div>
                                <label className="block text-sm font-bold text-slate-700 mb-2">
                                    Informe seu CPF
                                </label>
                                <input
                                    type="text"
                                    value={cpf}
                                    onChange={(e) => setCpf(e.target.value)}
                                    placeholder="000.000.000-00"
                                    className="w-full px-4 py-4 bg-slate-50 border border-slate-200 rounded-xl text-lg font-bold text-slate-900 focus:outline-none focus:ring-2 focus:ring-blue-500 transition-all placeholder:font-normal"
                                    required
                                />
                                <p className="text-xs text-slate-400 mt-2 flex items-center gap-1">
                                    <ShieldCheck className="w-3 h-3" />
                                    Ambiente seguro. Seus dados est├úo protegidos.
                                </p>
                            </div>

                            {error && (
                                <div className="p-4 bg-red-50 text-red-600 rounded-xl text-sm font-medium">
                                    {error}
                                </div>
                            )}

                            <button
                                type="submit"
                                disabled={loading}
                                className="w-full py-4 bg-blue-600 hover:bg-blue-700 text-white rounded-xl font-bold uppercase tracking-wider transition-all shadow-lg shadow-blue-600/20 disabled:opacity-50 flex items-center justify-center gap-2"
                            >
                                {loading ? <Loader2 className="w-5 h-5 animate-spin" /> : <>Continuar <ArrowRight className="w-5 h-5" /></>}
                            </button>
                        </form>
                    ) : (
                        <div className="space-y-6">
                            <div className="text-center">
                                <p className="text-slate-500 text-sm">Ol├í, <strong className="text-slate-900">{guardianName}</strong></p>
                                <h3 className="text-xl font-bold text-slate-800">Quem voc├¬ vai buscar?</h3>
                            </div>

                            <div className="space-y-3">
                                {students.map((student) => (
                                    <button
                                        key={student.id}
                                        onClick={() => handleSelectStudent(student.id)}
                                        className="w-full flex items-center gap-4 p-4 bg-white border border-slate-200 rounded-2xl hover:border-blue-500 hover:shadow-md transition-all group text-left"
                                    >
                                        <div className="w-12 h-12 bg-slate-100 rounded-full overflow-hidden">
                                            {student.foto_url ? (
                                                <img src={student.foto_url} alt="" className="w-full h-full object-cover" />
                                            ) : (
                                                <User className="w-6 h-6 m-3 text-slate-300" />
                                            )}
                                        </div>
                                        <div className="flex-1">
                                            <p className="font-bold text-slate-900 group-hover:text-blue-600 transition-colors">{student.nome_completo}</p>
                                            <p className="text-xs text-slate-500">Turma {student.turma}</p>
                                        </div>
                                        <ArrowRight className="w-5 h-5 text-slate-300 group-hover:text-blue-500" />
                                    </button>
                                ))}
                            </div>

                            <button
                                onClick={() => setStep('CPF')}
                                className="w-full py-3 text-slate-400 font-bold text-sm hover:text-slate-600"
                            >
                                Voltar / N├úo sou eu
                            </button>
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
}

import { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { supabase } from '../../lib/supabase';
import {
    CheckCircle,
    Clock,
    ArrowRight,
    Phone,
    ShieldCheck,
    Bell,
    School,
    User,
    Info,
    Loader2
} from 'lucide-react';
import GeoTracker from '../../components/parent/GeoTracker';
import { useToast } from '../../components/ui/Toast';

type StudentData = {
    id: string;
    nome_completo: string;
    foto_url: string | null;
    turma: string;
    escola_id: string;
};

type PickupData = {
    id: string;
    status: string;
    horario_solicitacao: string;
    mensagem_sala?: string;
    mensagem_recepcao?: string;
};

export default function ParentPickupStatus() {
    const { id: studentId } = useParams();
    const navigate = useNavigate();
    const toast = useToast();

    const [student, setStudent] = useState<StudentData | null>(null);
    const [pickup, setPickup] = useState<PickupData | null>(null);
    const [loading, setLoading] = useState(true);
    const [guardianName, setGuardianName] = useState('Respons├ível');

    useEffect(() => {
        const session = localStorage.getItem('sisra_parent_session');
        if (!session) {
            navigate('/parent/login');
            return;
        }

        const data = JSON.parse(session);
        const firstName = data.nome.split(' ')[0];
        setGuardianName(`${firstName} (Respons├ível)`);

        if (studentId) {
            loadInitialData();

            // 1. Realtime Subscription
            const channel = supabase
                .channel(`pickup_status_${studentId}`)
                .on(
                    'postgres_changes',
                    {
                        event: '*',
                        schema: 'public',
                        table: 'solicitacoes_retirada',
                        filter: `aluno_id=eq.${studentId}`
                    },
                    () => {
                        fetchPickupStatus();
                    }
                )
                .subscribe();

            // 2. 1-second Polling (User Request)
            const interval = setInterval(() => {
                fetchPickupStatus();
            }, 1000);

            return () => {
                supabase.removeChannel(channel);
                clearInterval(interval);
            };
        }
    }, [studentId]);

    const loadInitialData = async () => {
        setLoading(true);
        try {
            // 1. Fetch Student
            const { data: studentData, error: studentError } = await supabase
                .from('alunos')
                .select('id, nome_completo, foto_url, turma, escola_id')
                .eq('id', studentId)
                .single();

            if (studentError) throw studentError;
            setStudent(studentData);

            // 2. Fetch Pickup
            await fetchPickupStatus();

        } catch (err) {
            console.error("Error loading data:", err);
        } finally {
            setLoading(false);
        }
    };

    const fetchPickupStatus = async () => {
        try {
            const today = new Date();
            today.setHours(0, 0, 0, 0);

            const { data, error } = await supabase
                .from('solicitacoes_retirada')
                .select(`
                    id,
                    status,
                    mensagem_sala,
                    mensagem_recepcao,
                    horario_solicitacao,
                    aluno:alunos (
                        nome_completo,
                        foto_url,
                        turma
                    )
                `)
                .eq('aluno_id', studentId)
                .is('horario_confirmacao', null)
                .neq('status', 'CANCELADO')
                .gte('horario_solicitacao', today.toISOString())
                .order('horario_solicitacao', { ascending: false })
                .limit(1)
                .maybeSingle();

            if (error) console.error("Error fetching pickup", error);
            if (data) {
                // Force type cast as Supabase inference might be generic
                setPickup(data as unknown as PickupData);
            } else {
                setPickup(null);
            }
        } catch (err) {
            console.error(err);
        }
    };

    const handleRequestPickup = async () => {
        if (!student) return;

        try {
            setLoading(true);

            // Get parent session info
            const parentSessionStr = localStorage.getItem('sisra_parent_session');
            const parentSession = parentSessionStr ? JSON.parse(parentSessionStr) : null;

            const { error } = await supabase
                .from('solicitacoes_retirada')
                .insert({
                    aluno_id: student.id,
                    status: 'SOLICITADO',
                    escola_id: student.escola_id,
                    responsavel_id: parentSession?.id,
                    tipo_solicitacao: 'ROTINA' // Must be 'ROTINA' or 'EMERGENCIA'
                });

            if (error) {
                toast.error('Erro ao solicitar', error.message);
                setLoading(false);
            } else {
                await fetchPickupStatus();
                setLoading(false);
            }
        } catch (err) {
            toast.error('Erro ao solicitar', 'Tente novamente.');
            setLoading(false);
        }
    };

    if (loading) {
        return (
            <div className="min-h-screen bg-slate-50 flex items-center justify-center">
                <Loader2 className="w-8 h-8 animate-spin text-blue-600" />
            </div>
        );
