            case 'AGUARDANDO': return 1;
            case 'LIBERADO': return 2;
            case 'CONFIRMADO': return 3;
            case 'FINALIZADO': return 4;
            default: return 1;
        }
    };

    const currentStep = getStatusStep(pickup.status);

    return (
