import { useEffect, useState } from 'react';
import { supabase } from '../../lib/supabase';
import { QrCode, Download, RefreshCw, Printer, ShieldCheck, User as UserIcon, Calendar, Smartphone, Info, Loader2, Camera } from 'lucide-react';
import QRCodeStyling from 'qr-code-styling';
import domtoimage from 'dom-to-image-more';
import { useRef } from 'react';
import { useToast } from '../../components/ui/Toast';

type GuardianData = {
    id: string;
    nome_completo: string;
    cpf: string;
    telefone: string;
    foto_url?: string;
    qr_code: string;
    expires_at: string;
    codigo_acesso?: string;
};

export default function ParentQRCard() {
    const [guardian, setGuardian] = useState<GuardianData | null>(null);
    const [loading, setLoading] = useState(true);
    const toast = useToast();
    const qrRef = useRef<HTMLDivElement>(null);
    const qrCode = useRef<QRCodeStyling | null>(null);
    const fileInputRef = useRef<HTMLInputElement>(null);
    const [uploadingPhoto, setUploadingPhoto] = useState(false);

    useEffect(() => {
        fetchGuardianData();
    }, []);

    useEffect(() => {
        if (guardian && qrRef.current) {
            generateQRCode();
        }
    }, [guardian]);

    const fetchGuardianData = async () => {
        try {
            // In a real app, this would get the logged-in guardian's ID
            // For demo, we'll get the first guardian
            const { data: guardianData } = await supabase
                .from('responsaveis')
                .select('*')
                .limit(1)
                .single();

            if (!guardianData) return;

            // Check if QR card exists
            let { data: qrCard } = await supabase
                .from('parent_qr_cards')
                .select('*')
                .eq('responsavel_id', guardianData.id)
                .eq('active', true)
                .single();

            // Create or Reactivate
            if (!qrCard) {
                // Check if any card exists (even inactive) to reuse QR code
                const { data: anyCard } = await supabase
                    .from('parent_qr_cards')
                    .select('*')
                    .eq('responsavel_id', guardianData.id)
                    .order('created_at', { ascending: false })
                    .limit(1)
                    .maybeSingle();

                const newQRCode = anyCard?.qr_code || `LaSalleCheguei-${guardianData.id}-${Date.now()}`;
                const expiresAt = new Date();
                expiresAt.setMonth(expiresAt.getMonth() + 6); // Valid for 6 months

                const { data: newCard } = await supabase
                    .from('parent_qr_cards')
                    .insert({
                        responsavel_id: guardianData.id,
                        qr_code: newQRCode,
                        expires_at: expiresAt.toISOString(),
                        active: true
                    })
                    .select()
                    .single();

                qrCard = newCard;
            }

            setGuardian({
                ...guardianData,
                qr_code: qrCard?.qr_code || '',
                expires_at: qrCard?.expires_at || '',
                codigo_acesso: guardianData.codigo_acesso
            });
        } catch (err) {
            console.error('Error fetching guardian data:', err);
        } finally {
            setLoading(false);
        }
    };

    const generateQRCode = () => {
        if (!guardian) return;

        qrCode.current = new QRCodeStyling({
            width: 300,
            height: 300,
            data: guardian.qr_code,
            type: 'canvas',
            dotsOptions: {
                color: '#047857',
                type: 'rounded'
            },
            backgroundOptions: {
                color: '#ffffff'
            },
            imageOptions: {
                crossOrigin: 'anonymous',
                margin: 10
            }
        });

        if (qrRef.current) {
            qrRef.current.innerHTML = '';
            qrCode.current.append(qrRef.current);
        }
    };

    const handleRefresh = async () => {
        setLoading(true);
        await fetchGuardianData();
    };

    const handleDownload = async () => {
        const cardElement = document.getElementById('qr-card-printable');
        if (cardElement && guardian) {
            try {
                // Ensure the QR code is present
                if (qrRef.current && qrRef.current.innerHTML === '' && qrCode.current) {
                    qrCode.current.append(qrRef.current);
                }

                await new Promise(resolve => setTimeout(resolve, 500));

                // --- STEP 1: INJECT OVERRIDE STYLESHEET ---
                const captureStyle = document.createElement('style');
                captureStyle.id = 'qr-capture-override';
                captureStyle.textContent = `
                    #qr-card-printable,
                    #qr-card-printable *,
                    #qr-card-printable *::before,
                    #qr-card-printable *::after {
                        border-color: transparent !important;
                        border-image: none !important;
                        outline: none !important;
                        box-shadow: none !important;
                        text-shadow: none !important;
                        text-decoration: none !important;
                    }
                    #qr-card-printable canvas {
                        border: none !important;
                        outline: none !important;
                    }
                    #qr-card-printable .capture-ignore,
                    #qr-card-printable .no-print {
                        display: none !important;
                    }
                `;
                document.head.appendChild(captureStyle);

                // --- STEP 2: ALSO PATCH INLINE STYLES (belt-and-suspenders) ---
                const allElements = [cardElement, ...Array.from(cardElement.querySelectorAll('*'))] as HTMLElement[];
                const savedStyles = allElements.map(el => el.getAttribute('style'));

                allElements.forEach(el => {
                    el.style.borderColor = 'transparent';
                    el.style.outline = 'none';
                    el.style.boxShadow = 'none';
                    if (el.tagName === 'CANVAS') {
                        el.style.border = 'none';
                    }
                });

                // Let browser recalculate
                await new Promise(resolve => setTimeout(resolve, 200));

                const dataUrl = await domtoimage.toPng(cardElement, {
                    bgcolor: '#ffffff',
                    width: cardElement.offsetWidth,
                    height: cardElement.offsetHeight,
                    cacheBust: true,
                });

                // --- STEP 3: RESTORE EVERYTHING ---
                captureStyle.remove();
                allElements.forEach((el, i) => {
                    if (savedStyles[i] !== null) {
                        el.setAttribute('style', savedStyles[i]!);
                    } else {
                        el.removeAttribute('style');
                    }
                });

                const link = document.createElement('a');
                link.download = `meu-cartao-qr-${guardian.nome_completo.toLowerCase().replace(/\s+/g, '-')}.png`;
                link.href = dataUrl;
                document.body.appendChild(link);
                link.click();
                document.body.removeChild(link);
                toast.success('Sucesso', 'Download iniciado!');
            } catch (err) {
                console.error('Error in handleDownload:', err);
                document.getElementById('qr-capture-override')?.remove();
                toast.warning('Erro ao gerar imagem', 'Dica: Use o bot├úo "Imprimir Cart├úo" e escolha "Salvar como PDF".');
            }
        }
    };

    const handlePhotoUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file || !guardian) return;

        setUploadingPhoto(true);
        try {
            const fileExt = file.name.split('.').pop();
            const fileName = `${guardian.id}-${Math.random()}.${fileExt}`;
            const filePath = `avatars/${fileName}`;

            const { error: uploadError } = await supabase.storage
                .from('responsaveis')
                .upload(filePath, file);

            if (uploadError) throw uploadError;

            const { data: { publicUrl } } = supabase.storage
                .from('responsaveis')
                .getPublicUrl(filePath);

            const { error: updateError } = await supabase
                .from('responsaveis')
                .update({ foto_url: publicUrl })
                .eq('id', guardian.id);

            if (updateError) throw updateError;

            setGuardian({ ...guardian, foto_url: publicUrl });
            toast.success('Foto atualizada', 'Sua foto de identifica├º├úo foi atualizada com sucesso.');
        } catch (err) {
            console.error('Error uploading photo:', err);
            toast.error('Erro ao enviar foto', 'Tente novamente.');
        } finally {
            setUploadingPhoto(false);
        }
    };

    const handlePrint = () => {
        window.print();
    };

    if (loading) {
        return (
            <div className="min-h-screen bg-slate-50 flex items-center justify-center">
                <div className="flex flex-col items-center gap-4">
                    <div className="w-12 h-12 border-4 border-emerald-500 border-t-transparent rounded-full animate-spin"></div>
                    <p className="text-slate-500 font-black uppercase tracking-widest text-xs italic">Sincronizando Cart├úo...</p>
                </div>
            </div>
        );
    }

    return (
        <div className="min-h-screen bg-[#f8fafc] p-6 sm:p-12 font-sans overflow-x-hidden">
            <style>
                {`
                @media print {
                    @page {
                        margin: 0;
                        size: portrait;
                    }
                    body {
                        visibility: hidden;
                        background: white !important;
                        -webkit-print-color-adjust: exact !important;
                        print-color-adjust: exact !important;
                    }
                    #qr-card-printable, #qr-card-printable * {
                        visibility: visible;
                        -webkit-print-color-adjust: exact !important;
                        print-color-adjust: exact !important;
                    }
                    #qr-card-printable {
                        position: absolute;
                        left: 10mm;
                        top: 10mm;
                        width: 85mm !important;
                        max-width: 85mm !important;
                        height: auto !important;
                        box-shadow: none !important;
                        border: none !important;
                        border-radius: 6mm !important;
                        overflow: hidden !important;
                        margin: 0 !important;
                        padding: 0 !important;
                        background: #ffffff !important;
                    }
                    /* Header: dark bg with rounded top corners */
                    #qr-card-printable .print-header {
                        border-radius: 6mm 6mm 0 0 !important;
                        background-color: #0f172a !important;
                        border: none !important;
                        overflow: hidden !important;
                    }
                    /* Footer: light bg with rounded bottom corners */
                    #qr-card-printable .print-footer {
                        border-radius: 0 0 6mm 6mm !important;
                        background-color: #f1f5f9 !important;
                        border: none !important;
                        margin-left: 0 !important;
                        margin-right: 0 !important;
                        margin-bottom: 0 !important;
                        padding: 3mm 5mm !important;
                    }
                    /* Force all borders transparent in print */
                    #qr-card-printable *,
                    #qr-card-printable *::before,
                    #qr-card-printable *::after {
                        border-color: transparent !important;
                        box-shadow: none !important;
                    }
                    #qr-card-printable .p-10 { padding: 5mm !important; }
                    #qr-card-printable .px-10 { padding-left: 5mm !important; padding-right: 5mm !important; }
                    #qr-card-printable .py-8 { padding-top: 4mm !important; padding-bottom: 4mm !important; }
                    #qr-card-printable .text-2xl { font-size: 1.25rem !important; }
                    #qr-card-printable .text-3xl { font-size: 1.5rem !important; }
                    #qr-card-printable .w-12 { width: 8mm !important; height: 8mm !important; }
                    #qr-card-printable .h-12 { height: 8mm !important; }

                    /* Fix for info boxes (CPF, Code, Validity) in Parent View */
                    #qr-card-printable .grid-cols-2.lg\:grid-cols-3 {
                        display: grid !important;
                        grid-template-columns: repeat(3, 1fr) !important;
                        gap: 2mm !important;
                    }
                    #qr-card-printable .grid-cols-2.lg\:grid-cols-3 > div {
                        padding: 2mm 1.5mm !important;
                        border-radius: 4mm !important;
                    }
                    #qr-card-printable .grid-cols-2.lg\:grid-cols-3 p:first-child {
                        font-size: 8px !important;
                        margin-bottom: 1mm !important;
                    }
                    #qr-card-printable .grid-cols-2.lg\:grid-cols-3 p:last-child,
                    #qr-card-printable .grid-cols-2.lg\:grid-cols-3 .text-sm,
                    #qr-card-printable .grid-cols-2.lg\:grid-cols-3 .text-base {
                        font-size: 10px !important;
                        letter-spacing: normal !important;
                    }
                    
                    .no-print { display: none !important; }
                }
                `}
            </style>

            <div className="max-w-xl mx-auto space-y-8">
                {/* Header Section */}
                <div className="flex items-center justify-between mb-2 no-print">
                    <div>
                        <h1 className="text-3xl font-black text-slate-900 tracking-tighter italic uppercase">Meu Cart├úo</h1>
                        <p className="text-sm font-bold text-emerald-600 uppercase tracking-widest">Acesso Identificado</p>
                    </div>
                    <div className="bg-emerald-500/10 border border-emerald-500/20 px-4 py-2 rounded-2xl flex items-center gap-2">
                        <ShieldCheck className="w-5 h-5 text-emerald-600" />
                        <span className="text-[10px] font-black text-emerald-700 uppercase tracking-widest">Seguran├ºa Ativa</span>
                    </div>
                </div>

                {/* Main Card */}
                <div id="qr-card-printable" className="bg-white rounded-[3rem] shadow-2xl shadow-slate-200/50 overflow-hidden ring-1 ring-slate-900/5 transition-all hover:shadow-emerald-500/10 duration-500 group" style={{ backgroundColor: '#ffffff' }}>
                    {/* Top Branding Bar */}
                    <div className="bg-slate-900 px-10 py-8 flex items-center justify-between relative overflow-hidden print-header" style={{ backgroundColor: '#0f172a', border: 'none' }}>
                        <div className="absolute top-0 right-0 w-32 h-32 bg-emerald-500/10 rounded-full blur-3xl -mr-16 -mt-16" style={{ backgroundColor: 'rgba(16, 185, 129, 0.1)' }}></div>
                        <div className="relative z-10">
                            <h2 className="text-xs font-black text-emerald-500 uppercase tracking-[0.2em] mb-1" style={{ color: '#10B981', outline: 'none', border: 'none' }}>Institui├º├úo de Ensino</h2>
                            <p className="text-2xl font-black text-white italic tracking-tighter uppercase leading-none" style={{ outline: 'none', border: 'none' }}>Col├®gio La Salle Sobradinho</p>
                        </div>
                        <div className="w-12 h-12 rounded-xl flex items-center justify-center" style={{ backgroundColor: 'rgba(255, 255, 255, 0.1)', border: '1px solid rgba(255,255,255,0.2)' }}>
                            <QrCode className="w-6 h-6 text-white" />
                        </div>
                    </div>

                    <div className="p-10 space-y-10">
                        {/* QR Code Mirror */}
                        <div className="relative flex justify-center py-6">
                            <div className="absolute inset-0 bg-emerald-500/5 rounded-full blur-3xl scale-75 animate-pulse capture-ignore"></div>
                            <div className="relative p-6 bg-white rounded-3xl group-hover:scale-105 transition-transform duration-500" style={{ backgroundColor: '#ffffff' }}>
                                <div ref={qrRef} className="rounded-2xl" />
                            </div>
                        </div>

                        {/* Identification Details */}
                        <div className="space-y-6">
                            <div className="flex items-center gap-6">
                                <div
                                    className="w-16 h-16 bg-slate-100 rounded-2xl flex items-center justify-center shrink-0 relative overflow-hidden cursor-pointer group/avatar"
                                    style={{ backgroundColor: '#f1f5f9' }}
                                    onClick={() => fileInputRef.current?.click()}
                                >
                                    {guardian?.foto_url ? (
                                        <img
                                            src={guardian.foto_url}
                                            alt={guardian.nome_completo}
                                            className="w-full h-full object-cover"
                                            crossOrigin="anonymous"
                                        />
                                    ) : (
                                        <UserIcon className="w-8 h-8 text-slate-400" style={{ color: '#94a3b8' }} />
                                    )}
                                    <div className="absolute inset-0 bg-black/40 flex items-center justify-center opacity-0 group-hover/avatar:opacity-100 transition-opacity capture-ignore" style={{ backgroundColor: 'rgba(0,0,0,0.4)' }}>
                                        <Camera className="w-6 h-6 text-white" style={{ color: '#ffffff' }} />
                                    </div>
                                    {uploadingPhoto && (
                                        <div className="absolute inset-0 bg-white/80 flex items-center justify-center capture-ignore" style={{ backgroundColor: 'rgba(255,255,255,0.8)' }}>
                                            <Loader2 className="w-6 h-6 text-emerald-500 animate-spin" style={{ color: '#10B981' }} />
                                        </div>
                                    )}
                                </div>
                                <input
                                    type="file"
                                    ref={fileInputRef}
                                    onChange={handlePhotoUpload}
                                    className="hidden"
                                    accept="image/*"
                                />
                                <div>
                                    <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1 leading-none" style={{ color: '#94a3b8' }}>Nome do Respons├ível</p>
                                    <p className="text-xl md:text-2xl font-black text-slate-900 uppercase italic tracking-tighter break-words leading-tight" style={{ color: '#0f172a' }}>{guardian?.nome_completo}</p>
                                </div>
                            </div>

                            <div className="grid grid-cols-2 lg:grid-cols-3 gap-4">
                                <div className="p-4 bg-slate-50 rounded-2xl" style={{ backgroundColor: '#f8fafc' }}>
                                    <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1 leading-none" style={{ color: '#94a3b8' }}>CPF</p>
                                    <p className="text-sm font-black text-slate-700" style={{ color: '#334155' }}>{guardian?.cpf}</p>
                                </div>
                                <div className="p-4 bg-indigo-50 border border-indigo-100 rounded-2xl" style={{ backgroundColor: '#f5f3ff' }}>
                                    <p className="text-[10px] font-black text-indigo-600/60 uppercase tracking-widest mb-1 leading-none" style={{ color: '#4f46e5' }}>C├│d. Acesso</p>
                                    <p className="text-base font-black text-indigo-700 tracking-widest" style={{ color: '#4338ca' }}>{guardian?.codigo_acesso || '---'}</p>
                                </div>
                                <div className="p-4 bg-slate-50 rounded-2xl" style={{ backgroundColor: '#f8fafc' }}>
                                    <p className="text-[10px] font-black text-emerald-600/50 uppercase tracking-widest mb-1 leading-none" style={{ color: 'rgba(5, 150, 105, 0.5)' }}>Validade</p>
                                    <div className="flex items-center gap-2">
                                        <Calendar className="w-3 h-3 text-emerald-500" style={{ color: '#10B981' }} />
                                        <p className="text-sm font-black text-emerald-600">
                                            {guardian?.expires_at ? new Date(guardian.expires_at).toLocaleDateString('pt-BR') : '--/--/----'}
                                        </p>
                                    </div>
                                </div>
                            </div>
                        </div>

                        {/* Security Disclaimer */}
                        <div className="p-5 bg-amber-500/5 border border-amber-500/10 rounded-2xl flex items-start gap-4 no-print">
                            <Info className="w-5 h-5 text-amber-500 shrink-0 mt-0.5" />
                            <p className="text-[10px] font-bold text-amber-800 leading-relaxed uppercase tracking-widest italic">
                                Este cart├úo ├® pessoal e intransfer├¡vel. O uso inadequado pode resultar em suspens├úo de acesso.
                            </p>
                        </div>

                        {/* Action Buttons */}
                        <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 no-print select-none">
                            <button
                                onClick={handleDownload}
                                className="flex items-center justify-center gap-3 px-6 py-5 bg-slate-100 hover:bg-slate-200 rounded-2xl font-black text-[10px] uppercase tracking-widest text-slate-700 transition-all border border-slate-200"
                            >
                                <Download className="w-5 h-5" /> Salvar no Celular
                            </button>
                            <button
                                onClick={handlePrint}
                                className="flex items-center justify-center gap-3 px-6 py-5 bg-emerald-500 hover:bg-emerald-400 rounded-2xl font-black text-[10px] uppercase tracking-widest text-slate-900 transition-all shadow-xl shadow-emerald-500/20"
                            >
                                <Printer className="w-5 h-5" /> Imprimir Cart├úo
                            </button>
                        </div>
                    </div>

                    {/* Bottom Status Bar */}
                    <div className="bg-slate-100 px-10 py-6 text-center print-footer" style={{ backgroundColor: '#f1f5f9' }}>
                        <p className="text-[9px] font-black text-slate-400 uppercase tracking-[0.3em] flex items-center justify-center gap-2">
                            <Smartphone className="w-3 h-3" /> Sistema de Identifica├º├úo Biom├®trica Integrado
                        </p>
                    </div>
                </div>

                {/* Secondary Actions */}
                <div className="text-center pt-4 no-print">
                    <button
                        onClick={handleRefresh}
                        className="text-[10px] font-black text-slate-400 hover:text-emerald-500 uppercase tracking-widest flex items-center justify-center gap-2 mx-auto transition-colors"
                    >
                        <RefreshCw className="w-4 h-4" /> Atualizar sincroniza├º├úo de dados
                    </button>
                </div>
            </div>
        </div>
    );
}

import { useRef, useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { User, Camera, Shield, CheckCircle2, AlertCircle, Loader2, ArrowRight, Image as ImageIcon } from 'lucide-react';
import { supabase } from '../../lib/supabase';
import CameraCapture from '../../components/admin/CameraCapture';
import { fileToDataUrl } from '../../lib/imageUtils';
import { useToast } from '../../components/ui/Toast';
import QRCodeStyling from 'qr-code-styling';
import domtoimage from 'dom-to-image-more';
import { Download, Printer, Plus } from 'lucide-react';

export default function SelfRegistration() {
    const { token } = useParams<{ token: string }>();
    const navigate = useNavigate();
    const toast = useToast();
    const fileInputRef = useRef<HTMLInputElement>(null);

    const [loading, setLoading] = useState(true);
    const [validating, setValidating] = useState(true);
    const [student, setStudent] = useState<any>(null);
    const [error, setError] = useState<string | null>(null);
    const [success, setSuccess] = useState(false);
    const [lastRegisteredGuardian, setLastRegisteredGuardian] = useState<any>(null);
    const qrRef = useRef<HTMLDivElement>(null);
    const qrCode = useRef<QRCodeStyling | null>(null);

    const [formData, setFormData] = useState({
        nome: '',
        cpf: '',
        telefone: '',
        parentesco: 'Pai/M├úe',
        parentescoOutro: '',
    });
    const [photo, setPhoto] = useState<string | null>(null);
    const [photoLoading, setPhotoLoading] = useState(false);
    const [showCamera, setShowCamera] = useState(false);

    useEffect(() => {
        validateToken();
    }, [token]);

    useEffect(() => {
        if (success && lastRegisteredGuardian && qrRef.current) {
            generateQRCode();
        }
    }, [success, lastRegisteredGuardian]);

    const generateQRCode = () => {
        if (!lastRegisteredGuardian?.qr_code) return;

        qrCode.current = new QRCodeStyling({
            width: 300,
            height: 300,
            data: lastRegisteredGuardian.qr_code,
            type: 'canvas',
            dotsOptions: { color: '#047857', type: 'rounded' },
            backgroundOptions: { color: '#ffffff' },
            imageOptions: { crossOrigin: 'anonymous', margin: 10 }
        });

        if (qrRef.current) {
            qrRef.current.innerHTML = '';
            qrCode.current.append(qrRef.current);
        }
    };

    const validateToken = async () => {
        if (!token) {
            setError('Token de acesso n├úo fornecido.');
            setValidating(false);
            return;
        }

        try {
            const { data, error: tokenError } = await supabase
                .from('tokens_acesso')
                .select('*, alunos(*)')
                .eq('token', token)
                .single();

            if (tokenError || !data) {
                setError('Link de acesso inv├ílido ou expirado.');
            } else {
                setStudent(data.alunos);
            }
        } catch (err) {
            setError('Erro ao validar acesso.');
        } finally {
            setValidating(false);
            setLoading(false);
        }
    };

    const handleCameraCapture = (image: string) => {
        console.log('[SelfReg] Camera capture received, length:', image?.length, 'prefix:', image?.substring(0, 30));
        setPhoto(image);
        setShowCamera(false);
    };

    const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (file) {
            setPhotoLoading(true);
            try {
                console.log('[SelfReg] File selected:', file.name, 'type:', file.type, 'size:', file.size);
                const dataUrl = await fileToDataUrl(file);
                setPhoto(dataUrl);
            } catch (err: any) {
                console.error('[SelfReg] Erro ao processar imagem:', err);
                const msg = err?.message?.includes?.('HEIC_NOT_SUPPORTED')
                    ? 'Formato HEIC n├úo suportado neste navegador.\n\nPor favor:\nÔÇó Envie a foto em formato JPEG ou PNG\nÔÇó Ou no iPhone: Ajustes ÔåÆ C├ómera ÔåÆ Formatos ÔåÆ Mais Compat├¡vel'
                    : 'Erro ao processar a imagem. Tente outro arquivo (JPEG ou PNG).';
                toast.error('Erro na imagem', msg);
            } finally {
                setPhotoLoading(false);
            }
        }
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!photo) {
            toast.warning('Foto necess├íria', 'Por favor, tire uma foto para sua identifica├º├úo de seguran├ºa.');
            return;
        }

        setLoading(true);
        try {
            // 1. Check if guardian already exists by CPF
            const { data: existingGuardian } = await supabase
                .from('responsaveis')
                .select('*')
                .eq('cpf', formData.cpf)
                .limit(1)
                .maybeSingle();

            let guardian;

            if (existingGuardian) {
                // Update existing guardian info
                const { data: updatedGuardian, error: uError } = await supabase
                    .from('responsaveis')
                    .update({
                        nome_completo: formData.nome,
                        telefone: formData.telefone,
                        foto_url: photo,
                    })
                    .eq('id', existingGuardian.id)
                    .select()
                    .maybeSingle();

                if (uError) throw uError;
                guardian = updatedGuardian;
            } else {
                // Create new guardian
                const { data: newGuardian, error: gError } = await supabase
                    .from('responsaveis')
                    .insert({
                        nome_completo: formData.nome,
                        cpf: formData.cpf,
                        telefone: formData.telefone,
                        foto_url: photo,
                    })
                    .select()
                    .maybeSingle();

                if (gError) throw gError;
                guardian = newGuardian;
            }

            // 2. Create Authorization
            const finalParentesco = formData.parentesco === 'Outro' ? formData.parentescoOutro : formData.parentesco;

            const { error: aError } = await supabase
                .from('autorizacoes')
                .insert({
                    aluno_id: student.id,
                    responsavel_id: guardian.id,
                    tipo_autorizacao: 'SECUNDARIO',
                    parentesco: finalParentesco || 'Outro',
                    ativa: true
                });

            if (aError) throw aError;

            // 3. Create/Get QR Card
            const qrValue = `LaSalleCheguei-${guardian.id}-${Date.now()}`;
            const expiresAt = new Date();
            expiresAt.setMonth(expiresAt.getMonth() + 12); // Valid for 1 year for self-reg

            const { error: qrError } = await supabase
                .from('parent_qr_cards')
                .insert({
                    responsavel_id: guardian.id,
                    qr_code: qrValue,
                    expires_at: expiresAt.toISOString(),
                    active: true
                });

            if (qrError) throw qrError;

            setLastRegisteredGuardian({
                ...guardian,
                qr_code: qrValue,
                expires_at: expiresAt.toISOString()
            });
            setSuccess(true);
            toast.success('Cadastro conclu├¡do', 'Respons├ível cadastrado e autorizado com sucesso.');
        } catch (err: any) {
            toast.error('Erro no cadastro', err.message);
        } finally {
            setLoading(false);
        }
    };

    const handleResetForm = () => {
        setFormData({
            nome: '',
            cpf: '',
            telefone: '',
            parentesco: 'Pai/M├úe',
            parentescoOutro: '',
        });
        setPhoto(null);
        setSuccess(false);
        setLastRegisteredGuardian(null);
    };

    const handleDownload = async () => {
        const cardElement = document.getElementById('qr-card-printable');
        if (cardElement && lastRegisteredGuardian) {
            setLoading(true);
            try {
                if (qrRef.current && qrRef.current.innerHTML === '' && qrCode.current) {
                    qrCode.current.append(qrRef.current);
                }

                // Allow time for QR component to be ready
                await new Promise(resolve => setTimeout(resolve, 500));

                const dataUrl = await domtoimage.toPng(cardElement, {
                    bgcolor: '#ffffff',
                    width: cardElement.offsetWidth,
                    height: cardElement.offsetHeight,
                    cacheBust: true,
                    style: {
                        borderRadius: '2.5rem'
                    }
                });

                const link = document.createElement('a');
                link.download = `cartao-qr-${lastRegisteredGuardian.nome_completo.toLowerCase().replace(/\s+/g, '-')}.png`;
                link.href = dataUrl;
                link.click();
                toast.success('Sucesso', 'Download iniciado!');
            } catch (err) {
                console.error('Error downloading QR:', err);
                toast.error('Erro ao baixar', 'Tente tirar um print da tela.');
            } finally {
                setLoading(false);
            }
        }
    };

    if (validating) {
        return (
            <div className="min-h-screen bg-slate-50 flex items-center justify-center p-6">
                <div className="text-center">
                    <Loader2 className="w-12 h-12 text-blue-500 animate-spin mx-auto mb-4" />
                    <p className="text-slate-500 font-bold uppercase tracking-widest text-xs">Validando seu acesso seguro...</p>
                </div>
            </div>
        );
    }

    if (error) {
        return (
            <div className="min-h-screen bg-slate-50 flex items-center justify-center p-6">
                <div className="bg-white p-8 rounded-[2rem] shadow-xl border border-slate-200 text-center max-w-md">
                    <div className="w-20 h-20 bg-red-50 text-red-500 rounded-3xl flex items-center justify-center mx-auto mb-6">
                        <AlertCircle className="w-10 h-10" />
                    </div>
                    <h2 className="text-2xl font-black text-slate-900 mb-2">Acesso Negado</h2>
                    <p className="text-slate-500 mb-8">{error}</p>
                    <button
                        onClick={() => navigate('/')}
                        className="w-full py-4 bg-slate-900 text-white rounded-2xl font-bold uppercase tracking-widest text-xs"
                    >
                        Voltar ao In├¡cio
                    </button>
                </div>
            </div>
        );
    }

    if (success) {
        return (
            <div className="min-h-screen bg-slate-50 p-6 font-display">
                <style>
                    {`
                    @media print {
                        body * { visibility: hidden; }
                        #qr-card-printable, #qr-card-printable * { visibility: visible; }
                        #qr-card-printable { 
                            position: fixed !important; 
                            left: 0 !important; 
                            top: 0 !important; 
                            width: 100% !important; 
                            border: 2px solid #f1f5f9 !important; 
                            box-shadow: none !important;
                            padding: 0 !important;
                            margin: 0 !important;
                            -webkit-print-color-adjust: exact;
                            print-color-adjust: exact;
                        }
                        .no-print { display: none !important; }
                    }
                    `}
                </style>
                <div className="max-w-xl mx-auto space-y-8 animate-in zoom-in duration-500">
                    <div className="text-center">
                        <div className="w-20 h-20 bg-emerald-50 text-emerald-500 rounded-3xl flex items-center justify-center mx-auto mb-6">
                            <CheckCircle2 className="w-10 h-10" />
                        </div>
                        <h2 className="text-3xl font-black text-slate-900 mb-2 italic tracking-tight">Cadastro Conclu├¡do!</h2>
                        <p className="text-slate-500 mb-8 font-medium">Voc├¬ cadastrou com sucesso <strong>{lastRegisteredGuardian?.nome_completo}</strong> para retirar <strong>{student?.nome_completo}</strong>.</p>
                    </div>

                    {/* QR Card Preview - Cleaned for Capture */}
                    <div id="qr-card-printable" style={{ backgroundColor: '#ffffff', border: 'none' }} className="bg-white rounded-[2.5rem] overflow-hidden">
                        <div style={{ backgroundColor: '#0f172a', border: 'none' }} className="bg-slate-900 p-8 text-center">
                            <p style={{ color: '#10b981', border: 'none', outline: 'none' }} className="text-[10px] font-black text-emerald-500 uppercase tracking-[0.3em] mb-1">Identifica├º├úo de Seguran├ºa</p>
                            <h3 style={{ color: '#ffffff', border: 'none', outline: 'none' }} className="text-xl font-black text-white italic tracking-tight uppercase leading-none">Col├®gio La Salle Sobradinho</h3>
                        </div>

                        <div className="p-8 space-y-6 text-center">
                            <div className="flex justify-center items-center gap-6 py-2">
                                {photo && (
                                    <div style={{ backgroundColor: '#ffffff', border: '1px solid #f1f5f9' }} className="w-24 h-24 rounded-2xl overflow-hidden flex-shrink-0">
                                        <img src={photo} alt="Foto" className="w-full h-full object-cover" />
                                    </div>
                                )}
                                <div ref={qrRef} style={{ backgroundColor: '#ffffff', border: '1px solid #f1f5f9' }} className="p-2 rounded-2xl flex-shrink-0 shadow-inner" />
                            </div>

                            <div className="space-y-4">
                                <div>
                                    <p style={{ color: '#94a3b8' }} className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1 text-center">Respons├ível</p>
                                    <p style={{ color: '#0f172a' }} className="text-xl md:text-2xl font-black text-slate-900 uppercase italic tracking-tighter text-center leading-tight break-words px-4">{lastRegisteredGuardian?.nome_completo}</p>
                                </div>
                                <div className="grid grid-cols-2 gap-4">
                                    <div style={{ backgroundColor: '#f8fafc', borderColor: '#f1f5f9' }} className="p-3 bg-slate-50 rounded-2xl border border-slate-100 text-left">
                                        <p style={{ color: '#94a3b8' }} className="text-[9px] font-black text-slate-400 uppercase tracking-widest mb-0.5">CPF</p>
                                        <p style={{ color: '#334155' }} className="text-xs font-black text-slate-700">{lastRegisteredGuardian?.cpf}</p>
                                    </div>
                                    <div style={{ backgroundColor: '#f8fafc', borderColor: '#f1f5f9' }} className="p-3 bg-slate-50 rounded-2xl border border-slate-100 text-left">
                                        <p style={{ color: '#94a3b8' }} className="text-[9px] font-black text-slate-400 uppercase tracking-widest mb-0.5">Aluno</p>
                                        <p style={{ color: '#334155' }} className="text-xs font-black text-slate-700 leading-tight">{student?.nome_completo}</p>
                                    </div>
                                </div>
                            </div>

                            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 no-print pt-4">
                                <button
                                    onClick={handleDownload}
                                    className="flex items-center justify-center gap-2 px-6 py-4 bg-slate-100 hover:bg-slate-200 rounded-2xl font-black text-[10px] uppercase tracking-widest text-slate-700 transition-all border border-slate-200 shadow-sm"
                                >
                                    <Download className="w-4 h-4 text-slate-500" /> Salvar PNG
                                </button>
                                <button
                                    onClick={() => window.print()}
                                    className="flex items-center justify-center gap-2 px-6 py-4 bg-emerald-500 hover:bg-emerald-400 rounded-2xl font-black text-[10px] uppercase tracking-widest text-white transition-all shadow-lg shadow-emerald-500/20"
                                >
                                    <Printer className="w-4 h-4" /> Imprimir
                                </button>
                            </div>
                        </div>

                        <div style={{ backgroundColor: '#f8fafc', borderTop: '1px solid #f1f5f9' }} className="px-8 py-4 text-center italic">
                            <p style={{ color: '#94a3b8' }} className="text-[9px] font-bold uppercase tracking-widest flex items-center justify-center gap-2">
                                <Shield className="w-3 h-3 text-slate-300" /> V├ílido por 1 ano para identifica├º├úo
                            </p>
                        </div>
                    </div>

                    <div className="flex flex-col gap-4 no-print pt-6">
                        <button
                            onClick={handleResetForm}
                            className="w-full py-5 bg-blue-600 text-white rounded-3xl font-black uppercase tracking-[0.2em] text-xs flex items-center justify-center gap-3 hover:bg-blue-700 transition-all shadow-xl shadow-blue-500/10 active:scale-95"
                        >
                            <Plus className="w-5 h-5" /> Adicionar Outra Pessoa
                        </button>
                        <button
                            onClick={() => navigate('/')}
                            className="w-full py-5 bg-white text-slate-400 rounded-3xl font-black uppercase tracking-[0.2em] text-[10px] hover:text-slate-600 transition-all"
                        >
                            Finalizar e Sair
                        </button>
                    </div>
                </div>
            </div>
        );
    }

    return (
        <div className="min-h-screen bg-slate-50 font-display p-4 md:p-8">
            <div className="max-w-2xl mx-auto">
                <div className="mb-10 text-center">
                    <div className="inline-flex items-center gap-2 px-3 py-1 bg-blue-50 text-blue-600 rounded-full text-[10px] font-black uppercase tracking-[0.2em] mb-4">
                        <Shield className="w-3 h-3" /> Acesso Seguro SISRA
                    </div>
                    <h1 className="text-3xl font-black text-slate-900 mb-2 tracking-tight italic">Portal do Respons├ível</h1>
                    <p className="text-slate-500 font-medium italic">Ol├í! Cadastre seus dados e foto para autoriza├º├úo de retirada do aluno <strong>{student?.nome_completo}</strong>.</p>
                </div>

                <div className="bg-white rounded-[2.5rem] shadow-xl shadow-slate-200/60 border border-slate-200/60 overflow-hidden">
                    <div className="p-8 md:p-12 border-b border-slate-50 flex flex-col items-center bg-slate-50/30">
                        <div className="relative mb-6 group">
                            <div className="w-48 h-48 bg-white rounded-[2rem] border-4 border-white shadow-xl overflow-hidden flex items-center justify-center relative">
                                {photoLoading ? (
                                    <div className="flex flex-col items-center gap-2">
                                        <Loader2 className="w-10 h-10 text-blue-500 animate-spin" />
                                        <span className="text-xs text-slate-400 font-medium">Processando...</span>
                                    </div>
                                ) : photo ? (
                                    <img
                                        key={photo.substring(0, 50)}
                                        src={photo}
                                        alt="Foto do Respons├ível"
                                        className="w-full h-full object-cover"
                                        style={{ display: 'block' }}
                                        onLoad={() => console.log('[SelfReg] Image loaded successfully')}
                                        onError={() => {
                                            console.error('[SelfReg] Image failed to load. src prefix:', photo?.substring(0, 50));
                                        }}
                                    />
                                ) : (
                                    <User className="w-20 h-20 text-slate-100" />
                                )}
                            </div>
                        </div>

                        <div className="flex flex-col gap-3 w-full max-w-xs">
                            <button
                                type="button"
                                onClick={() => setShowCamera(true)}
                                className="w-full py-4 bg-blue-600 text-white rounded-2xl flex items-center justify-center gap-3 shadow-lg hover:bg-blue-700 transition-all font-bold text-sm"
                            >
                                <Camera className="w-5 h-5" /> {window.innerWidth < 768 ? 'Tirar Selfie' : 'Capturar da Webcam'}
                            </button>

                            <button
                                type="button"
                                onClick={() => fileInputRef.current?.click()}
                                className="w-full py-4 bg-slate-100 text-slate-600 rounded-2xl flex items-center justify-center gap-3 transition-all font-bold text-sm hover:bg-slate-200"
                            >
                                <ImageIcon className="w-5 h-5" /> Escolher da Galeria
                            </button>

                            <input
                                type="file"
                                ref={fileInputRef}
                                className="hidden"
                                accept="image/jpeg,image/png,image/webp,image/heic,image/heif,.heic,.heif"
                                onChange={handleFileChange}
                            />
                        </div>

                        <div className="mt-6 text-center">
                            <h3 className="font-black text-slate-900 uppercase tracking-widest text-[10px]">Foto de Identifica├º├úo (Obrigat├│ria)</h3>
                            <p className="text-[10px] text-slate-400 mt-1 uppercase font-bold tracking-widest leading-relaxed">
                                Tirar uma foto n├¡tida do rosto ou enviar da galeria
                            </p>
                        </div>
                    </div>

                    <form onSubmit={handleSubmit} className="p-8 md:p-12 space-y-8">
                        <div className="grid grid-cols-1 gap-8">
                            <div>
                                <label className="block text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-3">Seu Nome Completo</label>
                                <input
                                    required
                                    type="text"
                                    placeholder="Ex: Maria Rodrigues Silva"
                                    className="w-full px-6 py-4 bg-slate-50 border border-slate-100 rounded-2xl focus:bg-white focus:border-blue-500 outline-none transition-all font-bold text-slate-800"
                                    value={formData.nome}
                                    onChange={e => setFormData({ ...formData, nome: e.target.value })}
                                />
                            </div>
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                                <div>
                                    <label className="block text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-3">CPF (Obrigat├│rio)</label>
                                    <input
                                        required
                                        type="text"
                                        placeholder="000.000.000-00"
                                        className="w-full px-6 py-4 bg-slate-50 border border-slate-100 rounded-2xl focus:bg-white focus:border-blue-500 outline-none transition-all font-bold text-slate-800"
                                        value={formData.cpf}
                                        onChange={e => setFormData({ ...formData, cpf: e.target.value })}
                                    />
                                </div>
                                <div>
                                    <label className="block text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-3">WhatsApp / Telefone</label>
                                    <input
                                        required
                                        type="tel"
                                        placeholder="(00) 00000-0000"
                                        className="w-full px-6 py-4 bg-slate-50 border border-slate-100 rounded-2xl focus:bg-white focus:border-blue-500 outline-none transition-all font-bold text-slate-800"
                                        value={formData.telefone}
                                        onChange={e => setFormData({ ...formData, telefone: e.target.value })}
                                    />
                                </div>
                            </div>
                            <div>
                                <label className="block text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-3">Parentesco</label>
                                <select
                                    className="w-full px-6 py-4 bg-slate-50 border border-slate-100 rounded-2xl focus:bg-white focus:border-blue-500 outline-none transition-all font-bold text-slate-800 appearance-none mb-4"
                                    value={formData.parentesco}
                                    onChange={e => setFormData({ ...formData, parentesco: e.target.value })}
                                >
                                    <option value="Pai/M├úe">Pai/M├úe</option>
                                    <option value="Av├┤/Av├│">Av├┤/Av├│</option>
                                    <option value="Tio/Tia">Tio/Tia</option>
                                    <option value="Irm├úo/Irm├ú">Irm├úo/Irm├ú</option>
                                    <option value="Outro">Outro Autorizado</option>
                                </select>

                                {formData.parentesco === 'Outro' && (
                                    <div className="animate-in slide-in-from-top-2 duration-300">
                                        <label className="block text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-3">Especifique o Parentesco</label>
                                        <input
                                            required
                                            type="text"
                                            placeholder="Ex: Padrinho, Motorista, Amigo da Fam├¡lia"
                                            className="w-full px-6 py-4 bg-slate-50 border border-slate-100 rounded-2xl focus:bg-white focus:border-blue-500 outline-none transition-all font-bold text-slate-800"
                                            value={formData.parentescoOutro}
                                            onChange={e => setFormData({ ...formData, parentescoOutro: e.target.value })}
                                        />
                                    </div>
                                )}
                            </div>
                        </div>

                        <button
                            type="submit"
                            disabled={loading}
                            className="w-full py-5 bg-blue-600 text-white rounded-3xl font-black uppercase tracking-[0.2em] text-xs flex items-center justify-center gap-3 hover:bg-blue-700 transition-all shadow-xl shadow-blue-500/20 active:scale-95 disabled:opacity-50"
                        >
                            {loading ? <Loader2 className="w-5 h-5 animate-spin" /> : <>Finalizar Cadastro <ArrowRight className="w-5 h-5" /></>}
                        </button>
                    </form>
                </div>
            </div>

            {/* Modals */}
            {showCamera && (
                <CameraCapture
                    onCapture={handleCameraCapture}
                    onCancel={() => setShowCamera(false)}
                />
            )}
        </div>
    );
}

import { useEffect, useState } from 'react';
import { supabase } from '../../lib/supabase';
import { useAuth } from '../../context/AuthContext';
import { Clock, User, Users, ChevronRight, Activity, Search, Bell } from 'lucide-react';
import NavigationControls from '../../components/NavigationControls';

type WaitingStudent = {
    id: string;
    aluno: { nome_completo: string; turma: string; matricula: string };
    responsavel: { nome_completo: string };
    status: string;
    created_at: string;
    wait_time_minutes: number;
    mensagem_sala?: string;
    mensagem_recepcao?: string;
};

export default function ActiveWaitingList() {
    const { user } = useAuth();
    const [waiting, setWaiting] = useState<WaitingStudent[]>([]);
    const [loading, setLoading] = useState(true);
    const [filter, setFilter] = useState('');

    useEffect(() => {
        if (!user) return;

        fetchWaitingList();

        const channel = supabase
            .channel(`waiting_list_updates_${user.id}`)
            .on('postgres_changes', {
                event: '*',
                schema: 'public',
                table: 'solicitacoes_retirada'
            }, (payload) => {
                console.log('Realtime update at Reception:', payload);
                fetchWaitingList();
            })
            .subscribe((status) => {
                console.log('Realtime status at Reception:', status);
            });

        const timer = setInterval(() => {
            setWaiting(prev => prev.map(item => ({
                ...item,
                wait_time_minutes: Math.round(
                    (new Date().getTime() - new Date(item.created_at).getTime()) / 60000
                )
            })));
        }, 30000);

        return () => {
            supabase.removeChannel(channel);
            clearInterval(timer);
        };
    }, [user?.id]);

    const fetchWaitingList = async () => {
        try {
            const { data, error } = await supabase
                .from('solicitacoes_retirada')
                .select(`
                    *,
                    aluno:alunos(nome_completo, turma, matricula),
                    responsavel:responsaveis(nome_completo)
                `)
                .in('status', ['SOLICITADO', 'NOTIFICADO', 'CONFIRMADO', 'AGUARDANDO', 'LIBERADO'])
                .order('created_at', { ascending: true });

            if (error) throw error;

            const withWaitTime = data?.map(item => ({
                ...item,
                wait_time_minutes: Math.round(
                    (new Date().getTime() - new Date(item.created_at).getTime()) / 60000
                )
            })) || [];

            setWaiting(withWaitTime);
        } catch (err) {
            console.error('Error:', err);
        } finally {
            setLoading(false);
        }
    };

    const getStatusStyles = (status: string) => {
        switch (status) {
            case 'SOLICITADO': return 'bg-blue-500/10 text-blue-500 border-blue-500/20';
            case 'NOTIFICADO': return 'bg-purple-500/10 text-purple-500 border-purple-500/20';
            case 'CONFIRMADO': return 'bg-emerald-500/10 text-emerald-500 border-emerald-500/20';
            case 'AGUARDANDO': return 'bg-amber-500/10 text-amber-500 border-amber-500/20';
            case 'LIBERADO': return 'bg-emerald-600 text-white border-emerald-500 shadow-lg shadow-emerald-500/20';
            default: return 'bg-slate-500/10 text-slate-500 border-slate-500/20';
        }
    };

    const filtered = waiting.filter(w =>
        w.aluno?.nome_completo.toLowerCase().includes(filter.toLowerCase()) ||
        w.responsavel?.nome_completo.toLowerCase().includes(filter.toLowerCase())
    );

    if (loading) {
        return (
            <div className="min-h-screen bg-[#0f172a] flex items-center justify-center">
                <div className="flex flex-col items-center gap-4">
                    <Activity className="w-12 h-12 text-emerald-500 animate-pulse" />
                    <p className="text-slate-400 font-medium animate-pulse">Sincronizando fila...</p>
                </div>
            </div>
        );
    }

    return (
        <div className="min-h-screen bg-[#0f172a] text-slate-200 font-sans selection:bg-emerald-500/30">
            {/* Ambient Background */}
            <div className="fixed inset-0 overflow-hidden pointer-events-none">
                <div className="absolute top-[-10%] left-[-10%] w-[40%] h-[40%] bg-emerald-500/10 blur-[120px] rounded-full" />
                <div className="absolute bottom-[-10%] right-[-10%] w-[40%] h-[40%] bg-blue-500/10 blur-[120px] rounded-full" />
            </div>

            <div className="relative max-w-6xl mx-auto p-6 lg:p-12">
                {/* Header Section */}
                <header className="flex flex-col md:flex-row md:items-end justify-between gap-6 mb-12">
                    <div>
                        <NavigationControls />
                        <div className="flex items-center gap-3 mb-2">
                            <div className="p-2 bg-emerald-500/20 border border-emerald-500/30 rounded-lg">
                                <Users className="w-6 h-6 text-emerald-500" />
                            </div>
                            <span className="text-emerald-500 font-bold tracking-wider text-sm">RECEP├ç├âO EM TEMPO REAL</span>
                        </div>
                        <h1 className="text-4xl md:text-5xl font-black text-white tracking-tight">
                            Fila de <span className="text-transparent bg-clip-text bg-gradient-to-r from-emerald-400 to-blue-400">Espera Ativa</span>
                        </h1>
                        <p className="text-slate-400 mt-2 text-lg">Monitoramento din├ómico de retiradas e tempo de resposta.</p>
                    </div>

                    <div className="flex items-center gap-4">
                        <div className="relative">
                            <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-500" />
                            <input
                                type="text"
                                placeholder="Filtrar fila..."
                                value={filter}
                                onChange={(e) => setFilter(e.target.value)}
                                className="pl-10 pr-4 py-2 bg-slate-900/50 border border-slate-800 rounded-xl focus:ring-2 focus:ring-emerald-500/50 outline-none w-64 transition-all"
                            />
                        </div>
                        <div className="bg-slate-900 border border-slate-800 px-6 py-3 rounded-2xl flex flex-col items-center justify-center min-w-[120px]">
                            <span className="text-3xl font-black text-emerald-500">{waiting.length}</span>
                            <span className="text-[10px] font-bold text-slate-500 uppercase tracking-widest">ALUNOS TOTAIS</span>
                        </div>
                    </div>
                </header>

                {/* Empty State */}
                {filtered.length === 0 ? (
                    <div className="bg-slate-900/40 border border-slate-800/50 backdrop-blur-xl rounded-3xl p-20 text-center">
                        <div className="w-20 h-20 bg-slate-800 rounded-full flex items-center justify-center mx-auto mb-6">
                            <Activity className="w-10 h-10 text-slate-600" />
                        </div>
                        <h3 className="text-2xl font-bold text-white mb-2">Sem atividade pendente</h3>
                        <p className="text-slate-500 max-w-md mx-auto">A fila est├í vazia no momento. Novos chamados aparecer├úo aqui automaticamente.</p>
                    </div>
                ) : (
                    <div className="grid grid-cols-1 gap-4">
                        {filtered.map((item, index) => (
                            <div
                                key={item.id}
                                className="group relative bg-slate-900/40 hover:bg-slate-800/60 border border-slate-800 hover:border-emerald-500/30 backdrop-blur-xl rounded-2xl p-6 transition-all duration-300 flex flex-col md:flex-row md:items-center justify-between gap-6 overflow-hidden"
                            >
                                {/* Rank/Position Indicator */}
                                <div className="absolute left-0 top-0 bottom-0 w-1 bg-gradient-to-b from-emerald-500/50 to-blue-500/50 opacity-0 group-hover:opacity-100 transition-opacity" />

                                <div className="flex items-center gap-6">
                                    <div className="relative hidden md:block">
                                        <div className="w-14 h-14 bg-slate-800 rounded-2xl flex items-center justify-center border border-slate-700 font-black text-xl text-slate-400 group-hover:border-emerald-500/50 group-hover:text-emerald-500 transition-all">
                                            {index + 1}
                                        </div>
                                        {item.wait_time_minutes > 10 && (
                                            <div className="absolute -top-1 -right-1 w-4 h-4 bg-rose-500 rounded-full border-4 border-[#0f172a] animate-ping" />
                                        )}
                                    </div>

                                    <div>
                                        <div className="flex items-center gap-3 mb-1">
                                            <h3 className="text-xl font-bold text-white group-hover:text-emerald-400 transition-colors">
                                                {item.aluno?.nome_completo}
                                            </h3>
                                            <span className={`px-2 py-0.5 rounded text-[10px] font-black tracking-widest border uppercase ${getStatusStyles(item.status)}`}>
                                                {item.status === 'LIBERADO' ? 'LIBERADO' :
                                                    item.status === 'SOLICITADO' ? 'SOLICITADO' :
                                                        item.status === 'NOTIFICADO' ? 'NOTIFICADO' :
                                                            item.status === 'CONFIRMADO' ? 'CONFIRMADO' :
                                                                item.status === 'AGUARDANDO' ? 'AGUARDANDO' : item.status}
                                            </span>
                                        </div>
                                        <p className="text-slate-400 text-sm flex items-center gap-2">
                                            <span className="font-bold text-slate-300">{item.aluno?.turma}</span>
                                            <span className="w-1 h-1 bg-slate-700 rounded-full" />
                                            <span>Mat: {item.aluno?.matricula}</span>
                                        </p>
                                        {item.mensagem_sala && (
                                            <div className="mt-2 text-xs bg-amber-500/10 border border-amber-500/20 text-amber-400 px-3 py-1.5 rounded-lg flex items-center gap-2">
                                                <Bell className="w-3 h-3" />
                                                <span className="font-bold">Nota da Sala: {item.mensagem_sala}</span>
                                            </div>
                                        )}
