                                        ) : selectedStudent && (
                                            <>
                                                {selectedGuardianId ? (
                                                    <div className="flex items-center gap-2 px-5 py-3 bg-emerald-500/10 border border-emerald-500/30 rounded-2xl">
                                                        <CheckCircle2 className="w-4 h-4 text-emerald-400 shrink-0" />
                                                        <p className="text-xs font-bold text-emerald-400">Respons├ível identificado: <span className="text-white">{guardians.find(g => g.id === selectedGuardianId)?.nome_completo}</span></p>
