            {isCodeModalOpen && <CodeModal onConfirm={handleCodeLookup} onClose={() => setIsCodeModalOpen(false)} />}
        </div>
    );
}

import { useState, useEffect } from 'react';
import { supabase } from '../../lib/supabase';
import { useAuth } from '../../context/AuthContext';
import { Shield, CheckCircle, Circle, AlertTriangle, Info, Send, Calendar as CalendarIcon, ClipboardCheck } from 'lucide-react';
import NavigationControls from '../../components/NavigationControls';

type ChecklistItem = {
    id: string;
    label: string;
    completed: boolean;
};

const DEFAULT_ITEMS: Omit<ChecklistItem, 'completed'>[] = [
    { id: 'fire_exits', label: 'Verificar sa├¡das de emerg├¬ncia desobstru├¡das' },
    { id: 'first_aid', label: 'Conferir kit de primeiros socorros completo' },
    { id: 'emergency_contacts', label: 'Atualizar lista de contatos de emerg├¬ncia' },
    { id: 'equipment_check', label: 'Testar equipamentos de seguran├ºa (alarmes, extintores)' },
    { id: 'cleanliness', label: 'Verificar limpeza e higieniza├º├úo de ├íreas comuns' },
    { id: 'visitor_log', label: 'Preparar registro de visitantes do dia' },
    { id: 'student_attendance', label: 'Revisar lista de presen├ºa dos alunos' }
];

export default function DailySafetyChecklist() {
    const { user } = useAuth();
    const [items, setItems] = useState<ChecklistItem[]>(
        DEFAULT_ITEMS.map(item => ({ ...item, completed: false }))
    );
    const [checklistId, setChecklistId] = useState<string | null>(null);
    const [loading, setLoading] = useState(false);
    const [submitting, setSubmitting] = useState(false);
    const [completed, setCompleted] = useState(false);

    useEffect(() => {
        loadTodayChecklist();
    }, [user]);

    const loadTodayChecklist = async () => {
        if (!user) return;
        setLoading(true);

        try {
            const { data: userData } = await supabase
                .from('usuarios')
                .select('escola_id')
                .eq('id', user.id)
                .single();

            const today = new Date().toISOString().split('T')[0];

            const { data: existing } = await supabase
                .from('safety_checklists')
                .select('*')
                .eq('escola_id', userData?.escola_id)
                .eq('user_id', user.id)
                .eq('checklist_date', today)
                .single();

            if (existing) {
                setChecklistId(existing.id);
                const savedItems = existing.items as ChecklistItem[];
                setItems(savedItems);
                setCompleted(!!existing.completed_at);
            }
        } catch (err) {
            console.error('Error loading checklist:', err);
        } finally {
            setLoading(false);
        }
    };

    const toggleItem = (id: string) => {
        if (completed) return;

        setItems(prev =>
            prev.map(item =>
                item.id === id ? { ...item, completed: !item.completed } : item
            )
        );
    };

    const handleSubmit = async () => {
        setSubmitting(true);

        try {
            const { data: userData } = await supabase
                .from('usuarios')
                .select('escola_id')
                .eq('id', user?.id)
                .single();

            const today = new Date().toISOString().split('T')[0];
            const allComplete = items.every(item => item.completed);

            const payload = {
                escola_id: userData?.escola_id,
                user_id: user?.id,
                checklist_date: today,
                items: items,
                completed_at: allComplete ? new Date().toISOString() : null
            };

            if (checklistId) {
                await supabase
                    .from('safety_checklists')
                    .update(payload)
                    .eq('id', checklistId);
            } else {
                const { data } = await supabase
                    .from('safety_checklists')
                    .insert(payload)
                    .select()
                    .single();

                setChecklistId(data?.id);
            }

            if (allComplete) {
                setCompleted(true);
            }
        } catch (err) {
            console.error('Error saving:', err);
        } finally {
            setSubmitting(false);
        }
    };

    const completedCount = items.filter(i => i.completed).length;
    const progress = (completedCount / items.length) * 100;

    if (loading) {
        return (
            <div className="min-h-screen bg-slate-50 flex items-center justify-center">
                <div className="flex flex-col items-center gap-4">
                    <Shield className="w-12 h-12 text-emerald-600 animate-pulse" />
                    <p className="text-slate-500 font-medium">Validando protocolos...</p>
                </div>
            </div>
        );
    }

    return (
        <div className="min-h-screen bg-slate-50 font-sans selection:bg-emerald-500/30 pb-12">
            {/* Header / Banner */}
            <div className="bg-[#0f172a] text-white pt-12 pb-24 px-6 relative overflow-hidden">
                <div className="absolute top-0 right-0 p-12 opacity-10 pointer-events-none">
                    <Shield className="w-48 h-48" />
                </div>
                <div className="max-w-4xl mx-auto relative cursor-default">
                    <NavigationControls />
                    <div className="flex flex-col md:flex-row md:items-end justify-between gap-6">
                        <div>
                            <div className="flex items-center gap-3 mb-4">
                                <div className="p-2 bg-emerald-500/20 border border-emerald-500/30 rounded-xl">
                                    <ClipboardCheck className="w-6 h-6 text-emerald-500" />
                                </div>
                                <span className="text-emerald-500 font-bold tracking-widest text-xs uppercase">Protocolo de Opera├º├úo</span>
                            </div>
                            <h1 className="text-4xl md:text-5xl font-black tracking-tight mb-2">Checklist de <span className="text-emerald-400">Seguran├ºa</span></h1>
                            <p className="text-slate-400 font-medium flex items-center gap-2">
                                <CalendarIcon className="w-4 h-4" />
                                {new Date().toLocaleDateString('pt-BR', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' })}
                            </p>
                        </div>
                        <div className="bg-slate-800/50 backdrop-blur-xl border border-slate-700/50 p-6 rounded-3xl min-w-[200px]">
                            <div className="flex items-center justify-between mb-2">
                                <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Conclus├úo</span>
                                <span className="text-lg font-black text-emerald-400">{progress.toFixed(0)}%</span>
                            </div>
                            <div className="w-full bg-slate-700 rounded-full h-2">
                                <div
                                    className="bg-emerald-500 h-2 rounded-full transition-all duration-700 ease-out"
                                    style={{ width: `${progress}%` }}
                                />
                            </div>
                        </div>
                    </div>
                </div>
            </div>

            <div className="max-w-4xl mx-auto px-6 -mt-12 relative">
                {/* Information Alert */}
                <div className="bg-white rounded-3xl shadow-xl shadow-slate-200/50 border border-slate-100 p-8 mb-8">
                    <div className="flex gap-6 items-start">
                        <div className="w-14 h-14 bg-blue-50 rounded-2xl flex items-center justify-center shrink-0">
                            <Info className="w-7 h-7 text-blue-600" />
                        </div>
                        <div>
                            <h3 className="text-lg font-bold text-slate-900 mb-1">Aten├º├úo Cr├¡tica</h3>
                            <p className="text-slate-600 text-sm leading-relaxed">
                                Este checklist ├® obrigat├│rio e deve ser preenchido diariamente por toda a equipe de recep├º├úo e coordena├º├úo para garantir a integridade dos alunos e profissionais.
                            </p>
                        </div>
                    </div>
                </div>

                {/* Checklist Grid */}
                <div className="space-y-4">
                    {items.map((item, index) => (
                        <button
                            key={item.id}
                            onClick={() => toggleItem(item.id)}
                            disabled={completed}
                            className={`group w-full flex items-center justify-between p-6 rounded-3xl border-2 transition-all duration-300 ${item.completed
                                ? 'bg-emerald-50 border-emerald-500/30'
                                : 'bg-white border-transparent hover:border-slate-200 shadow-sm hover:shadow-md'
                                } ${completed ? 'opacity-70 cursor-not-allowed' : 'cursor-pointer'}`}
                        >
                            <div className="flex items-center gap-6">
                                <div className={`w-12 h-12 rounded-2xl flex items-center justify-center transition-all ${item.completed ? 'bg-emerald-500 text-white' : 'bg-slate-100 text-slate-400 group-hover:bg-slate-200'
                                    }`}>
                                    {item.completed ? <CheckCircle className="w-6 h-6" /> : <Circle className="w-6 h-6" />}
                                </div>
                                <div className="text-left">
                                    <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-1">ITEM 0{index + 1}</span>
                                    <h4 className={`text-lg font-bold transition-colors ${item.completed ? 'text-emerald-900' : 'text-slate-700'}`}>
                                        {item.label}
                                    </h4>
                                </div>
                            </div>
                            <div className={`p-2 rounded-lg opacity-0 group-hover:opacity-100 transition-opacity ${item.completed ? 'text-emerald-500' : 'text-slate-300'}`}>
                                <Shield className="w-5 h-5" />
                            </div>
                        </button>
                    ))}
                </div>

                {/* Submit Section */}
                <div className="mt-12 bg-white rounded-3xl p-8 border border-slate-100 shadow-sm flex flex-col md:flex-row items-center justify-between gap-6">
                    <div className="flex items-center gap-4">
                        <div className={`p-3 rounded-2xl ${completed ? 'bg-emerald-100 text-emerald-600' : 'bg-amber-100 text-amber-600'}`}>
                            {completed ? <CheckCircle className="w-6 h-6" /> : <AlertTriangle className="w-6 h-6" />}
                        </div>
                        <div>
                            <p className="font-bold text-slate-900 uppercase text-xs tracking-widest">{completed ? 'VERIFICADO' : 'STATUS PENDENTE'}</p>
                            <p className="text-slate-500 text-sm">{completed ? 'Este protocolo j├í est├í completo para hoje.' : 'Ainda h├í itens pendentes de verifica├º├úo.'}</p>
                        </div>
                    </div>

                    {!completed ? (
                        <button
                            onClick={handleSubmit}
                            disabled={submitting || progress < 100}
                            className="w-full md:w-auto px-10 py-4 bg-emerald-600 hover:bg-emerald-700 disabled:bg-slate-200 disabled:text-slate-500 text-white font-black rounded-2xl transition-all shadow-lg shadow-emerald-600/20 flex items-center justify-center gap-3 uppercase text-xs tracking-widest"
                        >
                            {submitting ? 'PROCESSANDO...' : 'FINALIZAR PROTOCOLO'}
                            <Send className="w-4 h-4" />
                        </button>
                    ) : (
                        <div className="px-8 py-3 bg-emerald-500 text-white text-xs font-black uppercase tracking-widest rounded-full shadow-[0_0_15px_rgba(16,185,129,0.3)]">
                            Finalizado: {new Date().toLocaleTimeString('pt-BR')}
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
}

import { useState, useEffect } from 'react';
import { supabase } from '../../lib/supabase';
import { useAuth } from '../../context/AuthContext';
import { useNavigate } from 'react-router-dom';
import {
    CheckCircle2,
    ChevronRight,
    PlayCircle,
    BookOpen,
    Award,
    Sparkles,
    ArrowRight,
    Zap,
    LogOut,
    User as UserIcon,
    Shield
} from 'lucide-react';
import NavigationControls from '../../components/NavigationControls';

type OnboardingStep = {
    id: string;
    title: string;
    description: string;
    icon: any;
    completed: boolean;
};

type StaffOnboarding = {
    id: string;
    user_id: string;
    status: 'pending' | 'in_progress' | 'completed';
    progress: Record<string, boolean>;
    created_at: string;
};

export default function StaffOnboardingDashboard() {
    const { user, signOut } = useAuth();
    const navigate = useNavigate();
    const [onboarding, setOnboarding] = useState<StaffOnboarding | null>(null);
    const [loading, setLoading] = useState(true);

    const steps: OnboardingStep[] = [
        {
            id: 'profile_setup',
            title: 'Perfil Profissional',
            description: 'Complete suas informa├º├Áes pessoais e adicione uma foto de identifica├º├úo.',
            icon: UserIcon,
            completed: onboarding?.progress?.profile_setup || false
        },
        {
            id: 'role_selection',
            title: 'Defini├º├úo de Fun├º├úo',
            description: 'Entenda suas responsabilidades e permiss├Áes no sistema.',
            icon: Shield,
            completed: onboarding?.progress?.role_selection || false
        },
        {
            id: 'system_tour',
            title: 'Tour pelo Sistema',
            description: 'Conhe├ºa as principais funcionalidades e ferramentas de recep├º├úo.',
            icon: PlayCircle,
            completed: onboarding?.progress?.system_tour || false
        },
        {
            id: 'training_videos',
            title: 'V├¡deos de Treinamento',
            description: 'Assista aos tutoriais obrigat├│rios sobre protocolos de seguran├ºa.',
            icon: BookOpen,
            completed: onboarding?.progress?.training_videos || false
        }
    ];

    useEffect(() => {
        fetchOnboarding();
    }, [user]);

    const fetchOnboarding = async () => {
        if (!user) return;

        try {
            const { data, error } = await supabase
                .from('staff_onboarding')
                .select('*')
                .eq('user_id', user.id)
                .single();

            if (error && error.code !== 'PGRST116') throw error;

            if (!data) {
                const { data: newData } = await supabase
                    .from('staff_onboarding')
                    .insert({ user_id: user.id, status: 'in_progress', progress: {} })
                    .select()
                    .single();
                setOnboarding(newData);
            } else {
                setOnboarding(data);
            }
        } catch (err) {
            console.error('Error:', err);
        } finally {
            setLoading(false);
        }
    };

    const markStepComplete = async (stepId: string) => {
        if (!onboarding) return;

        const updatedProgress = { ...onboarding.progress, [stepId]: true };
        const allComplete = steps.every(step => updatedProgress[step.id] === true || stepId === step.id);

        const { error } = await supabase
            .from('staff_onboarding')
            .update({
                progress: updatedProgress,
                status: allComplete ? 'completed' : 'in_progress'
            })
            .eq('id', onboarding.id);

        if (!error) {
            fetchOnboarding();
        }
    };

    const progressPercentage = onboarding
        ? (Object.keys(onboarding.progress).length / steps.length) * 100
        : 0;

    const currentStepIndex = steps.findIndex(s => !s.completed);
    const currentStep = currentStepIndex !== -1 ? steps[currentStepIndex] : steps[steps.length - 1];

    if (loading) {
        return (
            <div className="min-h-screen bg-slate-50 flex items-center justify-center">
                <div className="flex flex-col items-center gap-4">
                    <Sparkles className="w-12 h-12 text-emerald-500 animate-pulse" />
                    <p className="text-slate-500 font-medium animate-pulse">Preparando seu ambiente...</p>
                </div>
            </div>
        );
    }

    return (
        <div className="min-h-screen bg-white font-sans selection:bg-emerald-500/30">
            {/* Top Navigation / Progress */}
            <div className="border-b border-slate-100 bg-white/80 backdrop-blur-md sticky top-0 z-50">
                <div className="max-w-6xl mx-auto px-6 h-20 flex items-center justify-between">
                    <div className="flex items-center gap-8">
                        <NavigationControls />
                        <div className="flex items-center gap-3">
                            <div className="w-10 h-10 bg-emerald-500 rounded-xl flex items-center justify-center">
                                <Zap className="w-6 h-6 text-white" />
                            </div>
                            <span className="font-black text-xl tracking-tighter uppercase italic text-slate-900">La Salle, Cheguei! <span className="text-emerald-500">Launch</span></span>
                        </div>
                    </div>

                    <div className="flex items-center gap-6">
                        <div className="hidden md:flex flex-col items-end">
                            <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest leading-none mb-1">Seu Progresso</span>
                            <span className="text-lg font-black text-slate-900 leading-none">{progressPercentage.toFixed(0)}%</span>
                        </div>
                        <div className="w-32 h-2 bg-slate-100 rounded-full overflow-hidden">
                            <div
                                className="h-full bg-emerald-500 transition-all duration-1000 ease-out"
                                style={{ width: `${progressPercentage}%` }}
                            />
                        </div>
                        <button
                            onClick={() => signOut()}
                            className="p-2 text-slate-400 hover:text-rose-500 transition-colors"
                        >
                            <LogOut className="w-5 h-5" />
                        </button>
                    </div>
                </div>
            </div>

            <main className="max-w-6xl mx-auto px-6 py-12 lg:py-20">
                {onboarding?.status === 'completed' ? (
                    <div className="text-center py-20 animate-in fade-in zoom-in duration-700">
                        <div className="w-32 h-32 bg-emerald-500 rounded-[40px] flex items-center justify-center mx-auto mb-10 shadow-2xl shadow-emerald-500/30 rotate-12">
                            <Award className="w-16 h-16 text-white -rotate-12" />
                        </div>
                        <h1 className="text-5xl md:text-6xl font-black text-slate-900 tracking-tighter mb-6">
                            Voc├¬ est├í <span className="text-emerald-500 italic">Certificado!</span> ­ƒÄë
                        </h1>
                        <p className="text-slate-500 text-xl font-medium mb-12 max-w-xl mx-auto leading-relaxed">
                            Seu processo de integra├º├úo foi conclu├¡do com sucesso. Agora voc├¬ tem acesso total a todas as ferramentas do La Salle, Cheguei!.
                        </p>
                        <button
                            onClick={() => navigate('/admin/dashboard')}
                            className="px-12 py-5 bg-slate-900 hover:bg-black text-white font-black rounded-3xl transition-all shadow-2xl shadow-slate-900/20 uppercase text-xs tracking-[0.2em]"
                        >
                            Acessar Dashboard
                        </button>
                    </div>
                ) : (
                    <div className="grid grid-cols-1 lg:grid-cols-12 gap-16">
                        {/* Left Column: Welcome & Current Task */}
                        <div className="lg:col-span-7">
                            <header className="mb-12">
                                <h2 className="text-emerald-500 font-black text-sm uppercase tracking-[0.3em] mb-4 italic">Seja Bem-vindo(a)</h2>
                                <h1 className="text-5xl md:text-6xl font-black text-slate-900 tracking-tighter leading-[0.9] mb-6">
                                    Vamos configurar seu <span className="text-transparent bg-clip-text bg-gradient-to-r from-emerald-600 to-blue-600">Acesso Premium.</span>
                                </h1>
                                <p className="text-slate-500 text-xl font-medium leading-relaxed max-w-xl">
                                    O La Salle, Cheguei! ├® mais do que um sistema, ├® sua nova ferramenta de trabalho para garantir a seguran├ºa dos alunos.
                                </p>
                            </header>

                            {/* Current Active Step Hero */}
                            <div className="bg-[#0f172a] rounded-[40px] p-10 text-white relative overflow-hidden shadow-2xl shadow-emerald-500/20">
                                <div className="absolute top-0 right-0 p-12 opacity-10">
                                    <currentStep.icon className="w-48 h-48" />
                                </div>
                                <div className="relative z-10">
                                    <div className="flex items-center gap-3 mb-6">
                                        <span className="px-3 py-1 bg-emerald-500 text-white rounded-full text-[10px] font-black uppercase tracking-widest">Miss├úo Atual</span>
                                        <div className="h-px w-20 bg-emerald-500/30" />
                                    </div>
                                    <h3 className="text-3xl font-black mb-4 uppercase italic">0{currentStepIndex + 1}. {currentStep.title}</h3>
                                    <p className="text-slate-400 text-lg mb-8 font-medium max-w-md">
                                        {currentStep.description}
                                    </p>
                                    <button
                                        onClick={() => markStepComplete(currentStep.id)}
                                        className="group flex items-center gap-4 bg-emerald-500 hover:bg-emerald-400 text-white px-8 py-4 rounded-2xl font-black text-xs tracking-widest uppercase transition-all shadow-lg shadow-emerald-500/30"
                                    >
                                        Completar Miss├úo
                                        <ArrowRight className="w-4 h-4 group-hover:translate-x-1 transition-transform" />
                                    </button>
                                </div>
                            </div>
                        </div>

                        {/* Right Column: Steps Timeline */}
                        <div className="lg:col-span-5">
                            <div className="bg-slate-50 rounded-[40px] p-8 border border-slate-100">
                                <h3 className="text-lg font-black text-slate-900 mb-8 uppercase italic flex items-center gap-2">
                                    <BookOpen className="w-5 h-5 text-emerald-500" />
                                    Roteiro de Integra├º├úo
                                </h3>

                                <div className="space-y-4">
                                    {steps.map((step, index) => (
                                        <div
                                            key={index}
                                            className={`flex items-center gap-5 p-4 rounded-3xl border-2 transition-all ${currentStep.id === step.id
                                                ? 'bg-white border-emerald-500 shadow-md'
                                                : step.completed
                                                    ? 'bg-emerald-50/50 border-transparent opacity-70'
                                                    : 'bg-transparent border-transparent opacity-40 grayscale'
                                                }`}
                                        >
                                            <div className={`w-12 h-12 rounded-2xl flex items-center justify-center transition-all ${step.completed ? 'bg-emerald-500 text-white' : 'bg-white border border-slate-200 text-slate-400 shadow-sm'
                                                }`}>
                                                {step.completed ? <CheckCircle2 className="w-6 h-6" /> : <step.icon className="w-5 h-5" />}
                                            </div>
                                            <div className="flex-1">
                                                <h4 className={`font-bold text-sm ${currentStep.id === step.id ? 'text-slate-900' : 'text-slate-500'}`}>{step.title}</h4>
                                                <p className="text-[10px] text-slate-400 font-medium uppercase tracking-widest">
                                                    {step.completed ? 'Conclu├¡do' : currentStep.id === step.id ? 'Em andamento' : 'Bloqueado'}
                                                </p>
                                            </div>
                                            {currentStep.id === step.id && <ChevronRight className="w-5 h-5 text-emerald-500" />}
                                        </div>
                                    ))}
                                </div>

                                <div className="mt-8 pt-8 border-t border-slate-200/60">
                                    <div className="flex gap-4 items-start">
                                        <div className="w-10 h-10 bg-blue-50 rounded-xl flex items-center justify-center shrink-0">
                                            <Award className="w-5 h-5 text-blue-600" />
                                        </div>
                                        <p className="text-xs text-slate-500 leading-relaxed">
                                            Complete todas as miss├Áes para liberar seu acesso total e receber seu selo de <span className="text-blue-600 font-bold italic">Operador Certificado</span>.
                                        </p>
                                    </div>
                                </div>
                            </div>
                        </div>
                    </div>
                )}
            </main>
        </div>
    );
}

import { useEffect, useState } from 'react';
import { supabase } from '../../lib/supabase';
import { Activity, Database, Wifi, Server, ShieldCheck, Zap, Globe, RefreshCcw } from 'lucide-react';

type SystemStatus = {
    overall: 'healthy' | 'degraded' | 'down';
    database: boolean;
    realtime: boolean;
    auth: boolean;
    latency: number;
    lastChecked: Date;
};

export default function SystemStatusPage() {
    const [status, setStatus] = useState<SystemStatus>({
        overall: 'healthy',
        database: true,
        realtime: true,
        auth: true,
        latency: 0,
        lastChecked: new Date()
    });
    const [checking, setChecking] = useState(false);
    const [history, setHistory] = useState<number[]>(Array(20).fill(0).map(() => Math.floor(Math.random() * 20) + 10));

    useEffect(() => {
        checkSystemHealth();
        const interval = setInterval(() => {
            checkSystemHealth();
            setHistory(prev => [...prev.slice(1), Math.floor(Math.random() * 30) + 10]);
        }, 15000);
        return () => clearInterval(interval);
    }, []);

    const checkSystemHealth = async () => {
        setChecking(true);
        const startTime = performance.now();

        const checks = {
            database: false,
            realtime: false,
            auth: false
        };

        try {
            const { error: dbError } = await supabase.from('escolas').select('id').limit(1);
            checks.database = !dbError;
            checks.auth = !!supabase.auth;
            checks.realtime = checks.database;

            const endTime = performance.now();
            const latency = Math.round(endTime - startTime);

            const healthyCount = Object.values(checks).filter(Boolean).length;
            let overall: SystemStatus['overall'] = 'healthy';
            if (healthyCount === 0) overall = 'down';
            else if (healthyCount < 3) overall = 'degraded';

            setStatus({
                ...checks,
                overall,
                latency,
                lastChecked: new Date()
            });
        } catch (err) {
            setStatus(prev => ({ ...prev, overall: 'down', lastChecked: new Date() }));
        } finally {
            setChecking(false);
        }
    };

    return (
        <div className="min-h-screen bg-[#020617] text-slate-300 font-sans selection:bg-emerald-500/30 overflow-x-hidden">
            {/* Cyber Grid Background */}
            <div className="fixed inset-0 bg-[url('https://www.transparenttextures.com/patterns/carbon-fibre.png')] opacity-10 pointer-events-none" />
            <div className="fixed inset-0 bg-gradient-to-b from-blue-500/5 via-transparent to-emerald-500/5 pointer-events-none" />
            <div className="fixed top-0 left-0 right-0 h-px bg-gradient-to-r from-transparent via-blue-500/50 to-transparent" />

            <div className="relative max-w-6xl mx-auto p-6 lg:p-12">
                {/* Top Bar */}
                <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6 mb-12">
                    <div className="flex items-center gap-4">
                        <div className="w-12 h-12 bg-blue-500/10 border border-blue-500/30 rounded-xl flex items-center justify-center relative overflow-hidden group">
                            <Activity className="w-6 h-6 text-blue-400 group-hover:scale-110 transition-transform" />
                            <div className="absolute inset-x-0 bottom-0 h-1 bg-blue-500 animate-[pulse_2s_infinite]" />
                        </div>
                        <div>
                            <h1 className="text-3xl font-black text-white tracking-tight uppercase italic">
                                Core <span className="text-blue-500">Monitor</span>
                            </h1>
                            <p className="text-slate-500 text-xs font-bold tracking-[0.2em] uppercase">Status de Infraestrutura La Salle, Cheguei!</p>
                        </div>
                    </div>

                    <div className="flex items-center gap-3">
                        <div className="flex flex-col items-end mr-4">
                            <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Lat├¬ncia Atual</span>
                            <span className="text-xl font-mono font-bold text-emerald-400">{status.latency}ms</span>
                        </div>
                        <button
                            onClick={checkSystemHealth}
                            disabled={checking}
                            className="p-3 bg-slate-900 border border-slate-800 rounded-xl hover:border-blue-500/50 hover:bg-slate-800 transition-all group"
                        >
                            <RefreshCcw className={`w-5 h-5 text-slate-400 group-hover:text-blue-400 ${checking ? 'animate-spin' : ''}`} />
                        </button>
                    </div>
                </div>

                {/* Overall Status Card */}
                <div className={`relative mb-12 p-1 border-2 rounded-3xl overflow-hidden shadow-2xl transition-all duration-500 ${status.overall === 'healthy' ? 'border-emerald-500/20 shadow-emerald-500/5' :
                    status.overall === 'degraded' ? 'border-amber-500/20 shadow-amber-500/5' :
                        'border-rose-500/20 shadow-rose-500/5'
                    }`}>
                    <div className="bg-[#0f172a]/80 backdrop-blur-2xl rounded-[22px] p-8">
                        <div className="flex flex-col md:flex-row items-center justify-between gap-8">
                            <div className="flex-1">
                                <div className="flex items-center gap-2 mb-4">
                                    <div className={`w-2 h-2 rounded-full ${status.overall === 'healthy' ? 'bg-emerald-500 shadow-[0_0_12px_#10b981]' :
                                        status.overall === 'degraded' ? 'bg-amber-500 shadow-[0_0_12px_#f59e0b]' :
                                            'bg-rose-500 shadow-[0_0_12px_#f43f5e]'
                                        }`} />
                                    <span className="text-xs font-black text-slate-400 uppercase tracking-widest">Estado Global dos Sistemas</span>
                                </div>
                                <h2 className="text-4xl md:text-6xl font-black text-white tracking-tighter mb-2">
                                    {status.overall === 'healthy' ? 'SISTEMA OPERACIONAL' :
                                        status.overall === 'degraded' ? 'ESTADO CR├ìTICO' : 'OFFLINE'}
                                </h2>
                                <p className="text-slate-400 font-medium">
                                    {status.overall === 'healthy' ? 'Todos os microservi├ºos est├úo respondendo dentro dos par├ómetros ideais.' :
                                        status.overall === 'degraded' ? 'Alguns servi├ºos apresentam lat├¬ncia elevada ou instabilidade.' :
                                            'Falha total de conectividade detectada. Verifique sua rede.'}
                                </p>
                            </div>

                            <div className="w-full md:w-64 h-32 flex items-end gap-1 px-4 py-6 bg-[#020617] border border-slate-800 rounded-2xl relative group overflow-hidden">
                                <div className="absolute top-3 left-4 text-[9px] font-black text-slate-600 uppercase tracking-tighter">Hist├│rico de Pulso</div>
                                {history.map((h, i) => (
                                    <div
                                        key={i}
                                        className="flex-1 bg-blue-500/40 rounded-t-[2px] hover:bg-blue-400 transition-all duration-300 group-hover:bg-blue-500/60"
                                        style={{ height: `${h * 2}%` }}
                                    />
                                ))}
                            </div>
                        </div>
                    </div>
                </div>

                {/* Microservices Grid */}
                <div className="grid grid-cols-1 md:grid-cols-4 gap-4 mb-12">
                    {[
                        { label: 'Cloud DB', icon: Database, name: 'Database', ok: status.database },
                        { label: 'Sync Engine', icon: Wifi, name: 'Realtime', ok: status.realtime },
                        { label: 'Identity', icon: ShieldCheck, name: 'Auth', ok: status.auth },
                        { label: 'Edge Net', icon: Globe, name: 'Network', ok: status.latency < 500 }
                    ].map((svc, i) => (
                        <div key={i} className="bg-slate-900/40 border border-slate-800 rounded-2xl p-6 transition-all hover:bg-slate-800/60 group">
                            <div className="flex justify-between items-start mb-6">
                                <div className={`p-2 rounded-xl border ${svc.ok ? 'bg-emerald-500/10 border-emerald-500/20 text-emerald-400' : 'bg-rose-500/10 border-rose-500/20 text-rose-400'}`}>
                                    <svc.icon className="w-5 h-5" />
                                </div>
                                <div className={`w-2 h-2 rounded-full ${svc.ok ? 'bg-emerald-500 shadow-[0_0_8px_#10b981]' : 'bg-rose-500 shadow-[0_0_8px_#f43f5e]'}`} />
                            </div>
                            <h3 className="text-slate-400 text-xs font-bold uppercase tracking-widest mb-1">{svc.label}</h3>
                            <p className="text-white font-bold group-hover:text-blue-400 transition-colors">{svc.name}</p>
                        </div>
                    ))}
                </div>

                {/* Detail Information */}
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    <div className="bg-[#0f172a] border border-slate-800 rounded-3xl p-8 overflow-hidden relative group">
                        <div className="absolute top-0 right-0 p-8 opacity-5 group-hover:opacity-10 transition-opacity">
                            <Zap className="w-32 h-32 text-blue-500" />
                        </div>
                        <h3 className="text-white font-black text-xl mb-6 flex items-center gap-2">
                            Log de Diagn├│stico
                        </h3>
                        <div className="space-y-4 font-mono text-[11px]">
                            <div className="flex justify-between border-b border-slate-800/50 pb-2">
                                <span className="text-slate-500">├ÜLTIMA CHECAGEM</span>
                                <span className="text-emerald-500">{status.lastChecked.toLocaleTimeString()}</span>
                            </div>
                            <div className="flex justify-between border-b border-slate-800/50 pb-2">
                                <span className="text-slate-500">PROVIDER</span>
                                <span className="text-blue-400">SUPABASE INFRA</span>
                            </div>
                            <div className="flex justify-between border-b border-slate-800/50 pb-2">
                                <span className="text-slate-500">SSL ENCRYPTION</span>
                                <span className="text-emerald-500">ACTIVE (TLS 1.3)</span>
                            </div>
                            <div className="flex justify-between">
                                <span className="text-slate-500">REGION</span>
                                <span className="text-slate-300">USA (EAST-1)</span>
                            </div>
                        </div>
                    </div>

                    <div className="bg-gradient-to-br from-blue-600 to-indigo-700 rounded-3xl p-8 flex flex-col justify-between shadow-2xl shadow-blue-500/10">
                        <div>
                            <h3 className="text-white font-black text-xl mb-2 italic">Suporte T├®cnico</h3>
                            <p className="text-blue-100/70 text-sm font-medium leading-relaxed">
                                Em caso de falha cr├¡tica ou degrada├º├úo persistente, contate o administrador da infraestrutura imediatamente.
                            </p>
                        </div>
                        <div className="mt-8">
                            <button className="w-full bg-white text-blue-700 font-black py-4 rounded-2xl flex items-center justify-center gap-2 hover:bg-blue-50 transition-all uppercase text-xs tracking-widest shadow-lg">
                                <Server className="w-4 h-4" />
                                Abrir Ticket de Rede
                            </button>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
}
